INSERT INTO `wp_1_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(1, 1, '2010-04-05 15:51:54', '2010-04-05 15:51:54', '<div>Welcome...</div>\r\nThank you for stopping by hopeinloss.org, we hope you find your visit helpful and healing.\r\n\r\nWe are here to create and provide a safe, secure, ad free, cost free, string free, online environment for parents dealing with the loss of a child late in pregnancy, or immediately after birth, so they may engage each other in a helpful and healing dialogue, that may otherwise be missing in their lives.\r\n\r\nAs parents — faced by this debilitating situation, twice — a service such as this would have helped us immeasurably.  In fact, we intend to use this site as we continue to struggle with the confusion and heartbreak of losing Will and Tiger, and as we look to create a space for them in our world.\r\n\r\nThe journey through this grief is one we’ll be on for the rest of our lives so, access to this online tool will be extended to its members for life. Please stay tuned as we work to define our programs and update this site.\r\n\r\nWe expect a formal site launch in the coming months.\r\n\r\nIn the meantime we have provided some information for friends and family. We also can provide space for you to blog as well as a memorial page for you to remember and honor your child. We hope to get the online discussion going soon for those of you who join... hearing from others who have suffered loss does not take away our grief but it does help to experience it more fully, to feel less alone and maybe not so lost. For those who have lived with this loss for sometime, we want to create a space where you feel welcome once a year or once a day. While our children''s memories morph and change with our lives, they remain always our children. And so having a place where they are known seems right.\r\n\r\nlight,\r\n\r\n<em>Susan and Tom </em>', 'Home', '', 'publish', 'open', 'open', '', 'hello-world', '', '', '2010-12-01 11:46:19', '2010-12-01 11:46:19', '', 0, '', 0, 'post', '', 0),
(2, 1, '2010-04-05 15:51:54', '2010-04-05 15:51:54', '<a href="http://spreadsheets.google.com/a/hopeinloss.org/viewform?hl=en&amp;formkey=dEFBeFdudmZCbWdqdkVKSnBIc0pfT1E6MA">Request membership in the Hope in Loss community</a>\r\n\r\n<a href="https://spreadsheets.google.com/a/hopeinloss.org/viewform?formkey=dDJPb3BYRnRXcGRfc2x5ZUhRRHNseXc6MQ">Send us a general comment or question</a>', 'Contact us', '', 'publish', 'open', 'open', '', 'about', '', '', '2010-06-15 18:48:39', '2010-06-15 18:48:39', '', 0, '', 0, 'page', '', 0),
(21, 1, '2010-05-18 00:53:21', '2010-05-18 00:53:21', 'We are developing content in this area.\r\n\r\nStay tuned, please.', 'Locations', '', 'draft', 'open', 'open', '', 'locations', '', '', '2010-05-18 00:54:01', '2010-05-18 00:54:01', '', 0, 'http://hopeinloss.org/?p=21', 0, 'post', '', 0),
