(37, 1, '2010-06-08 15:02:08', '2010-06-08 15:02:08', '<p style="text-align: left"><strong>Now I Lay Me Down To Sleep                                                                                                                                           <span style="font-weight: normal"><em>The free gift of professional portraiture and remembrance photography to parents suffering the loss of a baby</em>.                                                                                                                        <span style="text-decoration: underline"><span style="color: #003300">http://www.nowilaymedowntosleep.org</span></span>/</span></strong></p>\r\n<strong>The Compassionate Friends</strong>: <em>supporting family after a child dies </em><em><span style="text-decoration: underline"> </span></em><span style="color: #003300"><span style="text-decoration: underline">http://www.compassionatefriends.org/home.aspx</span></span>\r\n\r\n<strong><em>Stopping lactation                                                                                              <span style="font-style: normal;font-weight: normal;color: #003300"><span style="text-decoration: underline">http://www.glowinthewoods.com/how-to-stop-lactation/ </span><span style="text-decoration: underline">http://breastfeeding.about.com/od/milksupplyproblems/a/lactsuppress.htm</span></span></em></strong>\r\n\r\n<strong>Miscarriage, Stillbirth, and Infant Loss Directory </strong><span style="color: #003300"><span style="text-decoration: underline">http://babylossdirectory.blogspot.com/2009/05/new-blogs-submitted_16.html</span></span>', 'Links', '', 'publish', 'open', 'open', '', 'links', '', '', '2013-01-06 13:24:23', '2013-01-06 13:24:23', '', 0, 'http://hopeinloss.org/?page_id=37', 0, 'page', '', 0),
(38, 1, '2010-06-08 15:01:52', '2010-06-08 15:01:52', 'Now I Lay Me Down To Sleep  The free gift of professional portraiture and remembrance photography to parents suffering the loss of a baby.   http://www.nowilaymedowntosleep.org/\n\nThe Compassionate Friends: supporting family after a child dies.  http://www.compassionatefriends.org/home.aspx\n\nStopping lactation:                                                                                            http://www.glowinthewoods.com/how-to-stop-lactation/ http://breastfeeding.about.com/od/milksupplyproblems/a/lactsuppress.htm\n\nMiscarriage, Stillbirth, and Infant Loss Directory             http://babylossdirectory.blogspot.com/2009/05/new-blogs-submitted_16.html', 'links', '', 'inherit', 'open', 'open', '', '37-revision', '', '', '2010-06-08 15:01:52', '2010-06-08 15:01:52', '', 37, 'http://hopeinloss.org/2010/06/08/37-revision/', 0, 'revision', '', 0),
