INSERT INTO `wp_2_comments` (`comment_ID`, `comment_post_ID`, `comment_author`, `comment_author_email`, `comment_author_url`, `comment_author_IP`, `comment_date`, `comment_date_gmt`, `comment_content`, `comment_karma`, `comment_approved`, `comment_agent`, `comment_type`, `comment_parent`, `user_id`) VALUES
(2, 19, 'Thomas Brennan', 'tom@hopeinloss.org', '', '128.122.236.204', '2010-04-22 20:05:18', '2010-04-22 20:05:18', 'I remember the moment - before the monitor - when the technician asked if we had noticed kicking today.. and you said, "actually, no, not really."\r\n\r\nYou said that -- and we looked at each other -- there was no more technician -- there was no more Universe. \r\n\r\nEventually, as she pointed to the monitor --showing off all of Tiger''s beautiful parts, I manged to squeak out a phrase for both of us... "I wouldn''t mind seeing the heartbeat."\r\n\r\nI love you my darling -- I wish I could send you back -- I wish I could send myself back - I would be so different.', 0, '1', 'Mozilla/5.0 (Windows; U; Windows NT 6.1; en-US) AppleWebKit/532.5 (KHTML, like Gecko) Chrome/4.1.249.1059 Safari/532.5', '', 0, 2),
(3, 36, 'susanbrennan', 'susan@hopeinloss.org', '', '96.250.21.3', '2010-05-05 15:04:43', '2010-05-05 15:04:43', 'I think I''m the one who laughed darlin''. I do every time. \r\n\r\nYou were good to make the joke. The truth is that it didn''t hide anything. With you standing there, you were not the only one thinking about Will and Tiger- it crossed a few other''s minds that YOU were looking at a picture of a newborn... and making a joke. \r\n\r\nlove.', 0, '1', 'Mozilla/5.0 (Macintosh; U; Intel Mac OS X 10_6_3; en-us) AppleWebKit/531.22.7 (KHTML, like Gecko) Version/4.0.5 Safari/531.22.7', '', 0, 3),
(5, 19, 'Sarah H', 'sarah.k.houlihan@gmail.com', 'http://nerdnuggets.com', '142.46.160.157', '2010-05-06 22:34:59', '2010-05-06 22:34:59', 'Reading this, I was back in the midwife''s office, march 22, the dopler on my huge belly, no noise. All I could say was that ''the silence was too loud''. I knew what the silence meant. \r\nThank you for posting this - it was haunting, and I too wish I had a super-mother suit and some time travel.', 0, '1', 'Mozilla/5.0 (Macintosh; U; Intel Mac OS X 10.5; en-US; rv:1.9.1.9) Gecko/20100315 Firefox/3.5.9', '', 0, 0),
(6, 36, 'mirne', 'mirne.derks@mac.com', 'http://freyja-kees-jet-lovedsomuch.blogspot.com/', '82.170.233.191', '2010-05-10 06:44:25', '2010-05-10 06:44:25', 'Hi Sooze, I just found your blog (via GlowInTheWoods).  I''m so sorry to read that you''ve lost two beautiful boys.  I''m so sorry that a huge part of your family will always be missing.  I too know your loss.  My husband and I have had and lost three beautiful children.  A girl and two boys.  I hope blogging and sharing with other baby-lost parents is helpful to you.  ((hugs))', 0, '1', 'Mozilla/5.0 (Macintosh; U; Intel Mac OS X 10_5_8; en-us) AppleWebKit/531.22.7 (KHTML, like Gecko) Version/4.0.5 Safari/531.22.7', '', 0, 0),
(15, 13, 'vera kate', 'twirlkitten@yahoo.com', 'http://verakatehadley.blogspot.com/', '76.192.50.53', '2010-06-15 20:30:24', '2010-06-15 20:30:24', 'I''m sure you didn''t subconciously decide what you knew about them, just because you had already chosen their names; I believe that you were able to choose their names <i>because you already knew them.</i> Because they''re yours.  \r\n\r\nThank you for sharing your story.  I needed it, today.  \r\nIt makes me feel less alone.\r\n\r\n--vera kate', 0, '1', 'Mozilla/4.0 (compatible; MSIE 8.0; Windows NT 5.1; Trident/4.0; GTB6.5; .NET CLR 1.0.3705; Media Center PC 3.1; .NET CLR 1.1.4322; yie8)', '', 0, 0),
(16, 55, 'vera kate', 'twirlkitten@yahoo.com', 'http://verakatehadley.blogspot.com/', '76.192.50.53', '2010-06-15 20:57:11', '2010-06-15 20:57:11', 'One time I was sharing a suite with a woman I''d never met before.  She asked me if I had any kids at home, and though my heart cracked a little, I gave her the simplest answer: "No."  \r\n\r\nI went into the bathroom to put some things away,  looked at myself in the mirror for a long minute, and made a decision.  When I came back out, I said to the woman, "You know, I don''t have any kids ''at home.''  But I do have two babies in heaven. So I''m a mother, too, if that was your real question."  Her face went ashen and she stammered her condolances, but it didn''t really matter.  What mattered was that I had said it.  I was proud of myself, for favoring truth over social comforts, and also for letting one more person in on the delicious secret of my children''s existence --  which is only secret because they are invisible to all but the most discerning.\r\n\r\nIt''s funny to me, the way we go around trying to protect other people from our pain.  Sometimes it is really satisfying to give them a peek, though.  Sometimes I think, <i>Yeah; stings, doesn''t it?  You have no idea.</i>   But mostly I just think, <i>I am grateful, for your sake, that you don''t really know what I am talking about.  I hope that you are grateful too.</i>', 0, '1', 'Mozilla/4.0 (compatible; MSIE 8.0; Windows NT 5.1; Trident/4.0; GTB6.5; .NET CLR 1.0.3705; Media Center PC 3.1; .NET CLR 1.1.4322; yie8)', '', 0, 0),
(9, 55, 'Tom', 'tom@hopeinloss.org', '', '128.122.236.204', '2010-05-26 17:57:38', '2010-05-26 17:57:38', 'My love - thank you thank you thank you - beautiful wonderful post.', 0, '1', 'Mozilla/5.0 (Windows; U; Windows NT 6.1; en-US) AppleWebKit/532.5 (KHTML, like Gecko) Chrome/4.1.249.1064 Safari/532.5', '', 0, 2),
(10, 65, 'Susan', 'susan@hopeinloss.org', '', '24.193.89.252', '2010-05-26 19:02:17', '2010-05-26 19:02:17', 'hmmm. a site to give others the space to really be with people sounds in order. oh you are doing that already. \r\n\r\nI love that you say their names whenever you can. \r\n\r\nYou are such an amazing father.', 0, '1', 'Mozilla/5.0 (Macintosh; U; Intel Mac OS X 10_6_3; en-us) AppleWebKit/531.22.7 (KHTML, like Gecko) Version/4.0.5 Safari/531.22.7', '', 0, 3),
(13, 72, 'Tom', 'tom@hopeinloss.org', '', '128.122.236.204', '2010-06-14 14:15:09', '2010-06-14 14:15:09', 'My love -- you are  a wonder on earth -- I celebrate, adore, worship, and stand in awe, of the breath of life in you.', 0, '1', 'Mozilla/5.0 (Windows; U; Windows NT 6.1; en-US; rv:1.9.2.3) Gecko/20100401 Firefox/3.6.3', '', 0, 2),
(32, 135, 'Leslie', 'lesliedispensaperlman@yahoo.com', 'http://www.cullensblessings.wordpress.com', '76.26.199.234', '2010-12-11 03:43:23', '2010-12-11 03:43:23', 'Thank you for sharing this Sooze...', 0, '1', 'Mozilla/5.0 (Macintosh; U; Intel Mac OS X 10_5_8; en-us) AppleWebKit/533.19.4 (KHTML, like Gecko) Version/5.0.3 Safari/533.19.4', '', 0, 0),
(60, 132, 'Brooke', 'bythebrooke@gmail.com', 'http://www.bythebrooke.blogspot.com', '128.252.47.83', '2011-01-21 18:31:04', '2011-01-21 18:31:04', 'This is beautiful.  Thanks for this.', 0, '1', 'Mozilla/5.0 (Windows; U; Windows NT 6.1; en-US; rv:1.9.2.13) Gecko/20101203 Firefox/3.6.13', '', 0, 0),
(421, 186, 'Lara', 'may@rmi.net', '', '65.128.42.166', '2013-02-20 05:59:51', '2013-02-20 05:59:51', 'As usual I fell asleep while putting Lily (taz''s big sister) and Lucia (his little sister)  to bed and within an hour I was shocked awake which happens almost nightly.  I lay in bed and thought to myself enough about you how about him, how about baby taz.  Similiar to you I had the flu and was in bed for 3 days and though it has been over a month now I am still shaken from being so sick.  I feel it is time to focus on that sweet little baby and let go of the horror-stop reliving the horror-\r\nThank you for your writing.  Your piece at Glow is unbelievable.\r\nxx,\r\nLara', 0, '1', 'Mozilla/5.0 (Macintosh; Intel Mac OS X 10.7; rv:7.0.1) Gecko/20100101 Firefox/7.0.1', '', 0, 0),
