l_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:24;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:52:"WPTavern: New Company Releases Evil WordPress Plugin";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=6864";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:104:"http://feedproxy.google.com/~r/WordpressTavern/~3/1om4I3Pxd9A/new-company-releases-evil-wordpress-plugin";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2678:"<p><a href="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/GangsterCodeLogo.jpg" rel="thumbnail"><img src="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/GangsterCodeLogo.jpg?resize=172%2C121" alt="GangsterCodeLogo" class="alignright size-full wp-image-6866" /></a> Earlier today on Twitter, WordPress community member Travis Ballard @Ansimation <a href="https://twitter.com/ansimation/statuses/332124789172994049">published a link</a> to a plugin that will have people thinking twice before they sign up to a WordPress based website. Ironically, it&#8217;s called <a href="http://gangstercode.com/wpevil-series-text-passwords-plugin/">WPEvil</a> and saves passwords into plain text instead of hashes. One thing I&#8217;ve learned over the years is that passwords are to never be stored in plain text, for any reason. I reached out to the creators of this plugin to see if they could give me a couple of legitimate use cases. Here is what they had to say.</p>\n<blockquote><p>Legitimate use would be I guess to tell one of your users their password if they can&#8217;t reset it for some reason. There are no appropriate uses for this plugin, I guess you could do your own research to see what people actually use as passwords.</p>\n<p>Motivation? Bored.</p></blockquote>\n<p>Travis also <a href="http://www.reddit.com/r/Wordpress/comments/1dxfop/wpevil_series_text_passwords_plugin_spy_on_your/">got in touch with the plugin author on Reddit</a> to discuss legitimate uses for this plugin and was greeted with an insult that it was above his pay grade.</p>\n<p>So if you come across a WordPress powered website that you can tell is using this plugin, would you register your account there? How does it make you feel to see a company release such a plugin to the wild? Should anyone be worried that this plugin exists? </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/wp-plugin-authors-the-target-of-a-phishing-scam" rel="bookmark" title="WP Plugin Authors The Target Of A Phishing Scam">WP Plugin Authors The Target Of A Phishing Scam</a></li>\n<li><a href="http://www.wptavern.com/absolute-privacy-plugin-now-at-v1-2" rel="bookmark" title="Absolute Privacy Plugin Now At v1.2">Absolute Privacy Plugin Now At v1.2</a></li>\n<li><a href="http://www.wptavern.com/whats-the-best-way-to-be-notified-of-theme-and-plugin-updates" rel="bookmark" title="What&#8217;s The Best Way To Be Notified Of Theme And Plugin Updates?">What&#8217;s The Best Way To Be Notified Of Theme And Plugin Updates?</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/1om4I3Pxd9A" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 08 May 2013 22:01:34 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:25;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:56:"WPTavern: Up To The Community To Improve Theme Demo Data";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=6835";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:108:"http://feedproxy.google.com/~r/WordpressTavern/~3/1k3l_kCn-Rk/up-to-the-community-to-improve-theme-demo-data";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3393:"<p><a href="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/PostStatusLogo.jpg" rel="thumbnail"><img src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/PostStatusLogo.jpg?resize=218%2C51" alt="Post Status Logo" class="alignright size-full wp-image-6860" /></a>Brian Krogsgard of Poststat.us has <a href="http://poststat.us/wordpress-org-theme-demos-leave-a-lot-to-be-desired/">raised an issue</a> that I never considered concerning the demo content displayed within themes on the theme repository. While commercial theme demos do a great job showing off what a theme is capable of doing, for at least some themes on the repository, the demo content ruins the look of a theme. As Brian pointed out, look at <a href="http://wordpress.org/extend/themes/pinboard">Pinboard</a> as an example. Looks great in the screenshot but is terrible using the WP.org demo content. The Pinboard theme needs to be configured with featured images and such before it can look the way it does in the screenshot. The blog demo content doesn&#8217;t suit Pinboard out of the box. </p>\n<p>This got me thinking. How many themes on WordPress.org are considered to look bad simply because of the demo content? Quite a discussion was had on Brian&#8217;s post on what could be done to solve the problem with <a href="http://poststat.us/wordpress-org-theme-demos-leave-a-lot-to-be-desired/#comment-27589">Otto responding</a> within the comments that this issue was discussed at last years WordPress Community Summit. Because of the issues involved with monitoring and such, theme authors will most likely never be able to add a custom demo link to their theme page. It&#8217;s also likely that theme authors will not be given control over the demo content displayed within the theme. However, <a href="http://poststat.us/wordpress-org-theme-demos-leave-a-lot-to-be-desired/#comment-27611">Otto has suggested</a> the following for theme authors that want better default demo data:</p>\n<blockquote><p>So, theme authors: Get together, make a site somewhere, start to put some demo data on it. Work together to create it. Argue about it. Pick fights. Whatever. ;)</p>\n<p>Come up with a good community-made set of demo data, and I assure you that I, for one, will certainly pay attention. This is something that can be easily community-driven and created. Once we have a site with the data, then it’s a simple matter of an export/import to get it onto the previewer. Well, not quite that simple, but still pretty simple.</p></blockquote>\n<p>So if anyone puts together an area to start working on this project, get in touch with me so I can pass the word. </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/listener-poll-how-should-i-review-a-theme" rel="bookmark" title="Listener Poll: How Should I Review A Theme?">Listener Poll: How Should I Review A Theme?</a></li>\n<li><a href="http://www.wptavern.com/standardizing-theme-hook-names" rel="bookmark" title="Standardizing Theme Hook Names">Standardizing Theme Hook Names</a></li>\n<li><a href="http://www.wptavern.com/theme-repository-eyetracking-and-free-themes" rel="bookmark" title="Theme Repository, EyeTracking And Free Themes">Theme Repository, EyeTracking And Free Themes</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/1k3l_kCn-Rk" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 08 May 2013 21:04:14 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:26;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:46:"WPTavern: At 10 Years Old, Is It Time To Fork?";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=6834";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:96:"http://feedproxy.google.com/~r/WordpressTavern/~3/-cVCmpOtDqY/at-10-years-old-is-it-time-to-fork";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:10428:"<p><a href="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/designisphilosophy.jpg" rel="thumbnail"><img src="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/designisphilosophy.jpg?resize=174%2C71" alt="Design Is Philosophy Logo" class="alignright size-full wp-image-6848" /></a>Over at Design Is Philosophy, Morten Rand-Hendriksen raised the question if after 10 years, is it <a href="http://designisphilosophy.com/wordpress/wordpress-at-10-time-for-a-fork/">time to fork WordPress</a>? The gist of the post is an argument/discussion that&#8217;s been made over the years at different times. It boils down to figuring out a way to remove all the stuff that&#8217;s not needed in WordPress and coming up with a lean, modular core. Morten takes an interesting approach in that this new WordPress would consist of branches. You start with WP Core connected to different branches that contain specific functionality such as WP CMS or WP For Bloggers. In this way, those specific use case branches would have most of what you needed out of the box without having one WordPress package that contained everything for everyone. </p>\n<p>On paper, I like the idea of a lean WordPress with modules that I enable or disable based on the functionality I need. Several years ago, I used a CMS called e107 that behaved in this manner. It was pretty cool at the time because if I wanted forums, I just enabled the forums module. If not, I left it disabled and the forums never loaded. Back in 2009, a lengthy discussion took place around the very topic of making WordPress more modular, <a href="http://lists.automattic.com/pipermail/wp-hackers/2009-February/024242.html">Less than Core, More than Plugins/Themes: Proposing Optional Modules</a>. Unlike creating different packages or branches of WordPress to fulfill specific needs, optional plugins could offer that functionality so that it wouldn&#8217;t be stuck in core.</p>\n<blockquote><p>What I&#8217;d like to propose is the creation of a new concept for WordPress, the &#8220;Optional module.&#8221; Optional modules would be singular like the core and would be versioned with the core but they would not be included in the default installation. Optional modules would be &#8220;installed-on-demand&#8221; based on a plugin&#8217;s request and admin&#8217;s approval to install, and the version of the optional module installed would be determined by the version of the WordPress core that is installing it.</p>\n<p>Having &#8220;Optional Modules&#8221; for WordPress such as I propose would allow progress in the direction of common infrastructure without bloating the core. And one of the first such optional modules could be a basic theming framework</p></blockquote>\n<p>One of the biggest arguments against the idea is that the mostly volunteer based team that works on the core of WordPress is already pressed for time, (pardon the pun) and by creating these optional modules or plugins, it would significantly raise their work load to the point where it negatively affects their ability to work on WordPress core. That discussion took place around February of 2009. In <a href="http://wordpress.org/news/2009/12/canonical-plugins/">late 2009, early 2010</a> the term Canonical Plugin was created to differentiate these plugins from a normal WordPress plugin. A poll was conducted with different name choices with Core Plugins winning the top spot. At the time, a core plugin was defined as follows:</p>\n<blockquote><p>Core plugins are community developed and encourage collaboration with multiple developers to satisfy the most popular functionality requests that would not make it into the Core of WordPress. These plugins would be developed alongside the core of WordPress to ensure compatibility, coding standards are met, secure code, etc. To highlight these plugins, a screen would be added to the plugins page in the back-end of WordPress to highlight these special plugins. Everything sounds great right? Let’s take a look at some of the possible unintended consequences this could have on the community.</p></blockquote>\n<p>One of the only plugins that I know of that ended up with this Core Plugin status was called <a href="http://westi.wordpress.com/2009/12/26/giving-your-wordpress-a-check-up/">Health Check by Peter Westwood</a>. This plugin was used as a test bed for the idea of creating core plugins through collaboration. </p>\n<p>I reached out to Aaron D. Campbell as he was one of the volunteers to generate effort and focus towards the Core Plugin project and asked him a few questions about the work that&#8217;s been completed since 2010 for Core Plugins.</p>\n<p><strong>Jeff -</strong> On January 11th, 2010 you published on the Make.WordPress.core blog on creating a Core Plugin Infrastructure. The only core plugin that I know up which was an experiment was Health Check by Peter Westwood. Do you know of any others that have been created since 2010? Has there been much progress or work done towards the idea of Core Plugins since?</p>\n<p><strong>Aaron -</strong>No. Post by E-Mail never really got off the ground. I&#8217;m hoping to get it kicked off at some point, possibly with a GSoC student this year (it was one of the ideas). Honestly, the best example of the CONCEPT of community driven development AROUND WordPress is probably _s. It&#8217;s a theme not a plugin, but it accomplished what we were envisioning</p>\n<p><strong>Jeff -</strong> Well, Jetpack has sort of taken the Post by email feature and put it into a plugin. My guess would be that eventually that feature will be removed in WordPress like Links in favor of the Jetpack version.</p>\n<p><strong>Aaron -</strong> I don&#8217;t think so. I don&#8217;t think any feature will ever be removed in favor of Jetpack.</p>\n<p><strong>Jeff -</strong> I was under the impression that core plugins would enable WordPress to be able to take things that became not so widely used anymore and be able to put stuff like that into a plugin enabling a light nimble core. Therefor, decreasing the need to argue that WordPress is bloated and we need to fork it.</p>\n<p><strong>Aaron -</strong> That&#8217;s certainly one of the goals of core plugins. However, Jetpack is not a core plugin.</p>\n<p><strong>Jeff -</strong> So since 2010, not much work has been accomplished around the idea of Core Plugins but it&#8217;s still an idea that&#8217;s being kicked around and will possibly make headway in the future?</p>\n<p><strong>Aaron -</strong> Yep. I think almost everyone agrees it&#8217;s a good idea, but having the hours needed to actually make it happen is a whole different thing.</p>\n<p><strong>Jeff -</strong> Agreed. It was one of the issues immediately brought up in the hackers mailing list article first proposing the idea of these core modules. Time and effort which wouldn&#8217;t detract from the time and effort of Core itself </p>\n<p>The issues that Morten has raised such as being stuck with old backwards compatibility code and future development of WordPress are justified but I don&#8217;t like the idea of different WordPress branches or cores. I don&#8217;t want to go through a process of figuring out which specific type of WordPress I need and I doubt new users will be able to easily grasp which one is best for them. We&#8217;ll end up needing flow charts, bar graphs and such to explain the differences. At the same time, I have noticed how much stuff WordPress has added over the years that I simply don&#8217;t use. Yet, the features I don&#8217;t use are the ones my neighbor does. It seems counter-productive to install plugins that remove unused functionality just so it&#8217;s completely out of my way. It also bothers me that so much of the unused portions of WordPress are loaded or even processed when they shouldn&#8217;t. This is why I&#8217;m for the idea of compartmentalizing WordPress to the point of simply being able to turn things on or off. Then again, I can see how having a module for the simple task of disabling or enabling image editing in WordPress could be cumbersome. </p>\n<p>I want to see WordPress continue on for another 10 years but at the same time, I don&#8217;t want it to bring everything from the previous 10 years with it. Although I haven&#8217;t mentioned the word bloat, this post from 2009 is relevant in that it discusses the question, <a href="http://www.wptavern.com/what-is-wordpress-bloat">What is WordPress bloat</a>? </p>\n<p><a href="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/ghostlogo.jpg" rel="thumbnail"><img src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/ghostlogo.jpg?resize=313%2C135" alt="ghostlogo" class="aligncenter size-full wp-image-6854" /></a></p>\n<p>I&#8217;d be re missed if I didn&#8217;t mention <a href="http://tryghost.org/">Ghost</a> somewhere in this conversation. <a href="http://john.onolan.org/ghost/">Ghost is a vision</a> proposed by John O&#8217;Nolan that aims to get back to the roots of simple, easy, publishing. I&#8217;m excited about Ghost and joined in with the crowd of wanting to see it in action. At this point, Ghost is just a bunch of pretty screenshots but I like what I see. John started a <a href="http://www.kickstarter.com/projects/johnonolan/ghost-just-a-blogging-platform">Kickstarter campaign</a> to acquire 25,000 Great British Pounds to get the project off the ground. Not only did he reach that goal within hours of starting the campaign, he has since quadrupled the goal amount with 19 days left to go. What this tells me is that there is pent-up interest in seeing a platform that gets back to the basics of publishing. Many of the names on the backers list are long-time WordPress users. </p>\n<p>There are techniques and methods to get WordPress back to its roots of being the easiest software to use to publish words to the web. Forking is not one of those methods. Are you willing to stick with WordPress through the long haul or are you ready to pack your bags and jump ship the minute something easier and better looking is released?</p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/why-wordpress-has-less-options-not-more" rel="bookmark" title="Why WordPress Has Fewer Options, Not More">Why WordPress Has Fewer Options, Not More</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/-cVCmpOtDqY" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 08 May 2013 20:25:15 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:27;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:74:"WordPress.tv: Mickey Mellen: The Difference Between WordPress.com and .org";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=19116";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:90:"http://wordpress.tv/2013/05/08/mickey-mellen-the-difference-between-wordpress-com-and-org/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:703:"<div id="v-yTCBEIw6-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/19116/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/19116/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=19116&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/08/mickey-mellen-the-difference-between-wordpress-com-and-org/"><img alt="Mickey Mellen: The Difference Between WordPress.com and .org" src="http://videos.videopress.com/yTCBEIw6/video-d1939b5060_scruberthumbnail_0.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 08 May 2013 19:23:13 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:28;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:32:"Joseph: The VaultPress Lite Plan";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"https://josephscott.org/?p=7660";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:65:"http://josephscott.org/archives/2013/05/the-vaultpress-lite-plan/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:157:"<p>Very excited to have the <a href="http://blog.vaultpress.com/2013/05/08/introducing-vaultpress-lite/">VaultPress Lite plan announced this morning</a>.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 08 May 2013 18:17:13 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"Joseph Scott";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:29;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:58:"WPTavern: How To Search For 100% GPL Themes On Themeforest";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=6831";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:109:"http://feedproxy.google.com/~r/WordpressTavern/~3/iD6061j0jLA/how-to-search-for-100-gpl-themes-on-themeforest";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2267:"<p>Not long ago, <a href="http://notes.envato.com/general/100-gpl-option-now-available-plus-woothemes-arrives/">Themeforest announced</a> that theme authors would be able to choose a 100% GPL theme license. However, as a customer, it&#8217;s difficult to find where those 100% GPL licensed themes are located on the site. Upon browsing the Themeforest Marketplace, I could not find a <em>category, tag, or link</em> that would show me all the WordPress themes licensed as such. Since the text located within the license information box is able to be crawled by Google, you can use a Site specific search query to find these themes. Just type <em>site:http://themeforest.net/item This item is licensed 100% GPL.</em> into Google to see a list of themes that have been indexed. </p>\n<p><a href="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/themeforestGPL.jpg" rel="thumbnail"><img src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/themeforestGPL.jpg?resize=532%2C265" alt="ThemeForest GPL Search String" class="aligncenter size-full wp-image-6838" /></a></p>\n<p>While I saw 53,800 results listed, not all the results take you directly to the theme page. For example, the License text is also shown on the <a href="http://themeforest.net/item/hustle/discussion/4137914">discussion pages</a> for each theme which is also indexed. Until Themeforest creates a better way of browsing these specific themes, this will have to do. </p>\n<p><strong>Hat Tip:</strong> <a href="https://twitter.com/bradleypotter/statuses/331854378078203904">@Bradleypotter</a></p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/another-company-goes-100-gpl" rel="bookmark" title="Another Company Goes 100% GPL">Another Company Goes 100% GPL</a></li>\n<li><a href="http://www.wptavern.com/premiumthemes-net-goes-gpl" rel="bookmark" title="PremiumThemes.net Goes GPL">PremiumThemes.net Goes GPL</a></li>\n<li><a href="http://www.wptavern.com/how-do-i-contribute-to-commercial-gpl-themes" rel="bookmark" title="How Do I Contribute To Commercial GPL Themes?">How Do I Contribute To Commercial GPL Themes?</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/iD6061j0jLA" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 08 May 2013 14:52:13 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:30;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:71:"WordPress.tv: John P. Bloch: Awesome Helper Functions in WordPress Core";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"