:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=19066";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:96:"http://wordpress.tv/2013/05/07/brad-parbs-320px-and-up-getting-started-with-responsive-design-2/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:713:"<div id="v-xnMjfoOO-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/19066/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/19066/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=19066&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/07/brad-parbs-320px-and-up-getting-started-with-responsive-design-2/"><img alt="Brad Parbs: 320px and Up, Getting started with Responsive Design" src="http://videos.videopress.com/xnMjfoOO/video-5c51eda920_scruberthumbnail_0.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 07 May 2013 21:09:46 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:32;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:56:"WPTavern: Pressnomics Conference Announces Date For 2013";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=6826";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:108:"http://feedproxy.google.com/~r/WordpressTavern/~3/-9bfGAH0eWA/pressnomics-conference-announces-date-for-2013";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2535:"<p><a href="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2012/05/pressnomicslogo.png" rel="thumbnail"><img src="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2012/05/pressnomicslogo.png?resize=155%2C136" alt="Pressnomics Logo" class="alignright size-full wp-image-6561" /></a>The folks behind <a href="http://pressnomics.com/">Pressnomics</a> have announced the dates for this years conference. It will be held on <strong>October 17th-19th</strong>. For those that don&#8217;t know, Pressnomics is a conference centered around the services and products that have created a successful and diverse economy around WordPress. Tickets go on sale <strong>June 19th at 10am PST</strong> and will be released in batches. From what I understand, there are a few folks that will be selectively invited to attend the conference, just like last year. </p>\n<p>I didn&#8217;t have the opportunity to attend the event last year but from all of the posts and tweets I read, it was one hell of an event I missed. I will do what I can to be in attendance this year. The primary reason I want to attend this conference is because most of the WordPress business movers and shakers are under one roof and there are a ton of things to learn from them. I want to seize that knowledge from these folks and pass it along to you. </p>\n<p>Here are a few links from attendees of last years event to give you a better idea of what this conference is all about.</p>\n<p>Alex King &#8211; <a href="http://itsmetherobot.appspot.com/alexking.org/blog/2012/11/13/pressnomics-2012">Pressnomics 2012</a><br />\nAZ Tech Beat &#8211; <a href="http://aztechbeat.com/2012/11/pressnomics-2012-day-1-2/">Key Takeaways From Pressnomics 2012 Day 1 &#8211; AZ Tech Beat</a><br />\nWebSavvy Marketing &#8211; <a href="http://www.web-savvy-marketing.com/2012/11/pressnomics-people-wordpress-core/">PressNomics: People Are The True WordPress Core</a><br />\nWebDevStudios &#8211; <a href="http://webdevstudios.com/2012/11/13/pressnomics-not-just-another-wordcamp/">Pressnomics &#8211; Not Just Another WordCamp</a></p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/pressnomics-conference-specifically-for-commercial-entities" rel="bookmark" title="PressNomics &#8211; Conference Specifically For Commercial WordPress Entities">PressNomics &#8211; Conference Specifically For Commercial WordPress Entities</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/-9bfGAH0eWA" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 07 May 2013 17:22:16 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:33;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:49:"WPTavern: Searching For A Better WordPress Search";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=6819";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:101:"http://feedproxy.google.com/~r/WordpressTavern/~3/19hutSdYz4I/searching-for-a-better-wordpress-search";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:5260:"<p>On May 6th, the WordPress VIP team blog <a href="https://vip.wordpress.com/2013/05/06/vip-search/">announced</a> a new VIP service they&#8217;ll be offering centered around search. While at first it may be surprising that the default search in WordPress was not used in their latest project, the fact is, WordPress search in its current state can not perform complex search queries without using a considerable amount of computational resources which spells doom for users on shared webhosting. The VIP Search Add-on uses third party software called <a href="http://www.elasticsearch.org/">Elasticsearch</a> which is open source and can be used by anyone. However, upon looking at the requirements and the methods of setting it up, it&#8217;s only meant for those that have the ability to run software on their hosting accounts either through a dedicated box or VPS. By using Elastic search, the VIP team was able to provide search capabilities such as being able to filter between the different types of content, categories, tags, authors, date ranges and more. To see the advanced search capabilities in action, check out <a href="http://kff.org/search/">http://kff.org/search/</a>. I reached out to Paul Maiorana, Vice President of Platform Services for Automattic but was unable to get a response I could share with the public. </p>\n<p><a href="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/VIPsearch.jpg" rel="thumbnail"><img src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/VIPsearch.jpg?resize=300%2C136" alt="VIP Search box" class="aligncenter size-medium wp-image-6820" /></a></p>\n<p>I briefly conversed with other members of the WordPress community on Twitter on why WordPress does not already have those advanced search queries out of the box. The gist of the conversation was that performing such intensive searches would be too much for the limited resources shared hosting provides. It was also mentioned that most of the functionality can be achieved using Google Custom Search. In fact, Matt Mullenwegs personal WordPress site Ma.tt runs Google Custom Search. </p>\n<p>Interestingly enough, back in 2009, Matt <a href="http://ma.tt/2009/07/acquia-searc/">published a post</a> that highlighted a new hosted service called Acquia Search that Drupal users could tap into. At the time, commenters urged Matt to continue to improve the search capabilities in WordPress as some users were not fans of relying on a third party service. Matt&#8217;s response was:</p>\n<blockquote><p>Yes and there is a Google Summer of Code project on this right now, but as with video processing we’re limited by the resources available to us by default and it’s something that could be fairly efficiently done as a remote service.</p></blockquote>\n<p>If you&#8217;re interested, you can <a href="http://wpsoc09.wordpress.com/2009/03/29/extended-wordpress-search-engine/">see the proposal</a> for that Google Summer Of Code project here. <a href="http://andy.wordpress.com/2009/08/21/wordpress-search-plugin/">According to Justin&#8217;s mentor Andy Skelton</a>, Justin Shreve was successful in completing his search API project which the results can be found within the <a href="http://wordpress.org/extend/plugins/search/">plugin repository</a> except that the plugin has not been updated for over two years. After asking around to see if the search API ever made it to core, it appears not. </p>\n<p>So while I don&#8217;t see any major improvement taking place in the near future for the core implementation of search, there are a few plugins out there that improve the situation. In fact, if you conduct a search of the WordPress plugin repository using the <a href="http://wordpress.org/extend/plugins/search.php?q=search">keyword of search</a>, 16 results show up although not all of the results are specifically tailored for the search functionality of WordPress. I personally have not yet taken the time to evaluate the different plugins but I have heard from a number of users that <a href="http://wordpress.org/extend/plugins/relevanssi/">Relevanssi</a> is a good solution. Of course, there is always <a href="http://wordpress.org/extend/plugins/google-custom-search/">Google Custom Search</a> which has a proven track record.</p>\n<p>Do you think having better search functionality in WordPress is worth paying for? Have you installed any plugins or have manually improved the search capabilities on your website? Let me know your thoughts in the comments on the state of search in WordPress. </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/improving-the-wordpress-search-engine-with-relevanssi" rel="bookmark" title="Improving The WordPress Search Engine With Relevanssi">Improving The WordPress Search Engine With Relevanssi</a></li>\n<li><a href="http://www.wptavern.com/adding-google-custom-search-is-easy" rel="bookmark" title="Adding Google Custom Search Is Easy">Adding Google Custom Search Is Easy</a></li>\n<li><a href="http://www.wptavern.com/searching-only-the-codex" rel="bookmark" title="Searching Only The Codex">Searching Only The Codex</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/19hutSdYz4I" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 07 May 2013 15:46:42 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:34;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:25:"Joseph: Scaling WordPress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"https://josephscott.org/?p=7653";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:58:"http://josephscott.org/archives/2013/05/scaling-wordpress/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:177:"<p>I&#8217;ve posted the <a href="http://www.slideshare.net/josephscott/scaling-wordpress-20731197">slides from my &#8216;Scaling WordPress&#8217; presentation</a>.</p>\n<p> </p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 07 May 2013 14:43:28 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"Joseph Scott";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:35;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:45:"WPTavern: WordPress Deployment Survey Results";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=6816";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:97:"http://feedproxy.google.com/~r/WordpressTavern/~3/Zh7fcn6A1Og/wordpress-deployment-survey-results";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1473:"<p>Interesting bit of <a href="http://wp.smashingmagazine.com/2013/04/15/wordpress-deployment-survey/">survey results</a> published by Kieran Masterton on Smashing WordPress today. According to her survey results, a lot more focus and education needs to be done surrounding the professional deployment of websites as well as the use of version control. If you&#8217;ve ever found yourself having to use a <em>Find And Replace</em> plugin or <em>MySQL snippet</em> because you switched environments with a WordPress site, I highly recommend reading the comments to see how so many others have faced the same situation and their solutions. </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/5-question-survey-to-help-make-wordpress-org-better" rel="bookmark" title="5 Question Survey To Help Make WordPress.org Better">5 Question Survey To Help Make WordPress.org Better</a></li>\n<li><a href="http://www.wptavern.com/joost-de-valk-conducting-wordpress-host-survey" rel="bookmark" title="Joost de Valk Conducting WordPress Host Survey">Joost de Valk Conducting WordPress Host Survey</a></li>\n<li><a href="http://www.wptavern.com/wpshout-releases-results-of-their-webhosting-survey" rel="bookmark" title="WPShout Releases Results Of Their Webhosting Survey">WPShout Releases Results Of Their Webhosting Survey</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/Zh7fcn6A1Og" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 06 May 2013 21:40:23 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:36;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:50:"WPTavern: Rolling Your Own WordPress With WPRoller";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=6806";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:102:"http://feedproxy.google.com/~r/WordpressTavern/~3/fAU7A6fErwI/rolling-your-own-wordpress-with-wproller";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:5712:"<p><a href="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/wprollerlogo.jpg" rel="thumbnail"><img src="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/wprollerlogo.jpg?resize=261%2C64" alt="wp roller logo" class="alignright size-full wp-image-6807" /></a>Almost four years ago, <a href="http://lists.automattic.com/pipermail/wp-hackers/2009-September/027659.html">the idea</a> of having <a href="http://www.wptavern.com/custom-install-profiles-sounds-like-a-cool-idea">custom WordPress installation profiles</a> was brought up. The initial idea was to change core around so that developers could pre-configure WordPress with a set of activated plugins while also being able to change/activate the default theme. The idea was championed at the time but the implementation was up for debate. Fast forward to today and there is now a free service called <a href="http://wproller.com/">WPRoller</a> which looks like a great solution to the problem, without having to do anything to the core of WordPress. </p>\n<p><a href="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/wproller-wpversion.jpg" rel="thumbnail"><img src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/wproller-wpversion.jpg?resize=300%2C138" alt="WPRoller Choosing Which Version Of WordPress To Install" class="aligncenter size-medium wp-image-6808" /></a></p>\n<p>Without needing to register an account, you simply scroll down the page and select which version of WordPress you&#8217;d like to use, either the latest stable version or the nightly build. Then, scroll through the various categories of plugins and select the ones you&#8217;d like to install along with WordPress. While at first I was disappointed that I couldn&#8217;t search the repository and just add whatever plugin I wanted, it then dawned on me how much more sense it makes to just list some of the most popular plugins in their respective categories. </p>\n<p><a href="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/wproller-choosingplugins.jpg" rel="thumbnail"><img src="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/wproller-choosingplugins.jpg?resize=300%2C171" alt="Choosing WordPress Plugins" class="aligncenter size-medium wp-image-6809" /></a></p>\n<p>During the initial launch of the service, users were unable to add plugins that were not already on the list. However, the site has recently undergone some updates so that you can now create a profile. Users can now upload themes and plugins to their WPRoller profile that will also be rolled into their custom WordPress installation. A killer feature if you ask me. Any theme or plugin that is uploaded to your profile is private. No one else can access that information which should generate a sigh of relief from commercial theme and plugin companies. </p>\n<p><a href="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/wproller-profile.jpg" rel="thumbnail"><img src="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/wproller-profile.jpg?resize=300%2C138" alt="WPRoller Profiles" class="aligncenter size-medium wp-image-6810" /></a></p>\n<p>Once you&#8217;ve gone through and created your WordPress package, you&#8217;ll have the opportunity to save it for future re-use. Being able to have multiple WordPress packages saved to your profile provides the ability to easily have different installations based on a clients/users needs. All of this is accomplished without modifying the core of WordPress which again, is a nice feature in and of itself. Depending upon how many plugins are added to a WordPress package, the zip file will range between 5-100 megs in size. So if you end up timing the 5 minute WordPress install claim, don&#8217;t add the time it takes to upload the zip file as that&#8217;s not fair.</p>\n<p>I can&#8217;t believe this website is free. As far as I can tell, there doesn&#8217;t appear to be a limit to the amount of plugins in the package, size of the zip file, or the number of packages you can save to your profile. Oh, if you&#8217;re wondering whether or not the plugins packaged with your WordPress install are up to date, <a href="http://wproller.com/blog/wproller-com-updates/plugins-updated-3-27-2013/">WPRoller says</a> they have a nightly Cron job running to make sure the latest versions end up in your installation zip file. While their last blog post was on April 10th, WPRoller has plans to allow custom install.php, wp-config.php and .htaccess files as well as installation starter packages for particular use case segments.</p>\n<p>So what I want to know from you is whether or not you&#8217;ve used this service and if so, has it really made your life of launching WordPress based sites easier? After all, this was only a pipe dream 4 years ago, and while plugins have been released since then to sort of create various WordPress install profiles, I just love the simplicity of how WPRoller executes its mission.</p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/six-revisions-on-missing-features-in-wordpress" rel="bookmark" title="Six Revisions On Missing Features In WordPress">Six Revisions On Missing Features In WordPress</a></li>\n<li><a href="http://www.wptavern.com/custom-install-profiles-sounds-like-a-cool-idea" rel="bookmark" title="Custom Install Profiles Sounds Like A Cool Idea">Custom Install Profiles Sounds Like A Cool Idea</a></li>\n<li><a href="http://www.wptavern.com/favoriting-posts-in-wordpress" rel="bookmark" title="Favoriting Posts In WordPress">Favoriting Posts In WordPress</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/fAU7A6fErwI" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 06 May 2013 20:41:35 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:37;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:70:"WordPress.tv: Steve Burge: How to Make Great Tutorial WordPress Videos";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=18855";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:87:"http://wordpress.tv/2013/05/06/steve-burge-how-to-make-great-tutorial-wordpress-videos/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:690:"<div id="v-DiPjDDdN-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/18855/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/18855/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=18855&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/06/steve-burge-how-to-make-great-tutorial-wordpress-videos/"><img alt="Steve Burge: How to Make Great Tutorial WordPress Videos" src="http://videos.videopress.com/DiPjDDdN/video-8c06be2fea_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 06 May 2013 16:13:34 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:38;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:47:"WPTavern: First WordCamp North Canton A Success";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=6768";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:99:"http://feedproxy.google.com/~r/WordpressTavern/~3/v2lT_-FS3bQ/first-wordcamp-north-canton-a-success";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:5372:"<p>Over the weekend, I had the opportunity to attend <a href="http://2013.northcanton.wordcamp.org/" title="WordCamp NorthCanton">WordCamp North Canton</a> located in North Canton, Ohio. The event took place on the Stark State College Campus within the Center for Entrepreneurship and was coordinated by Joe Rozsa. The venue offered plenty of seating, multiple classrooms for sessions and outlets galore for charging electronic devices. Although the WiFi at the event was surprisingly low speed considering the venue, it was&#8217;nt enough to notice when tweeting or pushing out images. In fact, there was little in the way of problems with the WiFi. </p>\n\n<a href="http://www.wptavern.com/first-wordcamp-north-canton-a-success/attachment/112" title="112"><img src="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/112.jpg?resize=150%2C150" class="attachment-thumbnail" alt="112" /></a>\n<a href="http://www.wptavern.com/first-wordcamp-north-canton-a-success/attachment/113" title="113"><img src="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/113.jpg?resize=150%2C150" class="attachment-thumbnail" alt="113" /></a>\n<a href="http://www.wptavern.com/first-wordcamp-north-canton-a-success/attachment/114" title="114"><img src="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/114.jpg?resize=150%2C150" class="attachment-thumbnail" alt="114" /></a>\n<a href="http://www.wptavern.com/first-wordcamp-north-canton-a-success/attachment/116" title="116"><img src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/116.jpg?resize=150%2C150" class="attachment-thumbnail" alt="116" /></a>\n<a href="http://www.wptavern.com/first-wordcamp-north-canton-a-success/attachment/115" title="115"><img src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/115.jpg?resize=150%2C150" class="attachment-thumbnail" alt="115" /></a>\n<a href="http://www.wptavern.com/first-wordcamp-north-canton-a-success/attachment/117" title="117"><img src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/117.jpg?resize=150%2C150" class="attachment-thumbnail" alt="117" /></a>\n\n<p>One of the cool aspects of this event is that it was the first WordCamp to have a Zero waste strategy. Everything used during the event was either recyclable or fully bio-degradable. There was a station set up in the back of the main room staffed by volunteers to help make sure things were put in the proper place. Having zero waste at a WordCamp event is beneficial no matter how you look at it. From what I heard, Joe Rozsa will be putting together a tutorial for how he accomplished this feat which will be shared on WordCamp.org for other organizers to take advantage of. </p>\n<p>One of the highlights for me was the lunch prepared by <a href="http://ermannospizza.com/">Ermannos pizza</a>. They brought in a selection of pizzas but my favorite was their Margherita which contained Extra Virgin Olive oil Infused with Garlic, their Triple Blend Cheese, Roma Tomatoes, Fresh Basil. Topped with Parmesan &#038; Romano Cheese, Italian Herbs &#038; Seasonings, and Balsamic Glaze. This pizza was awesome and when I&#8217;m back in the North Canton area, I&#8217;ll definitely be stopping by for some more. </p>\n<p><a href="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/119.jpg" rel="thumbnail"><img src="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/119.jpg?resize=224%2C300" alt="119" class="aligncenter size-medium wp-image-6776" /></a></p>\n<p>One other treat that I&#8217;ve not seen at any WordCamps is S&#8217;mores. Ermanno&#8217;s also baked ravioli stuffed s&#8217;mores that were fluffy, gooey pastries filled with marshmallow and chocolate. While I managed to eat two of them and then take a few home, I know of a few other attendees that couldn&#8217;t stop eating them. </p>\n<p><a href="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/120.jpg" rel="thumbnail"><img src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/120.jpg?resize=223%2C300" alt="120" class="aligncenter size-medium wp-image-6799" /></a></p>\n<p>Overall, the event was a major success for it being the first of it&#8217;s kind for the North Canton area. The sessions I attended were presented by people passionate about the subject they were talking about. Most of the people in the audience were either new to WordPress or had little to no development experience. I also wanted to point out that a lot of the attendees at this event were women. If s&#8217;mores didn&#8217;t cap off the camp in WordCamp, tents and sleeping bags were among some of the prizes given away at the end of the day. Joe Rozsa and his team of volunteer staff members are to be commended for a job well done.</p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/wordcamp-raleigh-in-may" rel="bookmark" title="WordCamp Raleigh In May">WordCamp Raleigh In May</a></li>\n<li><a href="http://www.wptavern.com/wordcamp-detroit-was-a-good-time" rel="bookmark" title="WordCamp Detroit Was A Good Time">WordCamp Detroit Was A Good Time</a></li>\n<li><a href="http://www.wptavern.com/wordcamp-montreal-a-success" rel="bookmark" title="WordCamp Montreal A Success">WordCamp Montreal A Success</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/v2lT_-FS3bQ" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 06 May 2013 13:45:32 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:39;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n