s";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:58:"WordPress.tv: Joe Boydston: WordPress is Saving Journalism";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=18781";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:77:"http://wordpress.tv/2013/05/04/joe-boydston-wordpress-is-saving-journalism-2/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:674:"<div id="v-v22ljSzm-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/18781/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/18781/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=18781&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/04/joe-boydston-wordpress-is-saving-journalism-2/"><img alt="Joe Boydston: WordPress is Saving Journalism" src="http://videos.videopress.com/v22ljSzm/video-4340159efd_scruberthumbnail_1.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sun, 05 May 2013 01:12:29 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:43;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:47:"Alex King: Capsule Hotkeys and Background Queue";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://alexking.org/?p=16768";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:57:"http://alexking.org/blog/2013/05/04/capsule-hotkeys-queue";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2238:"<p>It&#8217;s been very gratifying to see people continuing to discover <a href="http://crowdfavorite.com/capsule/">Capsule</a> this week, and seeing it resonate with them. This was typed into the demo earlier today:</p>\n<blockquote><p>\n  This software is an example of a thing that everyone wants but doesn&#8217;t exist until a great idea suddenly comes and voila! it appears!\n</p></blockquote>\n<p>There are a couple of new features committed to GitHub that you can play with if you like.</p>\n<h2>Hotkeys</h2>\n<p>In the <code>feature/hotkeys</code> branch<sup id="fnref:1"><a href="http://alexking.org/blog/topic/wordpress/feed#fn:1" rel="footnote">1</a></sup> in the <code>ui</code> submodule, you&#8217;ll find some additional keyboard shortcuts:</p>\n<ul>\n<li>shift+h = navigate to home</li>\n<li>shift+n = new entry</li>\n<li>shift+f = set focus to search field</li>\n</ul>\n<p>Make sure to update submodules as the <a href="https://github.com/jeresig/jquery.hotkeys">jQuery Hotkeys library</a> has been added.</p>\n<h2>Capsule Server Queue</h2>\n<p>In the <code>feature/queue</code> branch you&#8217;ll find an implementation of a very basic &#8220;send at least once&#8221; queue so that pushing posts to Capsule Server is no longer a blocking action (it makes saves faster). Another benefit to this feature is better support for using Capsule while offline. Saved entries are stored in the queue and sent to Capsule Server once Capsule is online again. To test this out, you&#8217;ll need to update your Capsule Server to the latest code in the <code>develop</code> branch.</p>\n<p>We&#8217;ve also <a href="https://github.com/crowdfavorite/wp-capsule/issues?page=1&state=closed">fixed a few bugs and incorporated a few submitted enhancements</a>. Thanks to everyone who has contributed.</p>\n<div class="footnotes">\n<hr />\n<ol>\n<li id="fn:1">\nWe use the excellent <a href="https://github.com/nvie/gitflow">Git Flow model</a> at <a href="http://crowdfavorite.com">Crowd Favorite</a>. Features are implemented in <code>feature</code> branches before being merged back to <code>develop</code> and subsequently into a release.&#160;<a href="http://alexking.org/blog/topic/wordpress/feed#fnref:1" rev="footnote">&#8617;</a>\n</li>\n</ol>\n</div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 04 May 2013 20:14:09 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Alex";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:44;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:76:"WordPress.tv: Evan Mullins: Your Firstborn Child Theme- Child Themes 101+102";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=18732";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:91:"http://wordpre