INSERT INTO `wp_2_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(90, 3, '2010-06-22 14:19:25', '2010-06-22 14:19:25', 'I don''t want to grieve forever. I don''t want to wish forever. I''m trying to parse the difference between honoring and grieving. It''s work- lovingly remembering and creatively honoring a dream. More often than not I need that work and dive in: I find it healing. It takes me back to that powerful world after Tiger died but before he was gone. All walls had crumbled and the sky went on forever. I was drenched in sorrow and fully alive. Maternal energy hung around me like the saints'' glow on a Catholic holy card and escaped out- having lost its intended (earthly) destination. I wanted to be anywhere but there, yet embraced my surroundings, my new eyes, my body that didn''t die. I think this is where the magical thinking lives for baby-loss mothers.\r\n\r\nWe want another child and my body can''t do it. I really want someone to carry our baby. And then, since that seems impossible, we want to adopt.... because I believe that another child is meant to be in our family. Still, I believe that. But some days I just don''t have the reserves.. to be my age, to be so dependent on a stranger and their sadness of giving up a child, to be so far from the joy of carrying your own. I am struck numb at the process of being interviewed and judged to love a baby. Who could love a baby more than Tom and I? <em>ok then, prove it. </em>\r\n\r\n<em><em><a href="http://susantomwillandtiger.hopeinloss.org/files/2010/06/IMG_0513.jpg"><img title="IMG_0513" src="http://susantomwillandtiger.hopeinloss.org/files/2010/06/IMG_0513-300x225.jpg" alt="" width="240" height="180" /></a></em></em>', 'Where do we go from here my love? Where will we be tomorrow? ', '', 'publish', 'open', 'open', '', 'where-do-we-go-from-here-my-love-where-will-we-be-tomorrow', '', '', '2010-06-22 14:25:06', '2010-06-22 14:25:06', '', 0, 'http://susantomwillandtiger.hopeinloss.org/?p=90', 0, 'post', '', 0),
(2, 2, '2010-04-07 11:00:22', '2010-04-07 11:00:22', 'This is an example of a WordPress page, you could edit this to put information about yourself or your site so readers know where you are coming from. You can create as many pages like this one or sub-pages as you like and manage all of your content inside of WordPress.', 'About', '', 'publish', 'open', 'open', '', 'about', '', '', '2010-04-07 11:00:22', '2010-04-07 11:00:22', '', 0, '', 0, 'page', '', 0),
(92, 3, '2010-06-22 14:17:51', '2010-06-22 14:17:51', 'I don''t want to grieve forever. I don''t want to wish forever. I''m trying to parse the difference between honoring and grieving. It''s work- lovingly remembering and creatively honoring a dream. More often than not I need that work and dive in: I find it healing. It takes me back to that powerful world after Tiger died but before he was gone. All walls had crumbled and the sky went on forever. I was drenched in sorrow and fully alive. Maternal energy hung around me like the saints'' glow on a Catholic holy card and escaped out- having lost its intended (earthly) destination. I wanted to be anywhere but there, yet embraced my surroundings, my new eyes, my body that didn''t die. I think this is where the magical thinking lives for baby-loss mothers.\n\nWe want another child and my body can''t do it. I really want someone to carry our baby. And then, since that seems impossible, we want to adopt.... because I believe that another child is meant to be in our family. Still, I believe that. But some days I just don''t have the reserves.. to be my age, to be so dependent on a stranger and their sadness of giving up a child, to be so far from the joy of carrying your own. I am struck numb at the process of being interviewed and judged to love a baby. Who could love a baby more than Tom and I? <em>ok then, prove it. </em>\n\n<em><em><a href="http://susantomwillandtiger.hopeinloss.org/files/2010/06/IMG_0513.jpg"><img title="IMG_0513" src="http://susantomwillandtiger.hopeinloss.org/files/2010/06/IMG_0513-300x225.jpg" alt="" width="240" height="180" /></a></em></em>', 'Where do we go from here my love? Where will we be tomorrow? ', '', 'inherit', 'open', 'open', '', '90-revision-2', '', '', '2010-06-22 14:17:51', '2010-06-22 14:17:51', '', 90, 'http://susantomwillandtiger.hopeinloss.org/2010/06/22/90-revision-2/', 0, 'revision', '', 0),
(91, 3, '2010-06-22 14:16:51', '2010-06-22 14:16:51', 'I don''t want to grieve forever. I don''t want to wish forever. I''m trying to parse the difference between honoring and grieving. It''s work- lovingly remembering and creatively honoring a dream. More often than not I need that work and dive in: I find it healing. It takes me back to that powerful world after Tiger died but before he was gone. All walls had crumbled and the sky went on forever. I was drenched in sorrow and fully alive. Maternal energy hung around me like the saints'' glow on a Catholic holy card and escaped out- having lost its intended (earthly) destination. I wanted to be anywhere but there, yet embraced my surroundings, my new eyes, my body that didn''t die. I think this is where the magical thinking lives for baby-loss mothers.\n\nWe want another child and my body can''t do it. I really want someone to carry our baby. And then, since that seems impossible, we want to adopt.... because I believe that another child is meant to be in our family. Still, I believe that. But some days I just don''t have the reserves.. to be my age, to be so dependent on a stranger and their sadness of giving up a child, to be so far from the joy of carrying your own. I am struck numb at the process of being interviewed and judged to love a baby. Who could love a baby more than Tom and I? Ok then, prove it than Tom and I? <em>ok then, prove it. <a href="http://susantomwillandtiger.hopeinloss.org/files/2010/06/IMG_0513.jpg"><img class="alignnone size-medium wp-image-87" title="IMG_0513" src="http://susantomwillandtiger.hopeinloss.org/files/2010/06/IMG_0513-300x225.jpg" alt="" width="240" height="180" /></a></em>', 'Where do we go from here my love? Where will we be tomorrow? ', '', 'inherit', 'open', 'open', '', '90-revision', '', '', '2010-06-22 14:16:51', '2010-06-22 14:16:51', '', 90, 'http://susantomwillandtiger.hopeinloss.org/2010/06/22/90-revision/', 0, 'revision', '', 0),
(8, 2, '2010-04-17 22:32:46', '2010-04-17 22:32:46', '<strong>Will Brennan February 12, 2006- February 13, 2006</strong>\r\n\r\n<em>"To live in this world you must be able to do three things: to love what is mortal, to hold it against your bones knowing your own life depends on it, and when the time comes to let it go, to let it go"</em>. - Mary Oliver', 'For Will', '', 'publish', 'open', 'open', '', 'for-will', '', '', '2010-04-20 13:41:19', '2010-04-20 13:41:19', '', 0, 'http://susantomwillandtiger.hopeinloss.org/?page_id=8', 0, 'page', '', 0),
(9, 2, '2010-04-17 22:32:15', '2010-04-17 22:32:15', '<em>"To live in this world you must be able to do three things: to love what is mortal, to hold it against your bones knowing your own life depends on it, and when the time comes to let it go, to let it go"</em>. - Mary Oliver', 'For Will', '', 'inherit', 'open', 'open', '', '8-revision', '', '', '2010-04-17 22:32:15', '2010-04-17 22:32:15', '', 8, 'http://susantomwillandtiger.hopeinloss.org/2010/04/17/8-revision/', 0, 'revision', '', 0),
(5, 3, '2010-04-15 17:53:07', '2010-04-15 17:53:07', 'I love the name Tiger now.\r\n\r\nA beautiful spring morning in Brooklyn, walking Fletcher in the park.... and the tulips at Will''s tree are in bloom.... and I wanted you with me. I guess I longed for these morning walks with you, like I had with Lucy and Fletch minus Will''s tree years ago now. I thought we would go and visit Will- and life and death would combine just to be Love. Without you this morning I danced the life part.... found myself jealous of the flowers for being nourished by your ashes.... and once again tried to gather it all as love and bring it home, help it motivate the process of finding the child who will join our family.\r\n\r\nYou both are so present in our lives, only not in the way I had dreamed. So very different  sweet boys.', 'not a walk in the park', '', 'publish', 'open', 'open', '', 'not-a-walk-in-the-park', '', '', '2010-04-15 17:53:07', '2010-04-15 17:53:07', '', 0, 'http://susantomwillandtiger.hopeinloss.org/?p=5', 0, 'post', '', 0),
(6, 3, '2010-04-15 17:52:12', '2010-04-15 17:52:12', 'I love the name Tiger now.\n\nA beautiful spring morning in Brooklyn, walking Fletcher in the park.... and the tulips at Will''s tree are in bloom.... and I wanted you with me. I guess I longed for these morning walks with you, like I had with Lucy and Fletch minus Will''s tree years ago now. I thought we would go and visit Will and life and death would combine just to be love. Without you this morning I danced the life part.... found myself jealous of the flowers for being nourished by your ashes.... and once again tried to gather it all as love and bring it home, help it motivate the process to finding the child who will join our family.\n\nYou both are so present in our lives, only not in the way I had dreamed. Quite, quite different my sweet boys.', 'not a walk in the park', '', 'inherit', 'open', 'open', '', '5-revision', '', '', '2010-04-15 17:52:12', '2010-04-15 17:52:12', '', 5, 'http://susantomwillandtiger.hopeinloss.org/2010/04/15/5-revision/', 0, 'revision', '', 0),
(10, 2, '2010-04-17 22:32:19', '2010-04-17 22:32:19', '<em>"To live in this world you must be able to do three things: to love what is mortal, to hold it against your bones knowing your own life depends on it, and when the time comes to let it go, to let it go"</em>. - Mary Oliver', 'For Will', '', 'inherit', 'open', 'open', '', '8-revision-2', '', '', '2010-04-17 22:32:19', '2010-04-17 22:32:19', '', 8, 'http://susantomwillandtiger.hopeinloss.org/2010/04/17/8-revision-2/', 0, 'revision', '', 0),
(11, 2, '2010-04-17 22:34:55', '2010-04-17 22:34:55', '<strong>Tiger Brennan June 13, 2009</strong>\r\n\r\n"<em>You, though, you''ll have stars like nobody else." "When you look up at the sky at night, since I''ll be living on one of them, since I''ll be laughing on one of them, for you, it''ll be as if all the stars are laughing. You''ll have stars that can laugh! And when you''re consoled (everyone is eventually consoled), you''ll be glad you''ve known me. You''ll feel like laughing with me. And you''ll open your windows sometimes just for the fun of it... And your friends will be amazed to see you laughing while you''re looking up at the sky."</em>', 'For Tiger', '', 'publish', 'open', 'open', '', 'for-tiger', '', '', '2010-04-20 13:43:13', '2010-04-20 13:43:13', '', 0, 'http://susantomwillandtiger.hopeinloss.org/?page_id=11', 0, 'page', '', 1),
(12, 2, '2010-04-17 22:34:20', '2010-04-17 22:34:20', '', 'For Tiger', '', 'inherit', 'open', 'open', '', '11-revision', '', '', '2010-04-17 22:34:20', '2010-04-17 22:34:20', '', 11, 'http://susantomwillandtiger.hopeinloss.org/2010/04/17/11-revision/', 0, 'revision', '', 0),
(13, 2, '2010-04-17 22:35:10', '2010-04-17 22:35:10', 'I think we should start where I can for now:  Some time after Tiger died- maybe a month, maybe two- Tom and I sat on the steps of our backyard deck. We talked with some strangely inspired clarity about our two boys. We knew Will was strong and gentle. That he would be solid  and true with a sharp sense of humor. He was very different than his sister and would have loved her deeply from a distance. He would always have gone the extra mile. But taken risks. His love would be quiet and complete. Tiger, he was all fire. He was passionate and sneaky. He would have been trouble and would have broken hearts. We would  have held our breath at his risky ways. He would have loved fiercely.  Maybe it was in the names. <em>Maybe</em>. But I don''t think so.\r\n\r\nHere''s what happened...', 'Our Story', '', 'publish', 'open', 'open', '', 'our-story', '', '', '2010-04-22 20:42:09', '2010-04-22 20:42:09', '', 0, 'http://susantomwillandtiger.hopeinloss.org/?page_id=13', 0, 'page', '', 1),
