rg/development/2010/05/wordpress-3-0-beta-2/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:71:"http://wordpress.org/development/2010/05/wordpress-3-0-beta-2/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 May 2010 21:05:35 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:2:{i:0;a:5:{s:4:"data";s:11:"Development";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:7:"Testing";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1340";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:370:"Following the successful post-WordCamp San Francisco code sprint, we are now ready to release the second beta of WordPress 3.0.\nThings to test:\n\nRevised menu user interface\nChanges to the WordPress exporter and importer to make it more flexible\n\nAlready have a test install that you want to switch over to the beta? Try the beta tester plugin.\nTesters, don&#8217;t [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:14:"Peter Westwood";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:983:"<p>Following the successful post-WordCamp San Francisco code sprint, we are now ready to release the second beta of WordPress 3.0.<br />\nThings to test:</p>\n<ul>\n<li>Revised menu user interface</li>\n<li>Changes to the WordPress exporter and importer to make it more flexible</li>\n</ul>\n<p>Already have a test install that you want to switch over to the beta? Try the <a href="http://westi.wordpress.com/2009/06/22/making-it-easy-to-be-a-wordpress-tester/">beta tester plugin</a>.</p>\n<p>Testers, don&#8217;t forget to use the <a href="http://lists.automattic.com/mailman/listinfo/wp-testers">wp-testers mailing list</a> to discuss bugs you encounter.</p>\n<p>We hope you like it! And if you don&#8217;t, well, check back when the release candidate is ready. <img src=''http://wordpress.org/development/wp-includes/images/smilies/icon_smile.gif'' alt='':)'' class=''wp-smiley'' /> </p>\n<p>Download the <a href="http://wordpress.org/wordpress-3.0-beta2.zip">WordPress 3.0 Beta 2</a> now!</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:67:"http://wordpress.org/development/2010/05/wordpress-3-0-beta-2/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"0";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:1;a:6:{s:4:"data";s:47:"\n		\n		\n		\n		\n		\n				\n		\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:27:"WordCamp San Francisco 2010";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:57:"http://wordpress.org/development/2010/04/wordcampsf-2010/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:66:"http://wordpress.org/development/2010/04/wordcampsf-2010/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 24 Apr 2010 15:49:24 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:3:{i:0;a:5:{s:4:"data";s:9:"Community";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:6:"Events";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:2;a:5:{s:4:"data";s:8:"WordCamp";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1326";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:343:"A week from today on May 1, hundreds of WordPress users, developers, designers and general enthusiasts will descend upon San Francisco for the 4th annual WordCamp SF. Since that first WordCamp in 2006, back when WordPress was on version 2.0 (Duke), the number of people using WordPress to power their web publishing &#8212; from personal [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Jane Wells";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:4940:"<p>A week from today on May 1, hundreds of WordPress users, developers, designers and general enthusiasts will descend upon San Francisco for the 4th annual <a href="http://2010.sf.wordcamp.org/">WordCamp SF</a>. Since that first WordCamp in 2006, back when WordPress was on version 2.0 (Duke), the number of people using WordPress to power their web publishing &#8212; from personal blogs to large-scale commercial sites &#8212; has grown by millions. It&#8217;s no wonder this year&#8217;s event is going to be so great.</p>\n<p>If you&#8217;re unfamiliar with <a href="http://wordcamp.org/">WordCamps</a>, here&#8217;s the skinny: the San Francisco event is the flagship, put together each year under the direction of WordPress co-founder and lead developer <a href="http://ma.tt">Matt Mullenweg</a>, who traditionally reports on the &#8220;State of the Word&#8221; and assembles a lineup of <a href="http://2010.sf.wordcamp.org/speakers/">speakers</a> that have inspired him over the past year. This year&#8217;s lineup includes luminaries such as Richard Stallman, the father of Free Software, best-selling author Scott Berkun, and Salon.com co-founder Scott Rosenberg. As the final speaker list is finalized, the remaining speakers will be added to the <a href="http://2010.sf.wordcamp.org/">WordCamp SF website</a>, but a surprise or two is still possible.</p>\n<p>Though the main event is on Saturday, May 1, there are additional <a href="http://2010.sf.wordcamp.org/schedule/">days of WordPress goodness</a> in store. Saturday, May 1 will be the main conference with scheduled speakers. There will be keynotes, session tracks for both bloggers/end-users and developers, and lightning talks to provide a broad mix of content, followed by a raging afterparty. Sunday, May 2 will shift location and tone, with a low-key developers&#8217; unconference for the super-code-focused attendees. May 3 and 4 are conference-free, but a WordPress core contributor in-person code sprint will span those two days, bringing together core contributors old and new from around the globe for two days of intense hacking (and let&#8217;s face it, 3.0 bug fixes).</p>\n<p>If you&#8217;re in the Bay Area, or can be, and want to attend <a href="http://2010.sf.wordcamp.org/">WordCamp San Francisco</a>, <a href="http://2010.sf.wordcamp.org/tickets/">go get your ticket today</a>!</p>\n<p style="text-align: center;">*     *      *      *     *</p>\n<h3><strong>Other Upcoming WordCamps</strong></h3>\n<p>It&#8217;s definitely WordCamp season; just check out the growing list of upcoming WordCamps over the next couple of months! If you don&#8217;t see a WordCamp near you listed here, check the rest of the <a href="http://central.wordcamp.org/schedule/">schedule at WordCamp.org</a>. In the meantime, don&#8217;t forget that many WordCamps post video of their presentations on <a href="http://wordpress.tv">WordPress.tv</a>.</p>\n<p>April 24 (today!) &#8211; <a href="http://www.ocwordcamp.com/">WordCamp Orange County</a><br />\nIrvine, CA USA</p>\n<p>April 29 &#8211; <a href="http://www.wordcampnashville.com/">WordCamp Nashville</a><br />\nNashville, TN USA</p>\n<p><strong>May 1 &#8211; <a href="http://2010.sf.wordcamp.org/">WordCamp San Francisco</a><br />\nSan Francisco, CA USA</strong></p>\n<p>May 8 &#8211; <a href="http://wordcamp.fr/">WordCamp Paris</a><br />\nParis, France</p>\n<p>May 8 &#8211; <a href="http://argentina.wordcamp.org/">WordCamp Argentina </a><br />\nBuenos Aires, Argentina</p>\n<p>May 8 &#8211; <a href="http://chile.wordcamp.org/">WordCamp Chile</a><br />\nSantiago, Chile</p>\n<p>May 15–16 &#8211; <a href="http://denmark.wordcamp.org/">WordCamp Denmark</a><br />\nCopenhagen, Denmark</p>\n<p>May 15 &#8211; <a href="http://www.wordcampvictoria.ca/">WordCamp Victoria</a><br />\nVictoria, BC Canada</p>\n<p>May 21–22 &#8211; <a href="http://www.wordcamp.it/">WordCamp Italy</a><br />\nMilan, Italy</p>\n<p>May 22 &#8211; <a href="http://www.wordcamp.my/">WordCamp Malaysia</a><br />\nKuala Lumpur, Malaysia</p>\n<p>May 22–23 &#8211; <a href="http://wordcampraleigh.com/">WordCamp Raleigh</a><br />\nRaleigh, North Carolina USA</p>\n<p>May 29–30 &#8211; <a href="http://wordcampfayetteville.com/">WordCamp Fayetteville</a><br />\nFayetteville, Arkansas USA</p>\n<p>May 29 &#8211; <a href="http://yokohama2010.wordcamp.jp/">WordCamp Yokohama</a><br />\nYokohama, Japan</p>\n<p>June 5–6 &#8211; <a href="http://wordcampchicago.com/">WordCamp Chicago</a><br />\nChicago, Illinois USA</p>\n<p>June 12 &#8211; <a href="http://www.renotahoewordcamp.com/">WordCamp Reno-Tahoe</a><br />\nReno, Nevada USA</p>\n<p>June 12 &#8211; <a href="http://wordcampvancouver.com/">WordCamp Vancouver</a><br />\nVancouver, Canada</p>\n<p>June 18 &#8211; <a href="http://wordcamp.it/catania2010/">WordCamp Catania</a><br />\nCatania, Italy</p>\n<p>June 19 &#8211; <a href="http://wordcampcolumbus.com/">WordCamp Columbus </a><br />\nColumbus, Ohio USA</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:62:"http://wordpress.org/development/2010/04/wordcampsf-2010/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"0";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:2;a:6:{s:4:"data";s:53:"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:28:"Coming up on Beta 2: Sprint!";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:68:"http://wordpress.org/development/2010/04/coming-up-on-beta-2-sprint/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:77:"http://wordpress.org/development/2010/04/coming-up-on-beta-2-sprint/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 24 Apr 2010 12:08:39 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:5:{i:0;a:5:{s:4:"data";s:9:"Community";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:11:"Development";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:2;a:5:{s:4:"data";s:4:"beta";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:3;a:5:{s:4:"data";s:4:"bugs";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:4;a:5:{s:4:"data";s:7:"patches";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1328";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:301:"Early next week, we&#8217;re hoping to release the 2nd beta release of WordPress 3.0 on our journey toward the final version. There are still over 200 bugs in the 3.0 milestone, and we can use all the help we can get on fixing these problems. If you&#8217;re a developer, take a look at the list [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Jane Wells";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:2953:"<p>Early next week, we&#8217;re hoping to release the 2nd beta release of WordPress 3.0 on our journey toward the final version. There are still <a href="http://core.trac.wordpress.org/query?status=accepted&amp;status=assigned&amp;status=new&amp;status=reopened&amp;status=reviewing&amp;group=status&amp;order=priority&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=priority&amp;col=component&amp;col=version&amp;milestone=3.0&amp;type=defect+%28bug%29">over 200 bugs</a> in the 3.0 milestone, and we can use all the help we can get on fixing these problems. If you&#8217;re a developer, take a look at the list of bugs that <a href="http://core.trac.wordpress.org/query?status=accepted&amp;status=assigned&amp;status=new&amp;status=reopened&amp;status=reviewing&amp;group=status&amp;order=priority&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=priority&amp;col=component&amp;col=version&amp;milestone=3.0&amp;type=defect+%28bug%29">still need fixing</a> in 3.0. <a href="http://core.trac.wordpress.org/query?status=accepted&amp;status=assigned&amp;status=new&amp;status=reopened&amp;status=reviewing&amp;group=status&amp;order=priority&amp;col=id&amp;col=summary&amp;col=type&amp;col=owner&amp;col=priority&amp;col=component&amp;col=version&amp;milestone=3.0&amp;keywords=~needs-patch&amp;type=defect+%28bug%29">Write a patch</a>, or <a href="http://core.trac.wordpress.org/query?status=accepted&amp;status=assigned&amp;status=new&amp;status=reopened&amp;status=reviewing&amp;group=status&amp;order=priority&amp;col=id&amp;col=summary&amp;col=type&amp;col=owner&amp;col=priority&amp;col=component&amp;col=version&amp;milestone=3.0&amp;keywords=~has-patch&amp;type=defect+%28bug%29">test and give feedback</a> on someone else&#8217;s. The tickets around custom post types and taxonomies are especially in need of help. Every little bit helps, so if you&#8217;re a developer who&#8217;s never contributed to core before, maybe now is the right time! Check out our information on <a href="http://codex.wordpress.org/Contributing_to_WordPress">contributing to WordPress core</a>, and head over to <a href="http://core.trac.wordpress.org/">Trac</a> to see if there&#8217;s a problem you might know how to fix. If you get stuck, need collaborators, or have a question about the best way to approach a fix, hop into the dev channel on IRC at irc.freenode.net, channel #wordpress-dev. Core developers will be around over the weekend working on bugs themselves, so if you&#8217;re trying to help, don&#8217;t be afraid to ask questions. With your help, maybe by Monday we can knock the bug count down to half of what it is right now. How great would that be? (Answer: pretty great)</p>\n<p>The sprint will go full force until Monday afternoon, when the lead developers and core committers will all stop to take a breath and look at the remaining bug reports to see how we did over the weekend, so don&#8217;t wait! And thanks!</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:73:"http://wordpress.org/development/2010/04/coming-up-on-beta-2-sprint/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"0";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:3;a:6:{s:4:"data";s:41:"\n		\n		\n		\n		\n		\n				\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:30:"Secure File Permissions Matter";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:58:"http://wordpress.org/development/2010/04/file-permissions/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:67:"http://wordpress.org/development/2010/04/file-permissions/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 13 Apr 2010 19:52:30 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:1:{i:0;a:5:{s:4:"data";s:11:"Development";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1322";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:404:"Summary: A web host had a crappy server configuration that allowed people on the same box to read each others&#8217; configuration files, and some members of the &#8220;security&#8221; press have tried to turn this into a &#8220;WordPress vulnerability&#8221; story.\nWordPress, like all other web applications, must store database connection info in clear text. Encrypting credentials doesn&#8217;t [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:1428:"<p>Summary: A web host had a crappy server configuration that allowed people on the same box to read each others&#8217; configuration files, and some members of the &#8220;security&#8221; press have tried to turn this into a &#8220;WordPress vulnerability&#8221; story.</p>\n<p>WordPress, like <em>all other</em> web applications, must store database connection info in clear text. Encrypting credentials doesn&#8217;t matter because the keys have to be stored where the web server can read them in order to decrypt the data. If a malicious user has access to the file system &#8212; like they appeared to have in this case &#8212; it is trivial to obtain the keys and decrypt the information. When you leave the keys to the door in the lock, does it help to lock the door?</p>\n<p><strong>A properly configured web server will not allow users to access the files of another user, regardless of file permissions.</strong> The web server is the responsibility of the hosting provider. The methods for doing this (suexec, et al) have been around for 5+ years.</p>\n<p>I&#8217;m not even going to link any of the articles because they have so many inaccuracies you become stupider by reading them.</p>\n<p>If you&#8217;re a web host and you turn a bad file permissions story into a WordPress story, you&#8217;re doing something wrong.</p>\n<p>P.S. Network Solutions, it&#8217;s &#8220;WordPress&#8221; not &#8220;Word Press.&#8221;</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:63:"http://wordpress.org/development/2010/04/file-permissions/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"0";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:4;a:6:{s:4:"data";s:44:"\n		\n		\n		\n		\n		\n				\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:35:"GSoC Application Deadline is Today!";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:76:"http://wordpress.org/development/2010/04/gsoc-application-deadline-is-today/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:85:"http://wordpress.org/development/2010/04/gsoc-application-deadline-is-today/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 09 Apr 2010 15:56:35 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:2:{i:0;a:5:{s:4:"data";s:9:"Community";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:4:"GSoC";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1319";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:330:"The deadline for students applying for Google Summer of Code this year is today, at 19:00 UTC. That’s about 3 hours from now. Still working on your application? Double check your time zone here. No late applications will be accepted.\nThere are a lot of potential projects on our Ideas list, so if you&#8217;ve been hemming [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Jane Wells";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:1381:"<p>The deadline for students applying for Google Summer of Code this year is today, at 19:00 UTC. That’s about 3 hours from now. Still working on your application? <a href="http://bit.ly/bP1fXT">Double check your time zone</a> here. <strong>No late applications will be accepted.</strong></p>\n<p>There are a lot of potential projects on <a href="http://codex.wordpress.org/GSoC2010">our Ideas list</a>, so if you&#8217;ve been hemming and hawing over whether or not to apply, this is your last chance for this year. We have great people lined up to mentor the students, including most of the WordPress lead developers, some dedicated core contributors, plugin developers, the BuddyPress lead developers, etc. Google is providing a great opportunity for both students and the open source projects that act as mentoring organizations (like WordPress), so don&#8217;t pass it up if you&#8217;re an eligible student. </p>\n<p>You can’t win if you don’t play, right? Five thousand bucks for two months of coding over the summer with WordPress hotshots. I know a lot of people that would love that deal. Oh, and hey, student girl wonders of WordPress-land: why haven&#8217;t you applied yet?</p>\n<p><a href="http://socghop.appspot.com/">Apply now</a>! (Don&#8217;t forget to use our <a href="http://codex.wordpress.org/GSoC_2010_Application_Template">application template</a>.)</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:81:"http://wordpress.org/development/2010/04/gsoc-application-deadline-is-today/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"0";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:5;a:6:{s:4:"data";s:53:"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:21:"WordPress 3.0, Beta 1";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:62:"http://wordpress.org/development/2010/04/wordpress-3-0-beta-1/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:71:"http://wordpress.org/development/2010/04/wordpress-3-0-beta-1/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 03 Apr 2010 03:12:56 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:5:{i:0;a:5:{s:4:"data";s:11:"Development";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:8:"Releases";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:2;a:5:{s:4:"data";s:7:"Testing";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:3;a:5:{s:4:"data";s:3:"3.0";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:4;a:5:{s:4:"data";s:4:"beta";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1303";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:322:"Remember when I posted earlier about the Twitter account, and I said that hopefully you&#8217;d find out later today what has been keeping us all so busy? Beta testers, this is your moment: the WordPress 3.0 Beta 1 has arrived!\nThis is an early beta. This means there are a few things we&#8217;re still finishing. We [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Jane Wells";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:2988:"<p>Remember when I posted earlier about the Twitter account, and I said that hopefully you&#8217;d find out later today what has been keeping us all so busy? Beta testers, this is your moment: the <a href="http://wordpress.org/wordpress-3.0-beta1.zip">WordPress 3.0 Beta 1</a> has arrived!</p>\n<p>This is an <strong>early beta</strong>. This means there are a few things we&#8217;re still finishing. We wanted to get people testing it this weekend, so we&#8217;re releasing it now rather than waiting another week until everything is finalized and polished. There&#8217;s a ton of stuff going on in 3.0, so this time we&#8217;re giving you a list of things to check out, so that we can make sure people are testing all the things that need it.</p>\n<p><span id="more-1303"></span>You Should Know:</p>\n<ul>\n<li>The custom menus system (Appearance &gt; Menus) is not quite finished. In Beta 2, the layout will be different and a bunch of the functionality will be improved, but we didn&#8217;t want to hold things up for this one screen. You can play with making custom menus, and report bugs if you find them, but this is not how the final screen will look/work, so don&#8217;t get attached to it.</li>\n<li>The merge! Yes, WordPress and WordPress MU have merged. This does not mean that you can suddenly start adding a bunch of new blogs from within your regular WordPress Dashboard. If you&#8217;re interested in testing the Super Admin stuff associated with multiple sites, you&#8217;ll need <a href="http://codex.wordpress.org/User:Andrea/Create_A_Network">some simple directions</a> to get started.</li>\n<li>We&#8217;re still fiddling with a few small things in the UI, as we were focused on getting the more function-oriented code finished first. For example, we&#8217;re getting a new icon for the Super Admin section.</li>\n</ul>\n<p>Things to test:</p>\n<ul>\n<li>Play with the new default theme, Twenty Ten, including the custom background and header options.</li>\n<li>Custom Post Type functionality has been beefed up. It&#8217;s <a href="http://kovshenin.com/archives/custom-post-types-in-wordpress-3-0/">really easy</a> to add new types, so do that and see how it looks!</li>\n<li>WordPress MU users should test the multiple sites functionality to make sure nothing broke during the merge.</li>\n</ul>\n<p>Already have a test install that you want to switch over to the beta? Try the <a href="http://westi.wordpress.com/2009/06/22/making-it-easy-to-be-a-wordpress-tester/">beta tester plugin</a>.</p>\n<p>Testers, don&#8217;t forget to use the <a href="http://lists.automattic.com/mailman/listinfo/wp-testers">wp-testers mailing list</a> to discuss bugs you encounter.</p>\n<p>We hope you like it! And if you don&#8217;t, well, check back when beta 2 is ready. <img src=''http://wordpress.org/development/wp-includes/images/smilies/icon_smile.gif'' alt='':)'' class=''wp-smiley'' /> </p>\n<p>Download the <a href="http://wordpress.org/wordpress-3.0-beta1.zip">WordPress 3.0 Beta 1</a> now!</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:67:"http://wordpress.org/development/2010/04/wordpress-3-0-beta-1/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"0";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:6;a:6:{s:4:"data";s:44:"\n		\n		\n		\n		\n		\n				\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:13:"Tweet, Tweet!";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:53:"http://wordpress.org/development/2010/04/tweet-tweet/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:62:"http://wordpress.org/development/2010/04/tweet-tweet/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 02 Apr 2010 17:20:56 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:2:{i:0;a:5:{s:4:"data";s:9:"Community";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:7:"twitter";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1297";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:332:"This post is about the @WordPress Twitter account, so if you don&#8217;t use Twitter, or don&#8217;t care about Twitter, then feel free to take the time you might have spent reading this post to go play outside (or an equivalent) instead.\nOkay, so, Twitter! When all those apps started popping up using the Twitter API, things [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Jane Wells";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:3978:"<p>This post is about the <a href="https://twitter.com/wordpress">@WordPress</a> Twitter account, so if you don&#8217;t use <a href="https://twitter.com/">Twitter</a>, or don&#8217;t care about Twitter, then feel free to take the time you might have spent reading this post to go play outside (or an equivalent) instead.</p>\n<p>Okay, so, Twitter! When all those apps started popping up using the Twitter API, things like automatically following anyone who followed you and sending an automatic Direct Message seemed like good ideas. We&#8217;re all friends, right? Wrong. That auto-follow bit us hard, and the huge amount of spam the account gets means that it&#8217;s been nearly impossible to monitor legitimate messages from WordPress users and developers who need to be pointed to a help resource. We&#8217;re sorry! Just as we needed to get the <a href="http://wordpress.org/extend/ideas/">Ideas Forum</a> under control* so that it could become a more useful resource for the community, we needed to get rid of the spam clogging our Twitter arteries. Except there was no easy way to do it.</p>\n<p>We had wound up following over 50,000 people. If someone went to the @WordPress profile page on Twitter to see the stream of updates from people we followed, almost none of it had anything to do with WordPress or the community. Diet pills, Twitter scams, and multi-posted spam messages were the norm. Yuck! Who else wishes there was <a href="http://akismet.com/">Akismet</a> for Twitter? Unfortunately, there&#8217;s no easy way to clear this stuff out quickly (mass unfollows trigger their TOS alert, so it&#8217;s not surprising). I even contacted Twitter directly to see what the options might be, and it was suggested we use a script to clear the account.<strong> To be clear: </strong>Twitter flagged our account so that when the script was run they wouldn&#8217;t mark us as spammers for violating the TOS with a mass unfollow. We communicated with them beforehand, and the use of scripts to do this is not encouraged. Twitter was doing us a nice favor to help us get our house in order. Thanks, Twitter! Last night I ran the script and removed everyone. Extreme, but in good cause, right?</p>\n<p>We&#8217;re now starting to re-follow real people from the WordPress community. There will be no more auto-follow. If you are a WordPress developer, designer, blogger, fan site, whatever &#8212; and think your tweets should appear in the @WordPress updates stream, then send an @ reply to us and we can add you to the new list (assuming you&#8217;re not hawking diet pills, free iPads or ways to get a million followers). This way, people who are new to WordPress and go to check us out on Twitter will (hopefully) get a sense of the vibrant community that we have. People who send @ messages to us won&#8217;t (hopefully) wonder indefinitely why they were ignored, because without all the spam, maybe we can use Twitter as it was intended to be used, as another channel of communication.</p>\n<p>And for anyone who uses Qwitter and thinks @WordPress stopped loving them because of the last tweet they posted before the script ran&#8230; sorry! It wasn&#8217;t like that, we swear! It would be nice if the script could have done a bulk DM before the removal, but nope (otherwise we&#8217;d have included a message about this). So trust us, we still like you! And if you haven&#8217;t already been re-followed, please don&#8217;t take it personally&#8230; just send an @reply to @WordPress (tell us how you use WordPress!) and we&#8217;ll try to get you re-added soon. Later today (hopefully) you&#8217;ll find out what&#8217;s been keeping us so busy!</p>\n<p><em>*Have you noticed? We cleared out thousands of old threads, added categorization, and will try to keep it to under a hundred open idea threads at a time so that they can be managed in a timely fashion. <a href="http://wordpress.org/extend/ideas/">Check it out</a> and rate some of the new ideas today!</em></p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:58:"http://wordpress.org/development/2010/04/tweet-tweet/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"0";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:7;a:6:{s:4:"data";s:44:"\n		\n		\n		\n		\n		\n				\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:32:"Summer of WordPress 2010: Act II";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:73:"http://wordpress.org/development/2010/03/summer-of-wordpress-2010-act-ii/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:82:"http://wordpress.org/development/2010/03/summer-of-wordpress-2010-act-ii/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 29 Mar 2010 15:45:02 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:2:{i:0;a:5:{s:4:"data";s:9:"Community";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:11:"Development";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1281";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:346:"Scene: A college classroom\nProfessor: So. Out of the 20 students in the class, half wrote WordPress Summer of Code proposals good enough to receive an A. How many of you are planning to apply for the program?\nJack, a student: I am. They opened applications today.\nSophie, a student: I am. And that sentence was grammatically terrible.\nJack: [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Jane Wells";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:5148:"<p><em>Scene: A college classroom</em></p>\n<p><strong>Professor: </strong>So. Out of the 20 students in the class, half wrote <a href="http://wordpress.org/gsoc">WordPress Summer of Code</a> proposals good enough to receive an A. How many of you are planning to apply for the program?</p>\n<p><strong>Jack, a student:</strong> I am. They opened applications today.</p>\n<p><strong>Sophie, a student: </strong>I am. And that sentence was grammatically terrible.</p>\n<p><strong>Jack: </strong>Shut up.</p>\n<p><strong>Chris, a student: </strong>I&#8217;m not applying.</p>\n<p><strong>Jack</strong> (to Chris)<strong>:</strong> Chicken?</p>\n<p><strong>Sophie:</strong> You&#8217;re such a jerk! Maybe he has a job lined up or something, did you ever think of that?</p>\n<p><strong>Professor:</strong> Whoa -</p>\n<p><strong>Chris: </strong>Actually, I&#8217;m going backpacking in Australia with my Dad. No internet for about half the time, and when I emailed the people at WordPress they said I should probably wait until next year to apply and make sure I&#8217;d be able to be online through the whole summer.</p>\n<p><strong>Professor: </strong>Fair enough. The application period opens today at 19:00 UTC and goes through April 9th, so let&#8217;s hear from the people who are applying.</p>\n<p><strong>Jack:</strong> I&#8217;m submitting mine today.</p>\n<p><strong>Sophie: </strong>That&#8217;s just stupid.</p>\n<p><strong>Andrea, a teacher’s assistant: </strong>Hey, that&#8217;s not necessary.</p>\n<p><strong>Jack: </strong>Yeah! The early bird gets the worm, or hadn&#8217;t you heard?</p>\n<p><strong>Sophie:</strong> What I heard was that the WordPress mentors are holding open IRC chats this week to talk to prospective students and give them feedback on proposals and ideas, and that talking directly to the mentors ups your chances of being selected. But I guess you don&#8217;t think you need the people who are actually choosing the students to know your name because your proposal is so brilliant?</p>\n<p><em>Jack&#8217;s jaw drops.</em></p>\n<p><strong>Jack: </strong>Where did you hear that? It wasn&#8217;t on the GSoC mailing list.</p>\n<p><strong>Sophie: </strong>I joined the wp-hackers list and asked all the core contributors for feedback on my idea, and then I emailed 3 potential mentors to see what they thought of it personally. By the time applications are due, I&#8217;ll have revised it based on community and mentor feedback, and enough people will know who I am &#8212; and that I&#8217;m full of initiative &#8212; that my chances of being accepted will be much better.</p>\n<p><strong>Jack: </strong>You think you&#8217;re all Felicia Day with your MW2 level 70, but you&#8217;re just a computer nerd.</p>\n<p><strong>Sophie:</strong> Um, duh. We&#8217;re in an advanced computer programming class. We&#8217;re all computer nerds.</p>\n<p><strong>Professor: </strong>Now, now. Sophie&#8217;s correct; talking to community members and mentors will improve her chances. But, Jack, there&#8217;s no reason you can&#8217;t join the IRC chats and the mailing list to get your name out there, too, even if you submit your application today. Most proposals get tweaked a bit after the students are chosen anyway.</p>\n<p><strong>Sophie: </strong>Plus, Felicia Day is awesome! And <a href="http://feliciaday.com/blog">she uses WordPress</a>, so ha!</p>\n<p><em>End Act II.</em></p>\n<p>Here&#8217;s the deal. <a href="http://socghop.appspot.com/site/home/site">The application period opens today</a>. Early applications will likely get a bit more attention up front, but it&#8217;s also important that your ideas and approach are vetted by the community and <a href="http://codex.wordpress.org/GSoC2010#Mentors">the mentors</a>. If you haven&#8217;t already, you should join the <a href="http://lists.automattic.com/mailman/listinfo/wp-hackers">wp-hackers mailing list</a> and send your proposal to the list for feedback. We&#8217;ll also be doing a few IRC chats during the application period to give students a chance to talk directly with the mentors. Note that not every mentor will attend all three chats, so if you want to talk to a specific person, you might want to email them. Please arrive on time to the chats, as they will be scheduled for an hour, and will have to accommodate multiple students. IRC chats will be held at irc.freenode.net in room #wordpress-gsoc.</p>\n<ul>\n<li>Wednesday, March March 31 at 20:30 UTC (4:30pm eastern)</li>\n<li>Saturday, April 3 at 21:30 UTC (5:30pm eastern)</li>\n<li>Wednesday, April 7 at 20:30 UTC (4:30pm eastern)</li>\n</ul>\n<p>This chat room will remain open during the application period, and various mentors and community members may be there and able to answer questions, but the scheduled chats are the only official times at which they are scheduled to do so.</p>\n<p>Oh, and if you want to help publicize the WordPress summer of code, <a href="http://wpdevel.files.wordpress.com/2010/03/wordpress-gsoc-flyer.pdf">grab a flyer</a> and post it somewhere on a bulletin board at your local college campus. Professors, don&#8217;t forget to encourage your brightest students to apply!</p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:78:"http://wordpress.org/development/2010/03/summer-of-wordpress-2010-act-ii/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"0";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:8;a:6:{s:4:"data";s:59:"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:31:"Summer of WordPress 2010: Act I";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:66:"http://wordpress.org/development/2010/03/summer-of-wordpress-2010/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:75:"http://wordpress.org/development/2010/03/summer-of-wordpress-2010/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sun, 21 Mar 2010 21:52:21 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:7:{i:0;a:5:{s:4:"data";s:9:"Community";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:11:"Development";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:2;a:5:{s:4:"data";s:7:"college";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:3;a:5:{s:4:"data";s:6:"google";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:4;a:5:{s:4:"data";s:4:"GSoC";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:5;a:5:{s:4:"data";s:10:"Internship";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:6;a:5:{s:4:"data";s:8:"students";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1266";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:341:"Scene: A college classroom\nProfessor: Is anyone here applying for Google Summer of Code this year? If so, see me after class to discuss getting independent study credit toward your degree.\nJack, a student: Isn&#8217;t that a really hard program to get into? Like, hard like getting to level 70 in Modern Warfare 2?\nSophie, a student: I [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Jane Wells";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:5343:"<p><em>Scene: A college classroom</em></p>\n<p><strong>Professor: </strong>Is anyone here applying for <a href="http://socghop.appspot.com/site/home/site">Google Summer of Code</a> this year? If so, see me after class to discuss getting independent study credit toward your degree.</p>\n<p><strong>Jack, a student:</strong> Isn&#8217;t that a really hard program to get into? Like, hard like getting to level 70 in Modern Warfare 2?</p>\n<p><strong>Sophie, a student: </strong>I went past 70, I prestiged.</p>\n<p><strong>Jack</strong> (turning to Sophie)<strong>:</strong> Shut up, you did not!</p>\n<p><strong>Sophie:</strong> I did, too!</p>\n<p><strong>Professor:</strong> Not the point, kids. So who&#8217;s going to try for a GSoC spot?</p>\n<p><strong>Andrea, a teacher&#8217;s assistant: </strong>There are some great open source projects participating this year. I&#8217;d love to see someone from this class get in on the WordPress project.</p>\n<p><strong>Jack:</strong> WordPress is awesome, but my friend <a href="http://wordpress.org/development/2009/03/wordpress-summer-of-code-2009">Billy</a> didn&#8217;t get chosen by them <a href="http://wordpress.org/development/2009/04/summer-of-code-students-announced/">last year</a>.</p>\n<p><strong>Sophie:</strong> Billy&#8217;s not as smart as he thinks he is.</p>\n<p><strong>Jack: </strong>You think you could do better?!</p>\n<p><strong>Sophie:</strong> Of course I do! Any primate could do better than Billy! Or you, for that matter!</p>\n<p><strong>Jack: </strong>What? I would so beat you out in a coding competition!</p>\n<p><strong>Andrea: </strong>Sounds like we have the makings of a friendly classroom competition, Prof.</p>\n<p><strong>Professor: </strong>I think you&#8217;re right, Andrea. Tell you kids what. They announce the students who&#8217;ve been accepted on April 26th, which is before the semester ends. Let&#8217;s turn this into a class project.</p>\n<p><strong>Jack </strong>(raising a suspicious eyebrow)<strong>:</strong> How do you mean?</p>\n<p><strong>Professor: </strong>As a class assignment, everyone has one week to write a project proposal for the Google Summer of Code, specific to the WordPress project. The proposals will be graded like a regular assignment. Anyone who gets an A on the proposal can use me as a reference if they apply with the proposal to WordPress and Google for the program. The application deadline is <strong>April 9</strong>, so you&#8217;ll have time to revise your application after it&#8217;s been graded.</p>\n<p><strong>Sophie: </strong>What&#8217;s in it for us?</p>\n<p><strong>Andrea: </strong>If you&#8217;re successful in GSoC you earn $5000 for the summer.</p>\n<p><strong>Sophie </strong>(smirking, to Jack)<strong>: </strong>That&#8217;s more than you&#8217;ll make working the hot dog cart by City Hall.</p>\n<p><strong>Jack:</strong> You wish. I&#8217;m totally getting in, and you&#8217;ll be on the hot dog cart this year.</p>\n<p><strong>Professor: </strong>And as I was starting to say in the first place, a GSoC project would qualify for independent study credit. Tell you what, as an added bonus, anyone who actually gets accepted into the WordPress GSoC program will get extra credit points on their year end average.</p>\n<p><strong>Sophie </strong>(perking up)<strong>:</strong> Really? I&#8217;m in!</p>\n<p><strong>Jack: </strong>No way, they&#8217;ll choose me first!</p>\n<p><em>Stay tuned for the continuing adventures of Jack and Sophie as they navigate the course of applying to Google Summer of Code to work with WordPress.</em></p>\n<p>That&#8217;s right, WordPress is honored to be among the 150 open source organizations chosen to participate in Google Summer of Code this year. Students work on WordPress projects over the summer under the guidance of mentors from among the WordPress core developers, and if they complete their projects successfully Google pays them $5000! Talk about a win-win. Last year&#8217;s projects led to some very cool code being created, like the <a href="http://core.trac.wordpress.org/ticket/10667">new search API</a> targeted for version 3.0 and the <a href="http://elastictheme.org/">Elastic theme generator</a>.</p>\n<p><strong>Professors: </strong>Help us and your students by telling them about GSoC and encouraging them to apply. Consider having them write a WordPress plugin or core patch as a class assignment so they can get to know the codebase. Offer to sign on as an adviser for a summer independent study so they can get credit for their work with GSoC.</p>\n<p><strong>Students:</strong> Check out <a href="http://codex.wordpress.org/GSoC2010">our Ideas page</a>, and start thinking about projects you&#8217;d like to propose. Watch this space for an announcement of some live chat information sessions where you can ask potential mentors questions and get feedback on your pre-proposal ideas. This program is competitive, but is one of the best opportunities out there when it comes to programming. You get real-world experience as a member of an open source community, you make decent money, you make connections with industry leaders, and you get the attention of Google. Not to mention some serious bragging rights. What are you waiting for? Applications will be accepted from March 29-April 9, so start thinking about a project now!</p>\n<p><em><br />\n</em></p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:71:"http://wordpress.org/development/2010/03/summer-of-wordpress-2010/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"0";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:9;a:6:{s:4:"data";s:44:"\n		\n		\n		\n		\n		\n				\n		\n\n		\n		\n			\n			\n		\n		";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:5:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:18:"OMG WordPress BBQ!";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:59:"http://wordpress.org/development/2010/03/omg-wordpress-bbq/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:68:"http://wordpress.org/development/2010/03/omg-wordpress-bbq/#comments";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 13 Mar 2010 21:48:48 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"category";a:2:{i:0;a:5:{s:4:"data";s:6:"Events";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}i:1;a:5:{s:4:"data";s:4:"sxsw";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1251";s:7:"attribs";a:1:{s:0:"";a:1:{s:11:"isPermaLink";s:5:"false";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:360:"This weekend, thousands of WordPress users and developers are among the people attending the South by Southwest (SxSW) Interactive conference in Austin, TX. To celebrate this, we&#8217;re throwing a WordPress BBQ at SxSW tomorrow so that there&#8217;s a place for us all to get together.\nIf you&#8217;re a WordPress fan attending SxSW (or you just happen [...]";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Jane Wells";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:40:"http://purl.org/rss/1.0/modules/content/";a:1:{s:7:"encoded";a:1:{i:0;a:5:{s:4:"data";s:2363:"<p><img align="right" title="OMG WordPress BBQ" src="http://jane.files.wordpress.com/2010/03/cake.png" alt="OMG WordPress BBQ logo" width="136" height="230" />This weekend, thousands of WordPress users and developers are among the people attending the South by Southwest (SxSW) Interactive conference in Austin, TX. To celebrate this, we&#8217;re throwing a WordPress BBQ at SxSW tomorrow so that there&#8217;s a place for us all to get together.</p>\n<p>If you&#8217;re a WordPress fan attending SxSW (or you just happen to be in Austin), please join us for lunch after 12pm* tomorrow, Sunday March 14. We&#8217;re getting the BBQ from Rudy&#8217;s and the red velvet cake from Central Market. Yum! Come, eat, talk about the cool things you&#8217;re doing with WordPress, let us know what we can do better, gossip about Mark Jaquith&#8217;s new hairstyle, whatever. Think of it like a WordCamp without presentations. I&#8217;ll be there, lead developers Mark Jaquith and Ryan Boren will be there, core contributors will be there, plugin and theme developers will be there, and basically all the most intelligent and attractive people from SxSW will be there. You should be, too!</p>\n<p><strong>Location: </strong>Conjunctured coworking space, 1309 East 7th St., Austin, TX 78702. From the convention center, walk up to 7th Street, hang a right, and walk until you get to #1309. If you&#8217;re tired of walking, taking a cab is a decent option. Note that this is on the other side of I-35 from the convention center.</p>\n<p><iframe width="300" height="300" frameborder="0" scrolling="no" marginheight="0" marginwidth="0" src="http://maps.google.com/maps/ms?ie=UTF8&amp;hl=en&amp;msa=0&amp;msid=106394153008544515148.000481b552f8ed920cfc5&amp;ll=30.265739,-97.733645&amp;spn=0.01112,0.012875&amp;z=15&amp;output=embed"></iframe><br /><small>View <a href="http://maps.google.com/maps/ms?ie=UTF8&amp;hl=en&amp;msa=0&amp;msid=106394153008544515148.000481b552f8ed920cfc5&amp;ll=30.265739,-97.733645&amp;spn=0.01112,0.012875&amp;z=15&amp;source=embed" style="color:#0000FF;text-align:left">WordPress BBQ at SxSW</a> in a larger map</small></p>\n<p><em>* We&#8217;ll keep serving until we run out of food, so probably until around 2 or 3? We&#8217;ll have a hundred pounds of bbq meat, a bunch of sides, and dozens of gallons of iced tea, so come hungry.<br />\n</em></p>\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:36:"http://wellformedweb.org/CommentAPI/";a:1:{s:10:"commentRss";a:1:{i:0;a:5:{s:4:"data";s:64:"http://wordpress.org/development/2010/03/omg-wordpress-bbq/feed/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:38:"http://purl.org/rss/1.0/modules/slash/";a:1:{s:8:"comments";a:1:{i:0;a:5:{s:4:"data";s:1:"0";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}}}s:27:"http://www.w3.org/2005/Atom";a:1:{s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:0:"";s:7:"attribs";a:1:{s:0:"";a:3:{s:4:"href";s:38:"http://wordpress.org/development/feed/";s:3:"rel";s:4:"self";s:4:"type";s:19:"application/rss+xml";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:44:"http://purl.org/rss/1.0/modules/syndication/";a:2:{s:12:"updatePeriod";a:1:{i:0;a:5:{s:4:"data";s:6:"hourly";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:15:"updateFrequency";a:1:{i:0;a:5:{s:4:"data";s:1:"1";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}}}}}}}}s:4:"type";i:128;s:7:"headers";a:9:{s:10:"x-pingback";s:43:"http://wordpress.org/development/xmlrpc.php";s:13:"last-modified";s:29:"Thu, 06 May 2010 21:05:35 GMT";s:4:"etag";s:34:""79e3f6e7daacceee5816f4bb6504c743"";s:4:"link";s:17:"<>; rel=shortlink";s:12:"content-type";s:23:"text/xml; charset=UTF-8";s:17:"transfer-encoding";s:7:"chunked";s:4:"date";s:29:"Mon, 17 May 2010 20:31:42 GMT";s:6:"server";s:9:"LiteSpeed";s:10:"connection";s:5:"close";}s:5:"build";s:14:"20090627192103";}', 'no');
