(1, 1, '2010-05-17 20:29:55', '2010-05-17 20:29:55', 'Welcome to <a href="http://hopeinloss.org/">Hopeinloss.org </a>. This is your first post. Edit or delete it, then start blogging!', 'Hello world!', '', 'publish', 'open', 'open', '', 'hello-world', '', '', '2010-05-17 20:29:55', '2010-05-17 20:29:55', '', 0, '', 0, 'post', '', 1),
(2, 1, '2010-05-17 20:29:55', '2010-05-17 20:29:55', 'This is an example of a WordPress page, you could edit this to put information about yourself or your site so readers know where you are coming from. You can create as many pages like this one or sub-pages as you like and manage all of your content inside of WordPress.', 'About', '', 'publish', 'open', 'open', '', 'about', '', '', '2010-05-17 20:29:55', '2010-05-17 20:29:55', '', 0, '', 0, 'page', '', 0);
