MCM_5244-139x210.jpg" class="attachment-thumbnail" alt="MCM_5244" title="MCM_5244" /></a>\n<a href="http://ma.tt/2010/05/wcsf-2010-photos/mcm_5249-2/" title="MCM_5249"><img width="139" height="210" src="http://s.ma.tt/files/2010/05/MCM_5249-139x210.jpg" class="attachment-thumbnail" alt="MCM_5249" title="MCM_5249" /></a>\n<a href="http://ma.tt/2010/05/wcsf-2010-photos/mcm_5251-3/" title="MCM_5251"><img width="195" height="129" src="http://s.ma.tt/files/2010/05/MCM_5251-195x129.jpg" class="attachment-thumbnail" alt="MCM_5251" title="MCM_5251" /></a>\n<a href="http://ma.tt/2010/05/wcsf-2010-photos/mcm_5258-3/" title="MCM_5258"><img width="139" height="210" src="http://s.ma.tt/files/2010/05/MCM_5258-139x210.jpg" class="attachment-thumbnail" alt="MCM_5258" title="MCM_5258" /></a>\n<a href="http://ma.tt/2010/05/wcsf-2010-photos/mcm_5285-2/" title="MCM_5285"><img width="195" height="129" src="http://s.ma.tt/files/2010/05/MCM_5285-195x129.jpg" class="attachment-thumbnail" alt="MCM_5285" title="MCM_5285" /></a>\n<a href="http://ma.tt/2010/05/wcsf-2010-photos/mcm_5303-3/" title="MCM_5303"><img width="195" height="129" src="http://s.ma.tt/files/2010/05/MCM_5303-195x129.jpg" class="attachment-thumbnail" alt="MCM_5303" title="MCM_5303" /></a>\n<a href="http://ma.tt/2010/05/wcsf-2010-photos/mcm_5387/" title="MCM_5387"><img width="139" height="210" src="http://s.ma.tt/files/2010/05/MCM_5387-139x210.jpg" class="attachment-thumbnail" alt="MCM_5387" title="MCM_5387" /></a>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 May 2010 23:31:23 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:21;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:20:"Matt: Chrome Checker";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34409";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:36:"http://ma.tt/2010/05/chrome-checker/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:422:"<p>I&#8217;ve been back on Chrome pretty much full-time, especially since I figured out some proxy stuff, so the new <a href="http://blog.afterthedeadline.com/2010/05/06/after-the-deadline-for-google-chrome/">After the Deadline checker for Google Chrome is a lifesaver</a>. See also: <a href="http://www.downloadsquad.com/2010/05/06/after-the-deadline-now-checks-your-grammar-spelling-on-google-c/">Download Squad</a>.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 May 2010 23:11:50 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:22;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:90:"Weblog Tools Collection: Adding Scripts Properly to WordPress Part 1 – wp_enqueue_script";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://weblogtoolscollection.com/?p=8016";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:115:"http://weblogtoolscollection.com/archives/2010/05/06/adding-scripts-properly-to-wordpress-part-1-wp_enqueue_script/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:11179:"<p>Starting in WordPress 2.1 (if I remember correctly), the awesome folks at <a href="http://www.automattic.com">Automattic</a> gave us the even awesomer function of <strong>wp_enqueue_script</strong>.</p>\n<p>Before that, it was every plugin or theme author for himself.  If you wanted to add in a script, it was hard-coded in.</p>\n<p>As you might imagine, this presented a ton of problems.  Scripts were loaded twice, out of order, or even when they weren’t needed at all.</p>\n<p>Furthermore, some themes and plugins had the JavaScript embedded within the plugin’s or theme’s PHP file just to capture a few PHP variables.  Not good!  In order to add scripts properly to JavaScript, you must always keep your PHP and JavaScript separate.  And by separate, I mean separate files.  There’s just no excuse anymore (I’ll get into this in Part 2 of this series).</p>\n<p>The <strong>wp_enqueue_script</strong> function is the first step in loading your scripts properly.  Not only can you add your script, but you can also specify the dependencies (e.g., jQuery), and the version number.</p>\n<p>This prevents duplicate JavaScript files from loading, which is always a good thing.</p>\n<h3>So How Does wp_enqueue_script Work?</h3>\n<p>Aside from <a href="http://codex.wordpress.org/Function_Reference/wp_enqueue_script">the excellent documentation</a> from WordPress, you’ll find my regurgitated version below (gross, I know).</p>\n<p>The function <strong>wp_enqueue_script</strong> takes in five arguments, with the last four being optional.</p>\n<blockquote><pre><code>\n<pre><span>&lt;?php</span><span> wp_enqueue_script</span><span>(</span><span>''handle''</span><span>,</span><span> </span><span>''src''</span><span>,</span><span> </span><span>''deps''</span><span>,</span><span> </span><span>''ver''</span><span>,</span><span> </span><span>''in_footer''</span><span>)</span><span>;</span><span> </span><span>?></span>\n</pre>\n<p></code></pre>\n</blockquote>\n<p>The <strong>handle</strong> argument is a string that names your script, or references someone else’s.</p>\n<p>For example, you can add the jQuery script to any page by calling:</p>\n<blockquote><pre><code>\n<pre><span>&lt;?php</span><span> wp_enqueue_script</span><span>(</span><span>''jquery''</span><span>)</span><span>;</span><span> </span><span>?></span>\n</pre>\n<p></code></pre>\n</blockquote>\n<p>Likewise, if you have previously registered your script (using <strong>wp_register_script</strong>), you can call your script by calling:</p>\n<blockquote><pre><code>\n<pre><span>&lt;?php</span><span> wp_enqueue_script</span><span>(</span><span>''my_script''</span><span>)</span><span>;</span><span> </span><span>?></span>\n</pre>\n<p></code></pre>\n</blockquote>\n<h4>Src</h4>\n<p>The src argument is asking for the URL of the file.  If you supply the src of the script, the <strong>wp_enqueue_script</strong> function automatically registers your script for others to use (no need to use <strong>wp_register_script</strong>).</p>\n<p>An example of it in use is: </p>\n<blockquote><pre><code>\n<pre><span>&lt;?php</span><span> wp_enqueue_script</span><span>(</span><span>''my_script''</span><span>,</span><span> WP_CONTENT_URL </span><span>.</span><span> </span><span>''plugins/my_plugin/my_script.js''</span><span>)</span><span>;</span><span> </span><span>?></span>\n</pre>\n<p></code></pre>\n</blockquote>\n<p>Themers would use:</p>\n<blockquote><pre><code>\n<pre><span>&lt;?php</span><span> wp_enqueue_script</span><span>(</span><span>''my_script''</span><span>,</span><span> WP_CONTENT_URL </span><span>.</span><span> </span><span>''themes/my_theme/my_script.js''</span><span>)</span><span>;</span><span> </span><span>?></span>\n</pre>\n<p></code></pre>\n</blockquote>\n<h4>Deps</h4>\n<p>The <strong>deps</strong> argument is an array of dependencies.  For example, if your script requires jQuery or other JavaScript files, it’ll load these files before your plugin’s JavaScript file.</p>\n<p>Here’s an example:</p>\n<blockquote><pre><code>\n<pre><span>&lt;?php</span><span></span>\n<span>wp_enqueue_script</span><span>(</span><span>''my_script''</span><span>,</span><span> WP_CONTENT_URL </span><span>.</span><span> </span><span>''plugins/my_plugin/my_script.js''</span><span>,</span><span> </span><span>array</span><span>(</span><span>''jquery''</span><span>,</span><span> </span><span>''another_script''</span><span>)</span><span>)</span><span>;</span><span></span>\n<span>?></span>\n</pre>\n<p></code></pre>\n</blockquote>\n<p>See that array up there (it’s pretty, I know)?  That’s what’s calling your dependencies. </p>\n<p>jQuery is built into WordPress by default, so calling it via dependency is no problem as long as you queue it via <strong>wp_enqueue_script</strong>.  </p>\n<p>The <strong>another_script</strong> dependency assumes you have already used <strong>wp_enqueue_script</strong> to assign it a handle and a src.</p>\n<p>The outcome in this scenario is that <strong>jQuery</strong> and <strong>another_script</strong> will load before <strong>my_script</strong>.</p>\n<h4>Ver</h4>\n<p>The <strong>ver</strong> argument is simply the version of the JavaScript file for caching purposes.  If you are supplying your own script, it’s a good idea to supply a version.</p>\n<p>The version is string based and looks like this:</p>\n<blockquote><pre><code>\n<pre><span>&lt;?php</span><span></span>\n<span>wp_enqueue_script</span><span>(</span><span>''my_script''</span><span>,</span><span> WP_CONTENT_URL </span><span>.</span><span> </span><span>''plugins/my_plugin/my_script.js''</span><span>,</span><span> </span><span>array</span><span>(</span><span>''jquery''</span><span>,</span><span> </span><span>''another_script''</span><span>)</span><span>,</span><span> </span><span>''1.0.0''</span><span>)</span><span>;</span><span></span>\n<span>?></span>\n</pre>\n<p></code></pre>\n</blockquote>\n<p>As you update your JavaScript file, update the <strong>ver</strong> argument.  If you don’t, you’ll inevitably run into caching issues with WordPress.</p>\n<h4>In_footer</h4>\n<p>The <strong>in_footer</strong> argument (since WP 2.8) determines if the script will load in the header or footer (header is the default).</p>\n<p>To load your script in the footer, simply pass it a <strong>1</strong> (or <strong>true</strong>).</p>\n<blockquote><pre><code>\n<pre><span>&lt;?php</span><span></span>\n<span>wp_enqueue_script</span><span>(</span><span>''my_script''</span><span>,</span><span> WP_CONTENT_URL </span><span>.</span><span> </span><span>''plugins/my_plugin/my_script.js''</span><span>,</span><span> </span><span>array</span><span>(</span><span>''jquery''</span><span>,</span><span> </span><span>''another_script''</span><span>)</span><span>,</span><span> </span><span>''1.0.0''</span><span>,</span><span> </span><span>true</span><span>)</span><span>;</span><span></span>\n<span>?></span>\n</pre>\n<p></code></pre>\n</blockquote>\n<p>Great care should be used when setting the scripts to load in the footer as some themes do not have this functionality built in (the theme must make use of the <strong>wp_footer</strong> function call).</p>\n<h3>Naming Your Handler</h3>\n<p>One last thing (err, warning?) to take note of is naming your handler for <strong>wp_enqueue_script</strong>.  If you are using a third-party script (say, Colorbox), use common sense in naming the handler.  There’s no reason to name it “lightbox” or “mybox”.  The handler name should be obvious, right? </p>\n<p>The same goes for the built-in scripts with WordPress.  </p>\n<p>For example, the handler &#8216;jquery&#8217; is built-in.  Do you want to supply your own version of jQuery?  </p>\n<p>How about ruin everybody&#8217;s day and give it a handler of &#8216;jquery.js&#8217;?  The result will inevitably be two jQuery instances loading on the same page and causing mayhem with other scripts.</p>\n<p>Instead, use the function <strong>wp_deregister_script</strong> to remove the WordPress reference and supply your own.</p>\n<blockquote><pre><code>\n<pre><span>&lt;?php</span><span></span>\n<span>wp_deregister_script</span><span>(</span><span>array</span><span>(</span><span>''jquery''</span><span>)</span><span>)</span><span>;</span><span></span>\n<span>wp_enqueue_script</span><span>(</span><span>''jquery''</span><span>,</span><span> </span><span>''your-jquery-path.js''</span><span>)</span><span>;</span><span></span>\n<span>?></span>\n</pre>\n<p></code></pre>\n</blockquote>\n<p>With this technique, however, you should have a pretty darn good reason for not including the default scripts.  After all, you&#8217;ll essentially be running a piece of software that may not be fully tested and/or compatible with WordPress.  </p>\n<h3>Great, I have wp_enqueue_script down.  Now what?<br />\n</h3>\n<p>You have to call <strong>wp_enqueue_script</strong> from the appropriate hook in WordPress.</p>\n<p>Fortunately, WordPress has two such action hooks you can tap into: <strong>admin_print_scripts</strong> and <strong>wp_print_scripts</strong>.</p>\n<p>The <strong>admin_print_scripts</strong> hook allows you to add scripts in the admin panel, while the <strong>wp_print_scripts</strong> hook allows you to add scripts everywhere else.</p>\n<p>Adding your <strong>wp_enqueue_script</strong> code is as simple as adding an action inside your plugin or theme code.</p>\n<p>An example of the code being used inside of a class constructor is:</p>\n<blockquote><pre><code>\n<pre><span>&lt;?php</span><span></span>\n<span>add_action</span><span>(</span><span>''admin_print_scripts''</span><span>,</span><span> </span><span>array</span><span>(</span><span>&amp;</span><span>$</span><span>this</span><span>,</span><span> </span><span>''add_admin_scripts''</span><span>)</span><span>)</span><span>;</span><span></span>\n<span>?></span>\n</pre>\n<p></code></pre>\n</blockquote>\n<p>And for those not using a class (classes help avoid conflicts with other plugins):</p>\n<blockquote><pre><code>\n<pre><span>&lt;?php</span><span></span>\n<span>add_action</span><span>(</span><span>''admin_print_scripts''</span><span>,</span><span> </span><span>''add_admin_scripts''</span><span>)</span><span>;</span><span></span>\n<span>?></span>\n</pre>\n<p></code></pre>\n</blockquote>\n<p>For the above example, we have a callback method of <strong>add_admin_scripts</strong>.  An example of it in use is:</p>\n<blockquote><pre><code>\n<pre><span>&lt;?php</span><span></span>\n<span>function</span><span> add_admin_scripts</span><span>(</span><span>)</span><span> </span><span>{</span><span></span>\n<span>&#xa0;&#xa0;&#xa0;&#xa0;wp_enqueue_script</span><span>(</span><span>''jquery''</span><span>)</span><span>;</span><span></span>\n<span>}</span><span></span>\n<span>?></span>\n</pre>\n<p></code></pre>\n</blockquote>\n<h3>Conclusion</h3>\n<p>Here are the steps you should follow in order to add scripts to a WordPress theme or plugin:</p>\n<ul>\n<li>Add the appropriate action to your WordPress theme or plugin (themers will want to use <strong>functions.php</strong>).</li>\n<li>Determine your script dependencies.</li>\n<li>Code your <strong>wp_enqueue_script</strong> calls appropriately.</li>\n</ul>\n<p><em>This article is an excerpt from <a href="http://www.ronalfy.com/about/">Ronald Huereca&#8217;s</a> e-book entitled WordPress and Ajax (used with permission).</em></p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 May 2010 23:04:12 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:14:"Ronald Huereca";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:23;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:31:"Dev Blog: WordPress 3.0, Beta 2";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1340";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:62:"http://wordpress.org/development/2010/05/wordpress-3-0-beta-2/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:982:"<p>Following the successful post-WordCamp San Francisco code sprint, we are now ready to release the second beta of WordPress 3.0.<br />\nThings to test:</p>\n<ul>\n<li>Revised menu user interface</li>\n<li>Changes to the WordPress exporter and importer to make it more flexible</li>\n</ul>\n<p>Already have a test install that you want to switch over to the beta? Try the <a href="http://westi.wordpress.com/2009/06/22/making-it-easy-to-be-a-wordpress-tester/">beta tester plugin</a>.</p>\n<p>Testers, don&#8217;t forget to use the <a href="http://lists.automattic.com/mailman/listinfo/wp-testers">wp-testers mailing list</a> to discuss bugs you encounter.</p>\n<p>We hope you like it! And if you don&#8217;t, well, check back when the release candidate is ready. <img src="http://wordpress.org/development/wp-includes/images/smilies/icon_smile.gif" alt=":)" class="wp-smiley" /> </p>\n<p>Download the <a href="http://wordpress.org/wordpress-3.0-beta2.zip">WordPress 3.0 Beta 2</a> now!</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 06 May 2010 21:05:35 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:14:"Peter Westwood";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:24;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:66:"Publisher Blog: PGA Tour Live Report Launches on WordPress.com VIP";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:42:"http://publisherblog.automattic.com/?p=926";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:86:"http://publisherblog.automattic.com/2010/05/05/pga-tour-live-report-wordpress-com-vip/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1930:"<p>The PGA Tour just launched their latest site, <a href="http://livereport.pgatour.com/">Live Report</a>.  With beautiful photos, videos, and a running stream of updates, this is a great site for golf lovers to check-out.  This site is also hosted in the <a href="http://wordpress.com/vip">WordPress.com VIP program</a>:<br />\n<a href="http://livereport.pgatour.com"><img src="http://wordpresspublishers.files.wordpress.com/2010/05/pga-tour-live-report.png?w=600&#038;h=603" alt="" title="pga-tour-live-report" width="600" height="603" class="alignnone size-full wp-image-929" /></a></p>\n<p>[ Visit<a href="http://livereport.pgatour.com/"> PGA Tour Live Report</a> ]</p>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wordpresspublishers.wordpress.com/926/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wordpresspublishers.wordpress.com/926/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wordpresspublishers.wordpress.com/926/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wordpresspublishers.wordpress.com/926/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wordpresspublishers.wordpress.com/926/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wordpresspublishers.wordpress.com/926/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wordpresspublishers.wordpress.com/926/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wordpresspublishers.wordpress.com/926/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wordpresspublishers.wordpress.com/926/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wordpresspublishers.wordpress.com/926/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=publisherblog.automattic.com&blog=1470857&post=926&subd=wordpresspublishers&ref=&feed=1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 05 May 2010 18:25:25 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:16:"Raanan Bar-Cohen";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:25;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:23:"Gravatar: Faces of CPAN";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://blog.gravatar.com/?p=190";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:50:"http://blog.gravatar.com/2010/05/05/faces-of-cpan/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1800:"<p><a href="http://www.cpan.org/">CPAN</a> was a pretty early adopter (outside of blogs) of Gravatar, and have been using them for quite a while to put a face to the name of the people who are developing the core modules of the Perl programming language. I just happened to come across this awesome page that I had to share, called <a href="http://hexten.net/cpan-faces/">The Faces of CPAN</a>. It shows a page containing all of the Gravatars of members who have one. Very cool.</p>\n<p>I&#8217;d love to see websites do something like this, showing their &#8220;community&#8221; of commenters via their Gravatars. Maybe I&#8217;ll write a quick plugin to do that&#8230;</p>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/gravatar.wordpress.com/190/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/gravatar.wordpress.com/190/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/gravatar.wordpress.com/190/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/gravatar.wordpress.com/190/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/gravatar.wordpress.com/190/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/gravatar.wordpress.com/190/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/gravatar.wordpress.com/190/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/gravatar.wordpress.com/190/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/gravatar.wordpress.com/190/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/gravatar.wordpress.com/190/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=blog.gravatar.com&blog=1886259&post=190&subd=gravatar&ref=&feed=1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 05 May 2010 05:07:36 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:11:"Beau Lebens";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:26;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:39:"WordPress.tv: Ian Huet: Multimedia Mojo";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://wordpress.tv/?p=3758";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:57:"http://wordpress.tv/2010/03/07/huet-multimedia-ireland10/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1356:"<div id="x-video-11" class="video-player">\n\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/3758/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/3758/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wptv.wordpress.com/3758/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wptv.wordpress.com/3758/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wptv.wordpress.com/3758/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wptv.wordpress.com/3758/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wptv.wordpress.com/3758/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wptv.wordpress.com/3758/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wptv.wordpress.com/3758/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wptv.wordpress.com/3758/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=3758&subd=wptv&ref=&feed=1" /><div><a href="http://wordpress.tv/2010/03/07/huet-multimedia-ireland10/"><img alt="MultiMedia Mojo" src="http://cdn.videos.wordpress.com/ho0YeUvU/multimedia-mojo_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 04 May 2010 22:30:09 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:11:"Ryan Markel";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:27;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:54:"WordPress Podcast: Creating Communities with WordPress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:63:"http://www2.webmasterradio.fm/wordpress-community-podcast/?p=42";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:63:"http://feedproxy.google.com/~r/wordpresspodcast/~3/Rolf3_9S58o/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1224:"<p>Creating Communities with WordPress</p>\n<p><a href="http://www.lockergnome.com/">Chris Pirillo</a> has  been a voice, early adopter and harbinger on the web for over a decade. He  joins us on this week show to discuss the evolution that his career has taken  as open source tools like WordPress also evolved since WordPress MU v1.0. We explored how to build community, manage communities and what specifically is  the secret to making unique sites/communities on the web.</p>\n<p>News included:</p>\n<ul>\n<li><a href="http://central.wordcamp.org/schedule/">Upcoming  WordCamps</a></li>\n<li><a href="http://www.theregister.co.uk/2010/04/12/network_solutions_wordpress_hack/">Network  Solutions &amp; WordPress</a></li>\n<li><a href="http://googlenewsblog.blogspot.com/2010/04/bringing-living-stories-to-wordpress.html">Google  Living Stories</a></li>\n</ul>\n<p>Plugin Picks of the Week:</p>\n<ul>\n<li><a href="http://wordpress.org/extend/plugins/gn-xml-sitemap/">Google XML News  Sitemap</a></li>\n<li><a href="http://wordpress.org/extend/plugins/salesforce-wordpress-to-lead/">WordPress-to-lead  for Salesforce CRM</a></li>\n</ul>\n<img src="http://feeds.feedburner.com/~r/wordpresspodcast/~4/Rolf3_9S58o" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 04 May 2010 21:59:24 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:54:"joost@pressthis.com (Joost de Valk & Frederick Townes)";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:28;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:24:"Matt: Groupcard Acquired";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34341";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:40:"http://ma.tt/2010/05/groupcard-acquired/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:693:"<p>One of my first angel investments, <a href="http://www.groupcard.com/">GroupCard</a>, has been acquired by InComm as announced <a href="http://groupcard.wordpress.com/2010/04/29/groupcard-has-been-acquired-by-incomm/">on their blog</a>, <a href="http://deals.venturebeat.com/2010/04/29/groupcard-incomm/">VentureBeat</a>, and <a href="http://techcrunch.com/2010/04/29/gift-card-giant-incomm-acquires-fbfund-startup-groupcard/">TechCrunch</a>. It&#8217;s been a pleasure watching their team and business grow and I look forward to seeing what they come up with in the future. Hat tip to<a href="http://www.mattbartus.com/"> my consigliere, Matt Bartus</a>, for the original introduction.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 04 May 2010 15:54:50 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:29;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:49:"Dougal Campbell: Geolocation Plugin for WordPress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:33:"http://dougal.gunters.org/?p=2116";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:129:"http://dougal.gunters.org/blog/2010/05/04/geolocation-plugin-for-wordpress?utm_source=rss&amp;utm_medium=rss&amp;utm_campaign=rss";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1648:"<p>This <a href="http://iphone.wordpress.org/2010/05/03/geolocation-plugin-wordpress/">Geolocation Plugin</a> will be a nice addition for people who do travel blogging or who write about things in a particular area (restaurant and business reviews, hyperlocal news, etc).</p>\n<blockquote cite="http://iphone.wordpress.org/2010/05/03/geolocation-plugin-wordpress/"><p>The plugin adds a subtle but powerful addition to posts you’ve geotagged using WordPress for iPhone:  a link appears inside your post with a short description of the location where the post was tagged.  When your users hover over the link, an interactive map appears allowing them to view the location as a pin on the map.</p></blockquote>\n<p>You know, you could probably even combine this with the <a href="http://dougal.gunters.org/blog/2009/08/10/wordpress-webhooks-plugin">HookPress plugin</a>, and have it automatically check you in on <a href="http://foursquare.com/">Foursquare</a>, <a href="http://gowalla.com/">Gowalla</a> or <a href="http://www.yelp.com/">Yelp</a> when you publish a geotagged post.</p>\n\n\n<p>Related posts:<ol><li><a href="http://dougal.gunters.org/blog/2009/08/10/wordpress-webhooks-plugin" rel="bookmark" title="Permanent Link: WordPress Webhooks Plugin">WordPress Webhooks Plugin</a></li>\n<li><a href="http://dougal.gunters.org/blog/2009/07/14/analytics360-plugin-for-wordpress" rel="bookmark" title="Permanent Link: Analytics360 Plugin for WordPress">Analytics360 Plugin for WordPress</a></li>\n<li><a href="http://dougal.gunters.org/blog/2010/01/13/plugin-pages" rel="bookmark" title="Permanent Link: Plugin Pages">Plugin Pages</a></li>\n</ol></p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 04 May 2010 13:34:43 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Dougal";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:30;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:50:"WordPress.tv: Daryl Koopersmith: Rethinking Themes";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://wordpress.tv/?p=3749";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:67:"http://wordpress.tv/2010/03/06/daryl-koopersmith-rethinking-themes/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1407:"<div id="x-video-12" class="video-player">\n\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/3749/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/3749/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wptv.wordpress.com/3749/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wptv.wordpress.com/3749/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wptv.wordpress.com/3749/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wptv.wordpress.com/3749/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wptv.wordpress.com/3749/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wptv.wordpress.com/3749/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wptv.wordpress.com/3749/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wptv.wordpress.com/3749/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=3749&subd=wptv&ref=&feed=1" /><div><a href="http://wordpress.tv/2010/03/06/daryl-koopersmith-rethinking-themes/"><img alt="Daryl Koopersmith: Rethinking Themes" src="http://cdn.videos.wordpress.com/B80ovfMF/daryl-koopersmith-rethinking-themes_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 03 May 2010 23:31:00 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:11:"Ryan Markel";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:31;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:62:"WP Blackberry: Now Available: Geolocation Plugin for WordPress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:38:"http://blackberry.wordpress.org/?p=245";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:62:"http://blackberry.wordpress.org/2010/05/03/geolocation-plugin/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2836:"<p>Recently, we introduced a geotagging feature in WordPress for BlackBerry that allows our users to geotag posts.  While the response we received was positive, many of our users requested a plugin that would allow them to display the geotagged data on their self-hosted WordPress sites.</p>\n<p>We’re very happy to announce that the Geolocation plugin is now available for self-hosted WordPress sites, and can be downloaded at the WordPress.org plugin directory or through your WordPress dashboard:  <a href="http://wordpress.org/extend/plugins/geolocation/">http://wordpress.org/extend/plugins/geolocation</a></p>\n<p><a href="http://wpblackberry.files.wordpress.com/2010/05/screenshot.png"><img class="size-medium wp-image-246 alignleft" title="geolocation plugin screenshot" src="http://wpblackberry.files.wordpress.com/2010/05/screenshot.png?w=250" alt="" width="250" /></a></p>\n<p>The plugin adds a subtle but powerful addition to posts you’ve geotagged using WordPress for BlackBerry:  a link appears inside your post with a short description of the location where the post was tagged.  When your users hover over the link, an interactive map appears allowing them to view the location as a pin on the map.</p>\n<p>And if you’ve got a post that you forgot to geotag using WordPress for BlackBerry, we’ve got you covered there as well.  Just open up the Edit Post page, and you’ll be able to easily add geo information using the Geolocation panel.  All you’ve got to do is put in an address and hit Load.</p>\n<p>We think this new plugin serves as a nice companion to all WordPress Mobile apps.  Check it out and let us know what you think!</p>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wpblackberry.wordpress.com/245/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wpblackberry.wordpress.com/245/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wpblackberry.wordpress.com/245/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wpblackberry.wordpress.com/245/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wpblackberry.wordpress.com/245/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wpblackberry.wordpress.com/245/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wpblackberry.wordpress.com/245/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wpblackberry.wordpress.com/245/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wpblackberry.wordpress.com/245/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wpblackberry.wordpress.com/245/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=blackberry.wordpress.org&blog=8247031&post=245&subd=wpblackberry&ref=&feed=1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 03 May 2010 22:22:15 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Danilo";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:32;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:58:"WP iPhone: Now Available: Geolocation Plugin for WordPress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:34:"http://iphone.wordpress.org/?p=701";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:68:"http://iphone.wordpress.org/2010/05/03/geolocation-plugin-wordpress/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3078:"<p><a rel="attachment wp-att-702" href="http://iphone.wordpress.org/2010/05/03/geolocation-plugin-wordpress/screenshot/"><img class="alignleft size-thumbnail wp-image-702" title="Geolocation Plugin Screenshot" src="http://wpiphone.files.wordpress.com/2010/05/screenshot.png?w=152&#038;h=124" alt="Geolocation Plugin Screenshot" width="152" height="124" /></a>Recently, we introduced a geotagging feature in WordPress for iPhone that allows our users to geotag posts with the push of a button.  While the response we received was overwhelmingly positive, many of our users requested a plugin that would allow them to display the geotagged data on their self-hosted WordPress sites.</p>\n<p>Well friends, that day has come!  We&#8217;re very happy to announce that the Geolocation plugin is now available for self-hosted WordPress sites, and can be downloaded at the WordPress.org plugin directory or through your WordPress dashboard:  <a title="http://wordpress.org/extend/plugins/geolocation/" href="http://wordpress.org/extend/plugins/geolocation/">http://wordpress.org/extend/plugins/geolocation/</a></p>\n<p>The plugin adds a subtle but powerful addition to posts you&#8217;ve geotagged using WordPress for iPhone:  a link appears inside your post with a short description of the location where the post was tagged.  When your users hover over the link, an interactive map appears allowing them to view the location as a pin on the map.</p>\n<p>And if you&#8217;ve got a post that you forgot to geotag using WordPress for iPhone, we&#8217;ve got you covered there as well.  Just open up the Edit Post page, and you&#8217;ll be able to easily add geo information using the Geolocation panel.  All you&#8217;ve got to do is put in an address and hit Load.</p>\n<p>We think this new plugin serves as a nice companion to WordPress for iPhone as well as the other geo-enabled mobile app projects.  Check it out and let us know what you think!</p>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wpiphone.wordpress.com/701/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wpiphone.wordpress.com/701/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wpiphone.wordpress.com/701/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wpiphone.wordpress.com/701/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wpiphone.wordpress.com/701/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wpiphone.wordpress.com/701/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wpiphone.wordpress.com/701/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wpiphone.wordpress.com/701/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wpiphone.wordpress.com/701/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wpiphone.wordpress.com/701/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=iphone.wordpress.org&blog=3882653&post=701&subd=wpiphone&ref=&feed=1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 03 May 2010 20:45:59 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Chris Boyd";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:33;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:17:"Matt: Twitter API";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34337";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:33:"http://ma.tt/2010/05/twitter-api/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2567:"<p>I think the opportunity has passed for the <a href="http://apiwiki.twitter.com/">Twitter API</a> to become a lingua franca for the real-time web. <a href="http://en.blog.wordpress.com/2009/12/12/twitter-api/">WordPress.com</a>, <a href="http://staff.tumblr.com/post/287703110/api">Tumblr</a>, <a href="http://developer.typepad.com/typepad-twitter-api/twitter-api.html">Typepad</a>, SocialCast, and <a href="http://status.net/wiki/Twitter-compatible_API">Status.net</a> all added support for the API in a way to make it as easy as possible for Twitter client developers &#8212; all they had to do was change the endpoint. The clients would then become a hub for users across different services, and had the ability to flourish regardless of the direction of the service they originally built on.</p>\n<p>However because of perceived lack of market or a rush trying to keep up with each other and new features in Twitter&#8217;s API, like geo-location, we&#8217;re now close to half a year later and support for alternative endpoints in the major clients is haphazard at best. One of examples we all used to point to, <a href="http://www.atebits.com/">Tweetie</a>, is now <a href="http://blog.twitter.com/2010/04/twitter-for-iphone.html">owned by Twitter Inc.</a> and doesn&#8217;t have much motivation to support other services in the future. Neither do the <a href="http://blog.twitter.com/2010/04/twitter-for-android-robots-like-to.html">other official clients</a> they&#8217;re rolling out. (<a href="http://twitter.com/downloads">Twitter.com/downloads is now a 404 page</a>.)</p>\n<p>For the record I completely support Twitter creating or buying official clients for every platform, including desktops. It&#8217;s what I would do in their position. However the third-party client developers that contributed immeasurably to Twitter&#8217;s success thus far are now in the awkward position of no longer being useful to their parent. It makes no sense for Twitter to have its user or signup experience mediated by a third party. None of the third-party clients have innovated enough in the user experience (for the most part they do not look or work significantly different from when they launched) or in cross-service support and flow.</p>\n<p>If any of the clients had added seamless third-party API support when the opportunity first arose we&#8217;d all be pointing to them and promoting them. Now we&#8217;re more in a situation where, like Twitter, it makes more sense to build and promote our own because our users are demanding a multi-modal experience.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 03 May 2010 17:04:44 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:34;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:63:"Peter Westwood: Themes and WordPress 3.0 some important changes";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:33:"http://westi.wordpress.com/?p=161";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:86:"http://westi.wordpress.com/2010/05/03/themes-and-wordpress-3-0-some-important-changes/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:4672:"<p>During the development of WordPress 3.0 we have made a number of changes under the hood which will be of interest to the developers and users of themes.  Some of these changes are about making themes easier to develop and some of them are about making it easier to support the override of parts of themes.</p>\n<h3>1) get_template_part &#8211; <a href="http://core.trac.wordpress.org/changeset/13146">[13146]</a>, <a href="http://core.trac.wordpress.org/ticket/12371">#12371</a></h3>\n<p>The first change which should make it easier for extensible flexible theme development is the introduction of <code>get_template_part()</code> which has been introduced as a generic way of modularising themes a step beyond the basic footer/body/header files.  This new function makes it very easy for a theme to reuse blocks of code implementing theme areas such as the WordPress loop in a way which makes it easy for a child theme to override the implementation in a context sensitive way.</p>\n<p>This function is really easy to use &#8211; You create a file within your theme containing the code you want to re-use and then you pull it in as follows:</p>\n<pre class="brush: php;">get_template_part( ''loop'', ''author'' ); // Pull in the loop for the author archives</pre>\n<p>This will look for the files <code>loop-author.php</code> and <code>loop.php</code> searching first in the current themes folder before looking in the parent themes folder (if one if defined).  The new TwentyTen theme in WordPress 3.0 uses this for every call to it&#8217;s <code>loop.php</code> to make it easy to override in a single instance from a child theme.</p>\n<h3>2) Deprecating overly minimal themes <a href="http://core.trac.wordpress.org/changeset/14365">[14365]</a>, <a href="http://core.trac.wordpress.org/ticket/12425">#12425</a></h3>\n<p>The next change is to deprecate the support for overly minimal themes.  Prior to WordPress 3.0 any theme which was using the <strong>relevant template tag</strong> but missing any of the following template files &#8211; <code>header.php</code>, <code>footer.php</code>, <code>sidebar.php</code>, <code>comments.php</code>, <code>comments-popup.php</code> &#8211; would effectively behave as if it has a parent theme defined as &#8216;default&#8217; using the relevant files from the old default theme.</p>\n<p>Now that we are moving to a new default theme we didn&#8217;t want to have to support this very old behaviour indefinitely or make it such that the files from the TwentyTen theme were used as they have a different visual layout and would like change peoples existing sites.</p>\n<p>Going forward a WordPress theme using the <strong>relevant template tags</strong> is expected to contain all these files itself, or have them provided by a parent theme, and the theme compatibility files included in WordPress 3.0 will be removed in a future version.</p>\n<p>If you are using a theme which is affected by this change then you just need to make sure that you have the <a href="http://wordpress.org/extend/themes/default">default theme</a> installed &#8211; it will not be in new installs but will be preserved on upgrades. Then add the following to the comment at the top of the <code>style.css</code> of your theme to make it such that the default theme is used as its parent theme:</p>\n<pre class="brush: css;">Template: default</pre>\n<p>More information on the process of indicating a parent theme in a child themes <code>style.css</code> is available in the <a href="http://codex.wordpress.org/Theme_Development#Child_Themes_style.css">codex</a>.</p>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/westi.wordpress.com/161/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/westi.wordpress.com/161/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/westi.wordpress.com/161/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/westi.wordpress.com/161/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/westi.wordpress.com/161/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/westi.wordpress.com/161/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/westi.wordpress.com/161/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/westi.wordpress.com/161/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/westi.wordpress.com/161/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/westi.wordpress.com/161/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=westi.wordpress.com&blog=15396&post=161&subd=westi&ref=&feed=1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 03 May 2010 10:55:56 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:14:"Peter Westwood";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:35;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:59:"Weblog Tools Collection: WordPress Theme Releases for 05/01";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://weblogtoolscollection.com/?p=8011";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:89:"http://weblogtoolscollection.com/archives/2010/05/01/wordpress-theme-releases-for-0501-2/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2109:"<h4><a href="http://buynowshop.com/themes/desk-mess-mirrored/">Desk Mess Mirrored</a></h4>\n<p><img title="Desk Mess Mirrored" src="http://weblogtoolscollection.com/wp-content/uploads/2010/05/DeskMessMirrored.png" alt="Desk Mess Mirrored" width="200" height="138" /></p>\n<p>Marble desktop covered with a mix of old and new items, such as some vintage papers, a stainless steel pen, and, a hot cup of coffee! Now with threaded comments and sticky posts!</p>\n<h4><a href="http://wordpress.org/extend/themes/ground-floor">Ground Floor</a></h4>\n<p><img title="Ground Floor" src="http://weblogtoolscollection.com/wp-content/uploads/2010/05/GroundFloor.png" alt="Ground Floor" width="200" height="150" /></p>\n<p>Richly toned wood floor background with bare-earth colored widgetized sidebar and footer (six widget areas in total, as shown on the included widget-map.png). A strong theme to begin with; grow into; and, build on.</p>\n<h4><a href="http://fnexttheme.com/?p=1">FNext Business &amp; Finance Theme </a></h4>\n<p><img title="FNext Theme" src="http://weblogtoolscollection.com/wp-content/uploads/2010/05/FNextTheme.gif" alt="FNext Theme" width="200" height="117" /></p>\n<p>Stylish wordpress theme with three columns, widget-support, twitter support</p>\n<h4><a href="http://tntbase.com/wordpress-themes/straight-blue/">Straight Blue</a></h4>\n<p><a href="http://tntbase.com/tntbasedemosite/?themedemo=Straight_Blue"><img title="Straight Blue" src="http://weblogtoolscollection.com/wp-content/uploads/2010/05/StraightBlue.png" alt="Straight Blue" width="200" height="150" /></a></p>\n<p>Clean Blue and white theme with pale shades of brown. Great for adsense ads and other easy customizations.</p>\n<h4><a href="http://www.wpthemesplanet.com/free-wp-themes/director-wordpress-theme/">Director</a></h4>\n<p><a href="http://www.wpthemesplanet.com/?themedemo=director"><img title="Director" src="http://weblogtoolscollection.com/wp-content/uploads/2010/05/Director.png" alt="Director" width="200" height="152" /></a></p>\n<p>Director includes threaded-comments, sticky-post, theme-options and a unique amazing design</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 01 May 2010 19:00:30 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:7:"Perurry";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:36;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:57:"Lloyd: Great Lineup for WordCamp SF Genius Bar Help Desk!";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:30:"http://foolswisdom.com/?p=2505";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:73:"http://foolswisdom.com/great-lineup-for-wordcamp-sf-genius-bar-help-desk/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1013:"<p>I just posted the <a href="http://2010.sf.wordcamp.org/2010/04/30/genius-bar-help-desk/">WordCamp SF 2010 Genius Bar Help Desk schedule</a>.</p>\n<p>Like previous years, I&#8217;m really excited about these amazing people so generously sharing their WordPress expertise one on one!</p>\n<p>The WordCamp Genius Bar came about when myself and other WordPress participants felt regret for not being able to answer all of the excellent questions people were stopping us in the hall with at the first WordCamp (2006, <em>has it really been 5 years</em>). For WordCamp SF 2007, WordCamp Genius Bar was born, and has continued every year since with the help of <a href="http://mayadesai.wordpress.com/">Maya</a>, <a href="http://in-essence.org/">Elea</a> and numerous genius volunteers. It has become an ingredient in the WordCamp formula, <em>the most potent batches anyway</em>.</p>\n<p><a href="http://2010.sf.wordcamp.org/"><img src="http://2010.sf.wordcamp.org/wp-content/themes/wcsf2010/images/logo.png" /></a></p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 01 May 2010 02:00:25 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:5:"Lloyd";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:37;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:67:"Weblog Tools Collection: Google Living Stories Plugin for WordPress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://weblogtoolscollection.com/?p=8004";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:96:"http://weblogtoolscollection.com/archives/2010/04/30/google-living-stories-plugin-for-wordpress/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:788:"<p><a href="http://googlenewsblog.blogspot.com/2010/04/bringing-living-stories-to-wordpress.html">Google News Blog: Bringing Living Stories to WordPress</a>: Google is releasing their Living Stories experimental format as a <a href="http://code.google.com/p/living-stories/wiki/WordpressInstallation">plugin and a theme for WordPress</a>.  Living Stories is an experimental news format from Google. In the form of a plugin, each Living Story would be a WordPress category with the plugin allowing a blogger to add the stories themselves. An example would be nice to see but none is to be found yet. Thanks to a <a href="http://www.readwriteweb.com/archives/google_brings_living_stories_to_wordpress.php">writeup on ReadWriteWeb </a>I would love to see an example blog or screenshots.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 30 Apr 2010 16:22:49 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Mark Ghosh";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:38;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:44:"Dougal Campbell: FancyBox Gallery demo fixed";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:33:"http://dougal.gunters.org/?p=2105";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:124:"http://dougal.gunters.org/blog/2010/04/29/fancybox-gallery-demo-fixed?utm_source=rss&amp;utm_medium=rss&amp;utm_campaign=rss";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2000:"<div><img width="150" height="150" src="http://media.dougal.us.s3.amazonaws.com/wordpress/wp-content/uploads/2008/11/wplogo-notext-rgb.png" class="attachment-post-thumbnail wp-post-image" alt="WordPress" title="WordPress" /></div><p>Yesterday, I discovered that the demo at the bottom of my <a title="FancyBox Gallery plugin for WordPress" href="http://dougal.gunters.org/plugins/fancybox-gallery">FancyBox Gallery plugin</a> page was broken. After a little research, I discovered that a third-party javascript was the culprit. I&#8217;ve disabled that script for now, and alerted the service provider to the problem.</p>\n<p>So, my apologies if you came to the page and got the impression that the plugin didn&#8217;t work well.</p>\n<p>In a related note, I&#8217;ve been working (slowly) on some updates to the plugin. Hopefully I will be able to wrap up the changes by the time WordPress 3.0 is released. New features will expand the features to include the ability to use FancyBox with individual images, and an options page with options to set things like the caption placement, special effects, and timing for the image expansion and transitions.</p>\n<p>If you aren&#8217;t already familiar with this plugin, FancyBox Gallery gives you a nice popup image browser using the attached images displayed by the WordPress [gallery] shortcode. See the plugin page linked above for a live demonstration.</p>\n\n\n<p>Related posts:<ol><li><a href="http://dougal.gunters.org/blog/2009/06/15/plugin-fancybox-gallery-0-3-1" rel="bookmark" title="Permanent Link: Plugin: Fancybox Gallery 0.3.1">Plugin: Fancybox Gallery 0.3.1</a></li>\n<li><a href="http://dougal.gunters.org/blog/2009/01/26/fancybox-gallery-01" rel="bookmark" title="Permanent Link: FancyBox Gallery 0.1">FancyBox Gallery 0.1</a></li>\n<li><a href="http://dougal.gunters.org/blog/2009/01/21/plugin-preview-fancybox-gallery" rel="bookmark" title="Permanent Link: Plugin preview: FancyBox Gallery">Plugin preview: FancyBox Gallery</a></li>\n</ol></p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 29 Apr 2010 20:00:53 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Dougal";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:39;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:27:"Alex King: WordCamp SF 2010";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://alexking.org/?p=4292";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:52:"http://alexking.org/blog/2010/04/28/wordcamp-sf-2010";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1015:"<p>I&#8217;m heading to <a href="http://2010.sf.wordcamp.org/" rel="external">WordCamp SF</a> <a href="http://alexking.org/blog/2009/05/28/wordcamp-sf-this-weekend">again</a> this year and quite looking forward to it. Several folks from <a href="http://crowdfavorite.com">Crowd Favorite</a> are making the trip this year.</p>\n<p class="center"><a href="http://2010.sf.wordcamp.org/"><img src="http://2010.sf.wordcamp.org/files/2010/04/wcsf-l.png" alt="WordCamp SF 2010" /></a></p>\n<p>I&#8217;m looking forward to seeing a number of friends in the community this weekend. Of particular note, I&#8217;m hoping to talk to more plugin developers and find our new ways that <a href="http://wphelpcenter.com">WordPress HelpCenter</a> can work for them.</p>\n<p>If you&#8217;re going to be around and would like to catch up or perhaps meet up and get acquainted and talk WordPress &#8211; get in touch or come say hi at the event.</p>\n<img src="http://alexking.org/wp/?ak_action=api_record_view&id=4292&type=feed" alt="" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 28 Apr 2010 18:35:23 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Alex";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:40;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:28:"Alex King: Twitter Tools 2.3";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://alexking.org/?p=4285";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:53:"http://alexking.org/blog/2010/04/28/twitter-tools-2-3";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1924:"<p>I&#8217;ve updated my Twitter Tools plugin to version 2.3. This version has several security enhancements (thanks <a href="http://markjaquith.com" rel="external">Mark Jaquith</a>) as well as a change that may help some folks that have been seeing doubled digest posts. I recommend upgrading ASAP.</p>\n<p>The Twitter Tools plugin creates a full integration between your WordPress site and your Twitter account. You can send your blog posts to Twitter, bring your tweets back into your blog (as posts, in the sidebar or in a digest) and post to Twitter right from your WordPress admin. Twitter Tools also works as a Twitter archiver, so you keep a copy of all your tweets in your WordPress database. </p>\n<p>Twitter Tools has no known incompatibilities with WordPress 3.0 at this time and is working in our testing, however that could change between now and the time 3.0 is released. We won&#8217;t know for sure about compatibility until 3.0 is out there.</p>\n<p>I also wanted to note that Twitter Tools <strong>will</strong> be supporting OAuth in a future release, before the current authentication is <a href="http://countdowntooauth.com/" rel="external">turned off</a>.</p>\n<p>The download and more information are available on my <a href="http://alexking.org/projects/wordpress">WordPress Plugins page</a>.</p>\n<p>If you have any trouble with this, please contact the <a href="http://wphelpcenter.com">WordPress HelpCenter</a> (303-395-1346) or you can try the <a href="http://wordpress.org/support/" rel="external">WP Support Forums</a>.</p>\n<p>UPDATE: there is a bug in the recent tweet function that has been patched in the <a href="http://downloads.wordpress.org/plugin/twitter-tools.zip">development version</a>. I&#8217;m going to wait a day or two to see if any other issues arise before releasing the dot one update.</p>\n<img src="http://alexking.org/wp/?ak_action=api_record_view&id=4285&type=feed" alt="" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 28 Apr 2010 18:24:05 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Alex";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:41;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:30:"Matt: Mirroring Censored Blogs";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34335";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:46:"http://ma.tt/2010/04/mirroring-censored-blogs/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:302:"<p><a href="http://advocacy.globalvoicesonline.org/2010/04/22/guide-mirroring-a-censored-wordpress-blog/">Global Voices Advocacy has a new guide: Mirroring a Censored WordPress Blog</a>. They continue to be the best source for using WordPress to democratize publishing in places restricted freedom.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 28 Apr 2010 17:36:05 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:42;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:44:"Donncha: Preload the cache in WP Super Cache";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:29:"http://ocaoimh.ie/?p=89495847";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:47:"http://ocaoimh.ie/preload-cache-wp-super-cache/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3881:"<div align="center"><img src="http://ocaoimh.ie/wp-content/uploads/2010/04/cpu.png" alt="" title="cpu" width="550" height="227" class="aligncenter size-full wp-image-89495852" /></div>\n<p>See that nice dip in the graph for this week? I started to preload the cache used by WP Super Cache last Sunday and it&#8217;s made a noticeable difference in the load on my server here. The big spike is the preloading process.</p>\n<p>I&#8217;ve always discouraged users from preloading the cache (<a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL3dvcmRwcmVzcy5vcmcvZXh0ZW5kL3BsdWdpbnMvYXNrYXBhY2hlLWNyYXp5LWNhY2hlLw==">Askapache Crazy Cache</a> will do this for any cache plugin), mainly because of the possible problems so many files will cause for hosting companies. If you have thousands of cache files, it&#8217;s going to take so much longer to recover from a disk crash.<br />\nOn the other hand, Google will now be using speed as a metric for judging how &#8220;good&#8221; a website is. In the past this plugin ignored the pages visited by bots because the bots only visited each page once so caching a page after the fact was pointless. The page, all pages, have to be cached first before Google ever visits.</p>\n<p><img src="http://ocaoimh.ie/wp-content/uploads/2010/04/preload-screenshot.png" alt="" title="preload-screenshot" width="600" height="490" class="aligncenter size-full wp-image-89495849" /></p>\n<p>That&#8217;s what it looks like. Once you start preloading it launches a wp-cron job to fetch 100 posts, then schedules another job 10 seconds in the future to fetch another 100 posts until it finishes. It also disables garbage collection of old pages, but making comments or posts will still clear out the appropriate cached files.<br />\nIt only caches single posts right now. It may not be worth caching archive or tag pages because many sites already tell bots to ignore those pages as the server is doing less work it will serve those archive pages more quickly anyway.</p>\n<p>The preloading only works if you&#8217;re using the plugin in Supercache or &#8220;ON&#8221; mode. It&#8217;s still a work in progress but has worked fine here. As well as the preloader the development version of the plugin has:\n<ol>\n<li> <a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL3dvcmRwcmVzcy5vcmcvc3VwcG9ydC90b3BpYy8zMzkwNzU/cmVwbGllcz0yNA==">Better support</a> for mobile plugins.</li>\n<li> A cache tester.</li>\n<li> Can be configured to only delete the page a comment is left on, rather than the front page and associated pages.</li>\n<li> Works in WordPress 3.0.</li>\n</ol>\n<p> It also has a number of bug fixes and other features added too.</p>\n<p>I need testers though, so grab the development version from <a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL3dvcmRwcmVzcy5vcmcvZXh0ZW5kL3BsdWdpbnMvd3Atc3VwZXItY2FjaGUvZG93bmxvYWQv">the download page</a>. Install it and please leave feedback here or preferably on the <a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL3dvcmRwcmVzcy5vcmcvdGFncy93cC1zdXBlci1jYWNoZT9mb3J1bV9pZD0xMA==">support forum</a>.</p>\n<p><strong>Related Posts</strong><ul><li><a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL29jYW9pbWguaWUvd3Atc3VwZXItY2FjaGUtMDg0LXRoZS1nYXJiYWdlLWNvbGxlY3Rvci8=" rel="">WP Super Cache 0.8.4, the garbage collector</a></li><li><a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL29jYW9pbWguaWUvd3Atc3VwZXItY2FjaGUtMDg3Lw==" rel="">WP Super Cache 0.8.7</a></li><li><a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL29jYW9pbWguaWUvd3Atc3VwZXItY2FjaGUtMDk5Lw==" rel="">WP Super Cache 0.9.9</a></li></ul></p> <img src="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?view=1&post_id=89495847" width="1" height="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 28 Apr 2010 16:26:57 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:7:"Donncha";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:43;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:73:"Weblog Tools Collection: More plugins for securing your WordPress install";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://weblogtoolscollection.com/?p=7987";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:102:"http://weblogtoolscollection.com/archives/2010/04/27/more-plugins-for-securing-your-wordpress-install/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:9662:"<p>I wrote previously on <a href="http://weblogtoolscollection.com/archives/2010/04/15/how-to-improve-basic-security-on-a-fresh-wordpress-install/">securing a fresh WordPress install</a>. Today, I&#8217;ll cover several WordPress plugins that can be used with fresh or existing WordPress installations to enhance security. I&#8217;m not going to cover recovering a hacked site, or exploit scanning tools like <a href="http://wordpress.org/extend/plugins/exploit-scanner/">Exploit Scanner</a> or <a href="http://wordpress.org/extend/plugins/antivirus/">WordPress Antivirus</a> in this tutorial.</p>\n<p><span id="more-7987"></span></p>\n<p>As before, I&#8217;ll emphasize a few things:</p>\n<p>1. Your WordPress security is only as good as the security on your local computer. If you&#8217;re not running good antivirus and anti-malware software or are using an insecure wireless connection, none of this will matter.<br />\n2. Likewise, if you&#8217;re not keeping your WordPress install updated, none of this will matter.<br />\n3. I should have at least mentioned this in my previous security article but didn&#8217;t: your WordPress security is also only as good as your web server&#8217;s security. Since the audience for these tutorials is beginners, I&#8217;m going to assume that you don&#8217;t have a lot of control over your host&#8217;s security settings. So I&#8217;m not going to say anything else about this other than to look for a reputable host with experience hosting WordPress.<br />\n4. Make sure you&#8217;re using a strong password. See step 2 of <a href="http://weblogtoolscollection.com/archives/2010/04/15/how-to-improve-basic-security-on-a-fresh-wordpress-install/">my previous tutorial</a>.<br />\n5. I&#8217;m going to assume you already know how to install WordPress plugins.</p>\n<p>NOTE: I&#8217;m writing this guide for WordPress 2.92, the current stable release. All of these plugins seem to work with WordPress 3.0, but I haven&#8217;t thoroughly tested them.</p>\n<p><strong>WP Security Scan</strong></p>\n<p>Let&#8217;s start by checking for the biggest security holes first, using the plugin <a href="http://semperfiwebdesign.com/plugins/wp-security-scan/">WP Security Scan</a>.</p>\n<p>After you install you should see a new &#8220;Security&#8221; section on the left column of your dashboard:</p>\n<p><img class="alignnone size-full wp-image-7988" title="screenshot-1" src="http://weblogtoolscollection.com/wp-content/uploads/2010/04/screenshot-1.png" alt="" width="150" height="336" /></p>\n<p>Let&#8217;s click &#8220;Scanner&#8221; and check our file permissions, the most crucial of security settings in WordPress. Chances are everything will be shaded green, and everything&#8217;s ok. However, if anything&#8217;s not set correctly it will be highlighted in red. Changing file permissions is beyond the scope of this tutorial &#8211; contact your web host if you need to change anything.</p>\n<p><img class="alignnone size-full wp-image-7994" title="screenshot-2" src="http://weblogtoolscollection.com/wp-content/uploads/2010/04/screenshot-2.png" alt="" width="535" height="83" /></p>\n<p>Next, let&#8217;s change our database prefix. This is a &#8220;<a href="http://en.wikipedia.org/wiki/Security_through_obsurity">security through obscurity</a>&#8221; technique. What we want to do is make your WordPress database harder to exploit by using a database prefix other than the default one &#8211; this way any sort of generic, automated attack on the database will likely fail because the hacker will be using the wrong database prefix.</p>\n<p><strong>BEFORE ATTEMPTING THIS MAKE SURE YOU BACKUP</strong>. I can&#8217;t stress this enough. I wrote a tutorial on <a href="http://weblogtoolscollection.com/archives/2010/04/21/backing-up-your-wordpress-database-with-wp-db-backup/">backing up your WordPress tutorial</a>. Even if you don&#8217;t use the plugin I describe there, make sure you&#8217;ve got a good backup before proceeding.</p>\n<p>If you followed my last security tutorial and changed your database prefix during install, you can skip this step.</p>\n<p>Otherwise, click &#8220;Database&#8221; on the Security section. You&#8217;ll see something like this:</p>\n<p><img class="alignnone size-full wp-image-7995" title="screenshot-3" src="http://weblogtoolscollection.com/wp-content/uploads/2010/04/screenshot-3.png" alt="" width="628" height="195" /></p>\n<p>If you see something other than &#8220;wp_&#8221; in the field labeled &#8220;Change the current&#8221; field, then you can skip the next step.</p>\n<p>Change &#8220;wp_&#8221; to something else. It&#8217;s highly recommended that you still keep the _ for database readability in the future, however.</p>\n<p>Click &#8220;Start Renaming&#8221;</p>\n<p>If this fails, you&#8217;ll either have to change the database prefix manually or not at all. Manual changes of the prefix table are beyond the scope of this tutorial.</p>\n<p><strong>Secure WordPress</strong></p>\n<p>Next, let&#8217;s install <a href="http://bueltge.de/wordpress-login-sicherheit-plugin/652/">Secure WordPress</a>. After you install it click &#8220;Secure WP&#8221; in the settings column of the left column of the dashboard. Most of the defaults should be fine, except one: if you&#8217;re not planning on using Windows Live Writer, check the box next to that option and click &#8220;Save Changes.&#8221;</p>\n<p><strong>WordPress Firewall</strong></p>\n<p>The steps above will help prevent attacks by hiding information about your WordPress install from attackers, making sure the correct file permissions are set, and plugging a few potential security holes. Next we&#8217;ll install some plugins that actually stop attacks on your blog.</p>\n<p>WordPress Firewall is a handy plugin for preventing a variety of attacks. This one is especially important if you weren&#8217;t able to change your database prefix. It&#8217;s quite simple &#8211; just install it. There should be no need to change the default settings. <strong>Important:</strong> WordPress Firewall has only been tested up to WordPress 2.8. It has not been tested with WordPress 2.92 or WordPress 3.0 beta 2.</p>\n<p><strong>Bad queries</strong></p>\n<p><a href="http://wordpress.org/extend/plugins/block-bad-queries/">Block Bad Queries</a>, like Firewall, prevents hackers from performing certain common dangerous actions on your site. This one you just install and activate &#8211; there are no settings to change.</p>\n<p><strong>Chap Secure Login</strong></p>\n<p>If you&#8217;re not using SSL to login (once again, beyond the scope of this tutorial), you can use <a href="http://wordpress.org/extend/plugins/chap-secure-login/">Chap Secure Login</a> to encrypt your password. This is especially recommended if you use a lot of different computers to access WordPress, or frequently use public wireless Internet connections. Chap is another remarkably simple plugin &#8211; just install it and activate it and you&#8217;re ready to go. Note: you&#8217;ll get a warning the first time you login after installing. According the plugin developers, this is to be expected.</p>\n<p><strong>Login Lockdown</strong></p>\n<p>Finally, we&#8217;ll want to protect against brute force or dictionary attacks. In an out of the box WordPress installation, users can attempt and fail to login an infinite number of times. This means someone could try thousands of password combinations until they got the right one. <a href="http://wordpress.org/extend/plugins/login-lockdown/">Login Lockdown</a> will ban users from IP addresses that have tried and failed to login too many times.</p>\n<p>Install the plugin and click &#8220;Login Lockdown&#8221; in the &#8220;Settings&#8221; section. You should get an options menu that looks like this:</p>\n<p><img class="alignnone size-full wp-image-7991" title="screenshot-4" src="http://weblogtoolscollection.com/wp-content/uploads/2010/04/screenshot-4.png" alt="" width="345" height="450" /></p>\n<p>If you have a hard time typing your password correctly, you might want to set the &#8220;Max Login Retriess&#8221; a little higher.</p>\n<p>I also recommend using the &#8220;Mask Login Errors&#8221; option. Normally, if a user types an incorrect username WordPress will return an invalid user name error. But if the user types a correct username but an incorrect password, WordPress will return an invalid password error. This gives someone trying to crack your password an extra hint as to whether they at least have the right username. If you use the &#8220;Mask Login Errors&#8221; option, WordPress will return a generic &#8220;username or password is incorrect&#8221; error instead.</p>\n<p><strong>Ask Apache</strong></p>\n<p>Many people swear by <a href="http://wordpress.org/extend/plugins/askapache-password-protect/">AskApache Password Protect</a>. However, I have not been able to get it to work with my host. Your mileage may vary. If I understand it correctly, this plugin adds an additional password to the /wp-admin directory. If you allow open registrations and have lot of users logging in, you might not want to use this plugin.</p>\n<p><strong>Conclusion</strong></p>\n<p>There&#8217;s still much more you can do, such as using .htaccess to protect directories, moving core WordPress files, and monitoring for exploits. Those are things we&#8217;ll have to cover in the future. If you have need to harden things further now, please see the <a href="http://codex.wordpress.org/Hardening_WordPress">Hardening WordPress Codex entry</a>. Remember no (usable) site will ever be completely secure, but if you&#8217;ve installed the plugins above your chances of getting hacked will be greatly reduced.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 27 Apr 2010 11:48:42 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"Klint Finley";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:44;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:60:"Weblog Tools Collection: WordPress Plugin Releases for 04/26";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://weblogtoolscollection.com/?p=7993";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:88:"http://weblogtoolscollection.com/archives/2010/04/26/wordpress-plugin-releases-for-0426/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:4007:"<h3>New Plugins</h3>\n<p><a href="http://www.gospelrhys.co.uk/plugins/wordpress-plugins/incomment-wordpress-plugin">Incomment Referrer</a></p>\n<p>This plugin quite simply lets you know where the users entered your site when they leave a comment. A lot of people who joined the do-follow movement are listed on sites which are a target for comment spammers. To those who suffer comment spam can now find out the page they come from, and block accordingly.</p>\n<p><a href="http://nxsn.com/projects/wp-hide-pages/">WP Hide Pages</a></p>\n<p>This plugin hides selected pages from menus which created with wp_list_pages function. Essentially it adds exclude parameter to wp_list_pages function but it’s so easy now.</p>\n<p><a href="http://obaq.uuuq.com/?p=253">Pages to Page</a></p>\n<p>Create the contents of Recent Comments, Pages, Categories, Archives, Recent Posts and Calendar which are usually shown in the sidebar and insert them onto a post or page.</p>\n<p><a href="http://eletrowidgets.hacklab.com.br/">eletro widgets</a></p>\n<p>It allows yout to use WordPress widgets to set up your home page (or any page) in your blog. You can configure and drag &amp; drop widgets around right in the front end. Please watch the video for further details.</p>\n<p><a href="http://pranav.me/projects/plugins/gt-geotargeting/">GT – Geo Targeting</a></p>\n<p>Description: GEO target content based on user’s country. Show/hide content to/from users from specific countries, Show a note to users who cannot see the content. Template tags and shortcodes available for use.</p>\n<p><a href="http://pranav.me/projects/plugins/taxonomy-manager/">Taxonomy Manager</a></p>\n<p>Add, Edit, Delete &amp; Manage taxonomies for posts, pages, links and custom post types with a few clicks of mouse. Makes adding taxonomies a lot easier. Display taxonomy tag clouds and more using widgets and display tags and other info at the bottom of posts.</p>\n<h3>Updated Plugins</h3>\n<p><a href="http://smashly.net/photosmash-galleries/">PhotoSmash Galleries</a></p>\n<p>PhotoSmash Galleries has been updated to provide a Gallery Viewer page (an index of your galleries), and now supports EXIF data with easy tags for displaying it ([exif_table] and [meta_data field=''aperture''] or whatever exif fields you have).</p>\n<p><a href="http://obaq.uuuq.com/?p=236">Rico Ajax Menu</a></p>\n<p>Can create a menu with tabs, accordions or pulldowns using <a href="http://openrico.org/">Rico Ajax</a></p>\n<p><a href="http://blog.grandprix.int/wordpress-plugins/avh-extended-categories/">AVH Extended Categories</a></p>\n<p>The AVH Extended Categories Widgets gives you three widgets for displaying categories.</p>\n<p><a href="http://scribu.net/wordpress/smart-archives-reloaded">Smart Archives Reloaded</a></p>\n<p>Offers an elegant and easy way to present your posts, grouped by year and month.</p>\n<p><a href="http://arpitshah.com/plugins/twitter-goodies/"></a><a href="http://arpitshah.com/plugins/twitter-goodies/">Twitter Goodies</a></p>\n<p>This plugin will show your twitter tweets under Sidebar Area (Widget), Post and/or Pages. Tweets will REFRESH AUTOMATICALLY. Also it has reply option inside widget on mouse over action.</p>\n<p><a href="http://arpitshah.com/plugins/wp-google-buzz/">WP Google-buzz</a></p>\n<p>Beautiful Google buzz integration to wordpress + 8 different admin panel options (Settings -&gt; WP Google-buzz) + 14 diff button images + Buzz Counter + mouse over effects.</p>\n<p><a href="http://www.weinschenker.name/plugin-feed-reading-blogroll/">WP Social Blogroll</a></p>\n<p>The plugin adds a cool new blogroll that is able to display the freshness, author name and the latest post-title of your bookmarks. It enables you to sort the blogroll by the latest update of your bookmarked blogs.</p>\n<p><a href="http://fusionswift.com/wordpress-tweeter/">WordPress Tweeter</a></p>\n<p>WordPress Tweeter is a plugin that will update a twitter account when you make a new post on your blog. You will be able to customize the tweet template.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 26 Apr 2010 20:05:30 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:7:"Perurry";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:45;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:43:"WP iPhone: jkOnTheRun: Blogging on the iPad";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:34:"http://iphone.wordpress.org/?p=691";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:71:"http://iphone.wordpress.org/2010/04/26/jkontherun-blogging-on-the-ipad/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2284:"<p><img class="alignright size-full wp-image-698" title="blogging-ipad-keyboard" src="http://wpiphone.files.wordpress.com/2010/04/blogging-ipad-keyboard.jpg?w=300&#038;h=225" alt="" width="300" height="225" /></p>\n<p><a href="http://jkontherun.com/author/jkendrick/">James Kendrick</a> has <a href="http://jkontherun.com/2010/04/22/blogging-on-the-ipad/">posted a very comprehensive review</a> of how he blogs from the iPad using the <a href="http://itunes.apple.com/us/app/wordpress/id335703880?mt=8">WordPress app</a> and a few other tools:</p>\n<blockquote><p>The WordPress app for the iPad is pretty good, and I usually write the entire blog post in this editor. It’s important to note that there is no fancy visual editor (WYSIWYG) like in the web-based version. It’s a simple text editor that works well for text entry. It’s also a HTML editor, so those familiar with HTML can use it to make posts with sophisticated formatting. I’m too far removed from the old HTML blogging days, so I avoid it.</p></blockquote>\n<p>You can read the <a href="http://jkontherun.com/2010/04/22/blogging-on-the-ipad/">full post over on jkOnTheRun.com</a> .</p>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wpiphone.wordpress.com/691/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wpiphone.wordpress.com/691/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wpiphone.wordpress.com/691/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wpiphone.wordpress.com/691/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wpiphone.wordpress.com/691/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wpiphone.wordpress.com/691/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wpiphone.wordpress.com/691/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wpiphone.wordpress.com/691/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wpiphone.wordpress.com/691/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wpiphone.wordpress.com/691/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=iphone.wordpress.org&blog=3882653&post=691&subd=wpiphone&ref=&feed=1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 26 Apr 2010 19:44:31 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:16:"Raanan Bar-Cohen";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:46;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:39:"Joseph: WordCamp San Francisco – 2010";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:30:"http://josephscott.org/?p=2218";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:68:"http://josephscott.org/archives/2010/04/wordcamp-san-francisco-2010/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1114:"<p>This Saturday is <a href="http://2010.sf.wordcamp.org/">WordCamp San Francisco</a>!  I&#8217;ll be there for WordCamp, the <a href="http://2010.sf.wordcamp.org/schedule/">developer day and two day code sprint</a> as well.  </p>\n<p>This year I&#8217;ll be <a href="http://2010.sf.wordcamp.org/speakers/">speaking at WordCamp</a>, a more technical focused presentation on “Writing Responsible Plugin &#038; Theme Code”.  I&#8217;ll be covering security items and tips for making sure that your plugin/theme plays nice with WordPress.</p>\n\n\n<p>Related posts:<ol><li><a href="http://josephscott.org/archives/2009/02/ill-be-at-wordcamp-denver/" rel="bookmark" title="Permanent Link: I&#8217;ll Be At WordCamp Denver">I&#8217;ll Be At WordCamp Denver</a></li>\n<li><a href="http://josephscott.org/archives/2009/04/reno-tahoe-wordcamp/" rel="bookmark" title="Permanent Link: Reno-Tahoe WordCamp">Reno-Tahoe WordCamp</a></li>\n<li><a href="http://josephscott.org/archives/2009/01/wordcamp-las-vegas-videos/" rel="bookmark" title="Permanent Link: WordCamp Las Vegas Videos">WordCamp Las Vegas Videos</a></li>\n</ol></p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 26 Apr 2010 16:32:11 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"Joseph Scott";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:47;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:25:"Matt: Twenty Ten starting";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34333";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:41:"http://ma.tt/2010/04/twenty-ten-starting/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:489:"<p><a href="http://en.blog.wordpress.com/2010/04/26/new-theme-twenty-ten/">The new Twenty Ten theme is now live on WordPress.com</a> and the default for all new blogs created on the service. As an aside, WP.com (11 million sites) was switched over to 3.0 over the weekend. I love it when we&#8217;re able to do that early because we find a ton of bugs in the integration and merge, and then we have 11 million beta testers banging on the software before we do the shrink-wrap release.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 26 Apr 2010 16:12:21 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:48;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:37:"Dev Blog: WordCamp San Francisco 2010";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1326";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:57:"http://wordpress.org/development/2010/04/wordcampsf-2010/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:4911:"<p>A week from today on May 1, hundreds of WordPress users, developers, designers and general enthusiasts will descend upon San Francisco for the 4th annual <a href="http://2010.sf.wordcamp.org/">WordCamp SF</a>. Since that first WordCamp in 2006, back when WordPress was on version 2.0 (Duke), the number of people using WordPress to power their web publishing &#8212; from personal blogs to large-scale commercial sites &#8212; has grown by millions. It&#8217;s no wonder this year&#8217;s event is going to be so great.</p>\n<p>If you&#8217;re unfamiliar with <a href="http://wordcamp.org/">WordCamps</a>, here&#8217;s the skinny: the San Francisco event is the flagship, put together each year under the direction of WordPress co-founder and lead developer <a href="http://ma.tt">Matt Mullenweg</a>, who traditionally reports on the &#8220;State of the Word&#8221; and assembles a lineup of <a href="http://2010.sf.wordcamp.org/speakers/">speakers</a> that have inspired him over the past year. This year&#8217;s lineup includes luminaries such as Richard Stallman, the father of Free Software, best-selling author Scott Berkun, and Salon.com co-founder Scott Rosenberg. As the final speaker list is finalized, the remaining speakers will be added to the <a href="http://2010.sf.wordcamp.org/">WordCamp SF website</a>, but a surprise or two is still possible.</p>\n<p>Though the main event is on Saturday, May 1, there are additional <a href="http://2010.sf.wordcamp.org/schedule/">days of WordPress goodness</a> in store. Saturday, May 1 will be the main conference with scheduled speakers. There will be keynotes, session tracks for both bloggers/end-users and developers, and lightning talks to provide a broad mix of content, followed by a raging afterparty. Sunday, May 2 will shift location and tone, with a low-key developers&#8217; unconference for the super-code-focused attendees. May 3 and 4 are conference-free, but a WordPress core contributor in-person code sprint will span those two days, bringing together core contributors old and new from around the globe for two days of intense hacking (and let&#8217;s face it, 3.0 bug fixes).</p>\n<p>If you&#8217;re in the Bay Area, or can be, and want to attend <a href="http://2010.sf.wordcamp.org/">WordCamp San Francisco</a>, <a href="http://2010.sf.wordcamp.org/tickets/">go get your ticket today</a>!</p>\n<p>*     *      *      *     *</p>\n<h3><strong>Other Upcoming WordCamps</strong></h3>\n<p>It&#8217;s definitely WordCamp season; just check out the growing list of upcoming WordCamps over the next couple of months! If you don&#8217;t see a WordCamp near you listed here, check the rest of the <a href="http://central.wordcamp.org/schedule/">schedule at WordCamp.org</a>. In the meantime, don&#8217;t forget that many WordCamps post video of their presentations on <a href="http://wordpress.tv">WordPress.tv</a>.</p>\n<p>April 24 (today!) &#8211; <a href="http://www.ocwordcamp.com/">WordCamp Orange County</a><br />\nIrvine, CA USA</p>\n<p>April 29 &#8211; <a href="http://www.wordcampnashville.com/">WordCamp Nashville</a><br />\nNashville, TN USA</p>\n<p><strong>May 1 &#8211; <a href="http://2010.sf.wordcamp.org/">WordCamp San Francisco</a><br />\nSan Francisco, CA USA</strong></p>\n<p>May 8 &#8211; <a href="http://wordcamp.fr/">WordCamp Paris</a><br />\nParis, France</p>\n<p>May 8 &#8211; <a href="http://argentina.wordcamp.org/">WordCamp Argentina </a><br />\nBuenos Aires, Argentina</p>\n<p>May 8 &#8211; <a href="http://chile.wordcamp.org/">WordCamp Chile</a><br />\nSantiago, Chile</p>\n<p>May 15–16 &#8211; <a href="http://denmark.wordcamp.org/">WordCamp Denmark</a><br />\nCopenhagen, Denmark</p>\n<p>May 15 &#8211; <a href="http://www.wordcampvictoria.ca/">WordCamp Victoria</a><br />\nVictoria, BC Canada</p>\n<p>May 21–22 &#8211; <a href="http://www.wordcamp.it/">WordCamp Italy</a><br />\nMilan, Italy</p>\n<p>May 22 &#8211; <a href="http://www.wordcamp.my/">WordCamp Malaysia</a><br />\nKuala Lumpur, Malaysia</p>\n<p>May 22–23 &#8211; <a href="http://wordcampraleigh.com/">WordCamp Raleigh</a><br />\nRaleigh, North Carolina USA</p>\n<p>May 29–30 &#8211; <a href="http://wordcampfayetteville.com/">WordCamp Fayetteville</a><br />\nFayetteville, Arkansas USA</p>\n<p>May 29 &#8211; <a href="http://yokohama2010.wordcamp.jp/">WordCamp Yokohama</a><br />\nYokohama, Japan</p>\n<p>June 5–6 &#8211; <a href="http://wordcampchicago.com/">WordCamp Chicago</a><br />\nChicago, Illinois USA</p>\n<p>June 12 &#8211; <a href="http://www.renotahoewordcamp.com/">WordCamp Reno-Tahoe</a><br />\nReno, Nevada USA</p>\n<p>June 12 &#8211; <a href="http://wordcampvancouver.com/">WordCamp Vancouver</a><br />\nVancouver, Canada</p>\n<p>June 18 &#8211; <a href="http://wordcamp.it/catania2010/">WordCamp Catania</a><br />\nCatania, Italy</p>\n<p>June 19 &#8211; <a href="http://wordcampcolumbus.com/">WordCamp Columbus </a><br />\nColumbus, Ohio USA</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 24 Apr 2010 15:49:24 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Jane Wells";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:49;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:38:"Dev Blog: Coming up on Beta 2: Sprint!";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1328";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:68:"http://wordpress.org/development/2010/04/coming-up-on-beta-2-sprint/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2952:"<p>Early next week, we&#8217;re hoping to release the 2nd beta release of WordPress 3.0 on our journey toward the final version. There are still <a href="http://core.trac.wordpress.org/query?status=accepted&amp;status=assigned&amp;status=new&amp;status=reopened&amp;status=reviewing&amp;group=status&amp;order=priority&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=priority&amp;col=component&amp;col=version&amp;milestone=3.0&amp;type=defect+%28bug%29">over 200 bugs</a> in the 3.0 milestone, and we can use all the help we can get on fixing these problems. If you&#8217;re a developer, take a look at the list of bugs that <a href="http://core.trac.wordpress.org/query?status=accepted&amp;status=assigned&amp;status=new&amp;status=reopened&amp;status=reviewing&amp;group=status&amp;order=priority&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=priority&amp;col=component&amp;col=version&amp;milestone=3.0&amp;type=defect+%28bug%29">still need fixing</a> in 3.0. <a href="http://core.trac.wordpress.org/query?status=accepted&amp;status=assigned&amp;status=new&amp;status=reopened&amp;status=reviewing&amp;group=status&amp;order=priority&amp;col=id&amp;col=summary&amp;col=type&amp;col=owner&amp;col=priority&amp;col=component&amp;col=version&amp;milestone=3.0&amp;keywords=~needs-patch&amp;type=defect+%28bug%29">Write a patch</a>, or <a href="http://core.trac.wordpress.org/query?status=accepted&amp;status=assigned&amp;status=new&amp;status=reopened&amp;status=reviewing&amp;group=status&amp;order=priority&amp;col=id&amp;col=summary&amp;col=type&amp;col=owner&amp;col=priority&amp;col=component&amp;col=version&amp;milestone=3.0&amp;keywords=~has-patch&amp;type=defect+%28bug%29">test and give feedback</a> on someone else&#8217;s. The tickets around custom post types and taxonomies are especially in need of help. Every little bit helps, so if you&#8217;re a developer who&#8217;s never contributed to core before, maybe now is the right time! Check out our information on <a href="http://codex.wordpress.org/Contributing_to_WordPress">contributing to WordPress core</a>, and head over to <a href="http://core.trac.wordpress.org/">Trac</a> to see if there&#8217;s a problem you might know how to fix. If you get stuck, need collaborators, or have a question about the best way to approach a fix, hop into the dev channel on IRC at irc.freenode.net, channel #wordpress-dev. Core developers will be around over the weekend working on bugs themselves, so if you&#8217;re trying to help, don&#8217;t be afraid to ask questions. With your help, maybe by Monday we can knock the bug count down to half of what it is right now. How great would that be? (Answer: pretty great)</p>\n<p>The sprint will go full force until Monday afternoon, when the lead developers and core committers will all stop to take a breath and look at the remaining bug reports to see how we did over the weekend, so don&#8217;t wait! And thanks!</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 24 Apr 2010 12:08:39 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Jane Wells";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}}}}}}}}}}}}s:4:"type";i:128;s:7:"headers";a:8:{s:4:"date";s:29:"Mon, 17 May 2010 21:23:35 GMT";s:6:"server";s:9:"LiteSpeed";s:13:"accept-ranges";s:5:"bytes";s:10:"connection";s:5:"close";s:4:"etag";s:23:""328f5-4bf1b1ef-5042b6"";s:13:"last-modified";s:29:"Mon, 17 May 2010 21:15:27 GMT";s:12:"content-type";s:15:"application/xml";s:14:"content-length";s:6:"207093";}s:5:"build";s:14:"20090627192103";}', 'no');
