(1, 1, '2010-05-17 21:23:01', '2010-05-17 21:23:01', 'Welcome to <a href="http://hopeinloss.org/">Hopeinloss.org </a>. This is your first post. Edit or delete it, then start blogging!', 'Hello world!', '', 'publish', 'open', 'open', '', 'hello-world', '', '', '2010-05-17 21:23:01', '2010-05-17 21:23:01', '', 0, '', 0, 'post', '', 1),
