";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:73:"http://feedproxy.google.com/~r/weblogtoolscollection/UXMP/~3/wu_wLR0VRvU/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1935:"<p><img class="alignnone size-full wp-image-11133" title="brownworld" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/brownworld.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://bestwpblogthemes.com/2012/simple-dark-wordpress-theme-brown-world/"><strong>Brown World</strong></a> is a simple dark brown theme.</p>\n<p><img class="alignnone size-full wp-image-11138" title="mylife" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/mylife.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://wordpress.org/extend/themes/my-life"><strong>My Life</strong></a> is a serene blogging theme that emphasizes your content with readable typography.</p>\n<p><img class="alignnone size-full wp-image-11134" title="picochic" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/picochic.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://wordpress.org/extend/themes/picochic"><strong>Picochic</strong></a> is a neutral, light, clean and professional looking theme.</p>\n<p><img class="alignnone size-full wp-image-11137" title="simpleblack" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/simpleblack.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://bestwpblogthemes.com/2012/simple-dark-black-wordpress-theme-simple-black-theme/"><strong>Simple Black</strong></a> is a simple theme with a dark black design.</p>\n<p><img class="alignnone size-full wp-image-11136" title="suede" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/suede.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://emptynestthemes.com/2012/03/10/suede-wordpress-theme/"><strong>Suede</strong></a> has two columns, fixed width, a left sidebar, and features a brilliant, vibrant orange-red, beige, tan, cream, brown, and taupe scheme.</p>\n<img src="http://feeds.feedburner.com/~r/weblogtoolscollection/UXMP/~4/wu_wLR0VRvU" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 12 Mar 2012 13:00:13 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:5:"James";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:6;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:59:"Weblog Tools Collection: WordPress Plugin Releases for 3/10";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:41:"http://weblogtoolscollection.com/?p=11129";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:73:"http://feedproxy.google.com/~r/weblogtoolscollection/UXMP/~3/ExNL2vXsZAo/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1203:"<h3>New plugins</h3>\n<p><a href="http://wordpress.org/extend/plugins/bbpress-digest/"><strong>bbPress Digest</strong></a> allows you to send daily digest with a forum&#8217;s active topics.</p>\n<p><a href="http://wordpress.org/extend/plugins/pulsemaps/"><strong>PulseMaps Visitor Map Plugin</strong></a> allows you to see your visitors on a world map.</p>\n<p><a href="http://wordpress.org/extend/plugins/user-login-stat/"><strong>User Login Statistics</strong></a> tracks registered users login statistics each day.</p>\n<p><a href="http://wpappmaker.com/"><strong>WP App Maker</strong></a> allows you to generate and distribute an Android App for your WordPress blog.</p>\n<h3>Updated plugins</h3>\n<p><a href="http://wordpress.org/extend/plugins/image-widget/"><strong>Image Widget</strong></a> uses a native WordPress upload thickbox to add image widgets to your site.</p>\n<p><a href="http://wordpress.org/extend/plugins/ultimate-cms/"><strong>Ultimate CMS</strong></a> is an easy to use plugin to create, customize, and manage custom post/page types, custom archives, and custom taxonomies.</p>\n<img src="http://feeds.feedburner.com/~r/weblogtoolscollection/UXMP/~4/ExNL2vXsZAo" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 10 Mar 2012 14:00:07 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:5:"James";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:7;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:61:"WPTavern: WordPress Not The Direct Cause Of Mass Site Attacks";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=6406";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:113:"http://feedproxy.google.com/~r/WordpressTavern/~3/-xrOIkFLWM8/wordpress-not-the-direct-cause-of-mass-site-attacks";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1736:"<p>Sucuri <a href="http://blog.sucuri.net/2012/03/rr-nu-malware-campain-more-details.html">has published more information</a> regarding the compromising of at least 30,000 domains. Based on their research, they are ruling out the possibility that the attacks are taking advantage of a new vulnerability within the core of WordPress. </p>\n<blockquote><p>The first question is how are these sites getting hacked? On all the cases we analyzed, they either had outdated versions of WordPress, or of a plugin. We can safely rule out any new vulnerability on WordPress itself.</p></blockquote>\n<p>To stay on top of the latest malware threats on the web, you should <a href="http://feeds.feedburner.com/SucuriSecurity">subscribe to their RSS feed</a>. Perhaps the more people that realize this stuff is happening on a daily basis, the more it will persuade them to keep sites, plugins, and themes updated. </p>\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/5-tips-to-create-a-great-site-about-wordpress" rel="bookmark" title="5 Tips To Create A Great Site About WordPress">5 Tips To Create A Great Site About WordPress</a></li>\n<li><a href="http://www.wptavern.com/getting-started-with-designing-your-site" rel="bookmark" title="Getting Started With Designing Your Site">Getting Started With Designing Your Site</a></li>\n<li><a href="http://www.wptavern.com/14-things-to-consider-when-choosing-a-webhost-for-your-wordpress-powered-site" rel="bookmark" title="14 Things To Consider When Choosing A Webhost For Your WordPress Powered Site">14 Things To Consider When Choosing A Webhost For Your WordPress Powered Site</a></li>\n</ol></p><img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/-xrOIkFLWM8" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 09 Mar 2012 18:00:29 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:8;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:74:"WPTavern: Lance Willett Helps Beginners Navigate WordPress Theme Landscape";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=6401";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:116:"http://feedproxy.google.com/~r/WordpressTavern/~3/WSendJNMxVE/lance-willett-helps-beginners-navigate-theme-landscape";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1227:"<p>Fresh from <a href="http://2012.phoenix.wordcamp.org/">WordCamp Phoenix 2012</a>, Lance Willett who works for Automattic and is part of the theme wrangler team gave a great presentation for beginners on how to navigate the vast landscape that is WordPress themes. He covers the gamut such as where to look for themes, commercial themes, things to consider before using the theme on your site, etc. This presentation is truly for the beginner as it has nothing to do with coding. Nice job Lance. </p>\n<div class="aligncenter"></div>\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/wpweekly-episode-109-%e2%80%93-interview-with-lance-willett" rel="bookmark" title="WPWeekly Episode 109 – Interview With Lance Willett">WPWeekly Episode 109 – Interview With Lance Willett</a></li>\n<li><a href="http://www.wptavern.com/name-your-dream-theme-team" rel="bookmark" title="Name Your Dream Theme Team">Name Your Dream Theme Team</a></li>\n<li><a href="http://www.wptavern.com/roots-wordpress-starter-theme" rel="bookmark" title="Roots &#8211; WordPress Starter Theme">Roots &#8211; WordPress Starter Theme</a></li>\n</ol></p><img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/WSendJNMxVE" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 09 Mar 2012 14:00:25 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:9;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:59:"WordPress.tv: Greg Loumeau: WP101 Rocking in the Free World";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://wordpress.tv/?p=9883";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:76:"http://wordpress.tv/2012/03/08/greg-loumeau-wp101-rocking-in-the-free-world/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1814:"<div id="v-rsomMGSg-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/9883/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/9883/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wptv.wordpress.com