.wordpress.com/1.0/goreddit/wptv.wordpress.com/9879/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wptv.wordpress.com/9879/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=9879&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2012/03/08/lance-willett-navigating-the-theme-landscape/"><img alt="Lance Willett: Navigating the Theme Landscape" src="http://videos.videopress.com/OLFIkyyP/wcphx_jumpstart_themes_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 08 Mar 2012 16:30:13 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:14:"blazestreaming";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:11;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:47:"WPTavern: Your Daily Fix Of WordPress Functions";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=6396";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:99:"http://feedproxy.google.com/~r/WordpressTavern/~3/jhJk2PJsbv4/your-daily-fix-of-wordpress-functions";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1968:"<p>How would you like to experience WordPress functions within your inbox on a daily basis? If so, consider signing up to the <a href="http://www.dailydocumentation.com/wordpress/">WordPress Daily Documentation site</a>. Each day features a different function within WordPress sent to your inbox which contains examples, an explanation of what the function does, parameters, and the usual information you would find via other sources. Since signing up, I&#8217;ve received emails covering <strong>add_shortcode()</strong> and <strong>get_the_ID()</strong>. </p>\n<p><a href="http://www.wptavern.com/wp-content/uploads/2012/03/shortcodefunction.png" rel="thumbnail"><img src="http://www.wptavern.com/wp-content/uploads/2012/03/shortcodefunction.png" alt="Daily WordPress functions" title="shortcodefunction" width="505" height="280" class="aligncenter size-full wp-image-6397" /></a></p>\n<p>There are all sorts of ways to view information related to specific WordPress functions but this method may be especially useful to those who are starting to learn what functions are and which ones WordPress contains. But if you don&#8217;t feel like putting your email address on yet another subscription list, there is always the <a href="http://codex.wordpress.org/Function_Reference">Codex</a>. </p>\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/lookup-functions-in-a-flash" rel="bookmark" title="Lookup Functions In A Flash">Lookup Functions In A Flash</a></li>\n<li><a href="http://www.wptavern.com/wordpress-is-more-functional-over-time" rel="bookmark" title="WordPress Is More Functional Over Time">WordPress Is More Functional Over Time</a></li>\n<li><a href="http://www.wptavern.com/too-much-rss-noise-get-an-email-daily-digest" rel="bookmark" title="Too Much RSS Noise? Get An Email Daily Digest">Too Much RSS Noise? Get An Email Daily Digest</a></li>\n</ol></p><img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/jhJk2PJsbv4" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 08 Mar 2012 14:00:57 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:12;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:57:"Weblog Tools Collection: WordPress Theme Releases for 3/8";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:41:"http://weblogtoolscollection.com/?p=11117";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:73:"http://feedproxy.google.com/~r/weblogtoolscollection/UXMP/~3/mVS_pPXOjoI/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3787:"<p><img class="alignnone size-full wp-image-11118" title="basiclaw" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/basiclaw.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://generalthemes.com/basic-law/"><strong>Basic Law</strong></a> is a theme for law blogs and legal websites.</p>\n<p><img class="alignnone size-full wp-image-11119" title="history" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/history.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://generalthemes.com/history/"><strong>History</strong></a> is a theme for history blogs.</p>\n<p><img class="alignnone size-full wp-image-11120" title="knit" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/knit.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://emptynestthemes.com/2012/02/23/knit-wordpress-blog-theme/"><strong>Knit</strong></a> has fixed width, two columns, right sidebar, is widget and adsense ready, has valid xhtml, and features soft colors – aqua, teal, blue, sea green, white.</p>\n<p><img class="alignnone size-full wp-image-11121" title="moderntown" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/moderntown.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://bestwpblogthemes.com/2012/yellow-red-wordpress-architecture-theme-modern-city/"><strong>Modern Town</strong></a> is a yellow and red modern architecture theme with great graphics and modern background.</p>\n<p><img class="alignnone size-full wp-image-11122" title="skirmish" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/skirmish.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://generalthemes.com/skirmish/"><strong>Skirmish</strong></a> is an elegant, two column theme, perfect for personal blogs.</p>\n<p><img class="alignnone size-full wp-image-11126" title="stumblr" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/stumblr.jpg" alt="" width="150" height="94" /></p>\n<p><a href="http://www.eleventhemes.com/stumblr-theme/"><strong>Stumblr</strong></a> is a clean and minimal MicroBlogging theme with a simple options panel.</p>\n<p><img class="alignnone size-full wp-image-11123" title="sunnytravel" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/sunnytravel.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://bestwpblogthemes.com/2012/light-blue-travel-wp-theme-sunny-travel/"><strong>Sunny Travel</strong></a> is a travel theme with a light blue design, great to share your travel photos.</p>\n<p><img class="alignnone size-full wp-image-11124" title="swift" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/swift.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://wordpress.org/extend/themes/swift-basic"><strong>Swift Basic</strong></a> is a fast loading, developer friendly, and advanced theme with loads of intutive customization options, giving you an infinite number of layouts.</p>\n<p><img class="alignnone size-full wp-image-11127" title="yaminth" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/yaminth.jpg" alt="" width="150" height="95" /></p>\n<p><a href="http://azmind.com/2012/03/04/free-wordpress-theme-yaminth/"><strong>YAMINTH</strong></a> is a free theme with a modern and minimal look.</p>\n<p><img class="alignnone size-full wp-image-11125" title="yellowtree" src="http://weblogtoolscollection.com/wp-content/uploads/2012/03/yellowtree.jpg" alt="" width="150" height="113" /></p>\n<p><a href="http://bestwpblogthemes.com/2012/gray-yellow-wordpress-theme-yellow-tree/"><strong>Yellow Tree</strong></a> is a simple gray and yellow theme with a tree silhouette in the header.</p>\n<img src="http://feeds.feedburner.com/~r/weblogtoolscollection/UXMP/~4/mVS_pPXOjoI" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 08 Mar 2012 14:00:20 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:5:"James";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:13;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:47:"WordPress.tv: Josh Ziering: Promoting Your Site";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://wordpress.tv/?p=9876";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:64:"http://wordpress.tv/2012/03/08/josh-ziering-pro