xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1404:"<div id="x-video-4" class="video-player">\n\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/3918/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/3918/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wptv.wordpress.com/3918/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wptv.wordpress.com/3918/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wptv.wordpress.com/3918/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wptv.wordpress.com/3918/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wptv.wordpress.com/3918/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wptv.wordpress.com/3918/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wptv.wordpress.com/3918/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wptv.wordpress.com/3918/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=3918&subd=wptv&ref=&feed=1" /><div><a href="http://wordpress.tv/2010/05/01/john-ford-healthy-computing-sf10/"><img alt="John Ford: Living with Our Computers… And Keeping it Healthy" src="http://cdn.videos.wordpress.com/bp2ANDV0/john-ford1_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 09 Jun 2010 20:15:33 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:11:"Ryan Markel";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:19;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:47:"Dev Blog: Expanding the Theme Review Experiment";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1347";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:79:"http://wordpress.org/development/2010/06/expanding-the-theme-review-experiment/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1964:"<p>When I was a kid my dad used to practice his typing skills (on a real typewriter no less) with the phrase:</p>\n<blockquote><p>Now is the time for all good men to come to the aid of their country.</p></blockquote>\n<p>For some reason that has stuck with me all these years. Today I’m going to rephrase and re-purpose that line:</p>\n<blockquote><p>Now is the time for great theme developers to come to the aid of their community.</p></blockquote>\n<p>The theme directory has been chugging along for more than a year now. During that time we’ve tinkered with the review process and some of the management tools, but haven’t really opened it up as much as we’d like. It&#8217;s time to rip off the band-aid and take some action; to that end, we&#8217;re looking for community members to help with the process of reviewing themes for the directory.</p>\n<p>Right now this is a bit like a New Year’s resolution to exercise every day: it’s what we need to do, but we’re still figuring out exactly how it will all work. That’s part of the community involvement as well &#8212; we expect that those who pitch in will also help shape the process.</p>\n<p>What’s involved in reviewing themes for the directory? There are some obvious things, such as being familiar with PHP and WordPress theme code (and the <a href="http://codex.wordpress.org/Theme_Development_Checklist">theme development checklist</a>), with an eye for security issues. You would also need to have the ability to set up a separate install of the latest version of WordPress for testing theme submissions.</p>\n<p>Hopefully a few talented theme developers are reading this right now and saying to themselves, &#8220;I’d love to help! How do I to get started?&#8221; Just join the new <a href="http://lists.wordpress.org/mailman/listinfo/theme-reviewers">theme reviewers mailing list</a> and we&#8217;ll get you up to speed on this new opportunity to come to the aid of your community.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 09 Jun 2010 16:06:11 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"Joseph Scott";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:20;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:26:"Matt: Automated Snail Mail";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34715";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:42:"http://ma.tt/2010/06/automated-snail-mail/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:358:"<p>Been looking into ways to send personalized letters and postcards through the mail system, old school style. Mail is the new email! The best option <a href="http://www.postful.com/">seems to be Postful</a> in terms of pricing and API. Wondering if anyone has any experience doing custom mailings like this, and if so what tips and experience you have.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 09 Jun 2010 13:37:14 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:21;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:20:"Matt: Windows Reboot";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34713";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:36:"http://ma.tt/2010/06/windows-reboot/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:787:"<p>Dear Microsoft, every time you reboot my computer overnight without me having any interaction I lose unsaved documents and messages. It completely breaks my trust in a way that&#8217;s irreparable. <a href="http://ma.tt/2004/10/bizarre-windows-behavior/">It&#8217;s been six years since I first wrote about this</a>. At the time Robert Scoble saw my entry and apologized on his blog in a really heartfelt way. This meant more to me than you will ever know; it was the day I went from being a childish Slashdot-reading Micro$oft-hater to having great respect for a large company made up of individuals who made mistakes but had changed the world. Six years later, though, the bug is still there. Fool me once, shame on you, fool me twice&#8230; well, you can&#8217;t fool me again.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 09 Jun 2010 13:21:59 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:22;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:53:"Publisher Blog: The Independent Switches to WordPress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:42:"http://publisherblog.automattic.com/?p=959";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:85:"http://publisherblog.automattic.com/2010/06/08/the-independent-switches-to-wordpress/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2592:"<p>Great to see that all the blogs on <a href="http://blogs.independent.co.uk/">blogs.independent.co.uk</a> are now powered by WordPress:<br />\n<img src="http://s2.wp.com/mshots/v1/http%3A%2F%2Fblogs.independent.co.uk%2F?w=600&amp;r=1" alt="http://blogs.independent.co.uk/" width="600" /></p>\n<p>In a <a href="http://blogs.independent.co.uk/2010/06/08/why-have-we-changed-the-blogs-at-independent-co-uk/">blog post</a> from Online Editor Martin King, the reasons for the switch from Livejournal included the following:</p>\n<blockquote><p>\n* to continue pushing forward a site that is ever more social-media-friendly, incorporating our recently improved and well-received comments functionality;</p>\n<p>* to enable our posters to add quicker views and analysis more easily.</p>\n<p>The last point will be especially beneficial to The Independent’s overseas correspondents, with their busy and occasionally perilous lives. As long as they can send an email, that can be posted immediately, including any image.\n</p></blockquote>\n<p>Mark wraps up his post with a very insightful point, saying &#8220;We are demonstrating that globally standard programs can free mainstream journalism from the complex bespoke set-ups of the past.&#8221;</p>\n<p>[ Visit <a href="http://blogs.independent.co.uk/">http://blogs.independent.co.uk/</a> ]</p>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wordpresspublishers.wordpress.com/959/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wordpresspublishers.wordpress.com/959/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wordpresspublishers.wordpress.com/959/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wordpresspublishers.wordpress.com/959/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wordpresspublishers.wordpress.com/959/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wordpresspublishers.wordpress.com/959/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wordpresspublishers.wordpress.com/959/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wordpresspublishers.wordpress.com/959/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wordpresspublishers.wordpress.com/959/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wordpresspublishers.wordpress.com/959/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=publisherblog.automattic.com&blog=1470857&post=959&subd=wordpresspublishers&ref=&feed=1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 08 Jun 2010 20:00:01 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:16:"Raanan Bar-Cohen";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:23;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:42:"Dougal Campbell: Splintering the Community";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:33:"http://dougal.gunters.org/?p=2273";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:122:"http://dougal.gunters.org/blog/2010/06/08/splintering-the-community?utm_source=rss&amp;utm_medium=rss&amp;utm_campaign=rss";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:6806:"<div><img width="150" height="112" src="http://media.dougal.us.s3.amazonaws.com/wordpress/wp-content/uploads/2010/06/Earthquake_000007853860XSmall-150x112.jpg" class="attachment-post-thumbnail wp-post-image" alt="A Split in the Community" title="A Split in the Community" /></div><p>Recently, Arlen Beiler created a proposal for a <a href="http://area51.stackexchange.com/proposals/1500/wordpress-answers">WordPress Answers</a> site on the in-progress <a href="http://area51.stackexchange.com/faq">StackExchange</a> network, which is part of <a href="http://stackoverflow.com/">StackOverflow</a>. If you aren&#8217;t familiar with StackOverflow or any of its sister-sites, it&#8217;s a sort of Questions and Answers forum where good answers are voted up, and float to the top. There is also a reputation system which rewards users for being active and providing quality feedback. I was not previously an active member on any of the sites, but I had run across answers to some of my own questions in the past when using Google to search.</p>\n<p>I signed up on the WordPress Answers site, which is currently in a &#8216;discussion&#8217; phase, where it needs sample questions to help define the scope. I provided some questions of my own, voted on the &#8216;on-topic&#8217; or &#8216;off-topic&#8217; status for the sample questions, and provided feedback on many questions when I thought it was necessary to explain my opinion.</p>\n<p>Meanwhile, back on the wp-hackers mailing list, there was a flurry of responses, including some people concerned that catering to this additional site might &#8220;splinter the development community&#8221; between the <em>official</em> and <em>unofficial</em> sites.</p>\n<p><span id="more-2273"></span>When I first started looking at the StackExchange site, I mentioned it to <a href="http://www.digitaldivas.net/">my wife, Susan</a>. She likes WordPress, but she uses <a href="http://drupal.org/">Drupal</a> a lot at work. After noticing that nobody else had set up a Drupal proposal yet, she started <a href="http://area51.stackexchange.com/proposals/2978/drupal-answers">Drupal Answers</a>. Shortly after, someone asked why such a site would be needed, when there are already Drupal forums, and asked, &#8220;Is it good to splinter that effort?&#8221;</p>\n<p>Again with the &#8220;splintering&#8221; talk? Why does this particular project invite claims of dividing the community? I know that in the WordPress community, there are many other places besides the official support forums where users gather to ask questions and share information &#8211;<a href="http://weblogtoolscollection.com/news/"> Weblog Tools Collection</a>, <a href="http://www.wptavern.com/forum/">WP Tavern</a>, and <a href="http://stackoverflow.com/questions/tagged/wordpress">StackOverflow</a> just to name a few, and many plugins and themes have their own support venues, hosted by their creators. And I&#8217;m sure the same is true in the Drupal world. Why are these different, why no cries of &#8220;splintering the community&#8221; over these?</p>\n<p>So, what do you think? Is there really a problem with a support site for questions and answers, separate from the &#8220;official&#8221; support forums? What features make you want to use one over the other, or both? What is <em>your</em> favorite place to find answers?</p>\n<ul class="socialwrap size48 row">\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="delicious" href="http://delicious.com/post?url=http%3A%2F%2Fdougal.gunters.org%2Fblog%2F2010%2F06%2F08%2Fsplintering-the-community&amp;title=Splintering+the+Community" title="Bookmark this post : Splintering the Community on Delicious"><span class="head">Bookmark on Delicious</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="digg" href="http://digg.com/submit?url=http%3A%2F%2Fdougal.gunters.org%2Fblog%2F2010%2F06%2F08%2Fsplintering-the-community&#038;title=Splintering+the+Community&#038;bodytext=Recently%2C+Arlen+Beiler+created+a+proposal+for+a+WordPress+Answers+site+on+the+in-progress+StackExchange+network%2C+which+is+part+of+StackOverflow.+If+you+aren%27t+familiar+with+StackOverflow+or+any+of+its+sister-sites%2C+it%27s+a+sort+of+Questions+and+Answers+forum+where+good+answers+are+voted+up%2C+and+float+to+the+top.+There+i" title="Digg this post : Splintering the Community"><span class="head">Digg this post</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="facebook" href="http://www.facebook.com/sharer.php?u=http%3A%2F%2Fdougal.gunters.org%2Fblog%2F2010%2F06%2F08%2Fsplintering-the-community&amp;t=Splintering+the+Community" title="Recommend this post : Splintering the Community on Facebook"><span class="head"> Recommend on Facebook</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="google_buzz" href="http://www.google.com/reader/link?url=http%3A%2F%2Fdougal.gunters.org%2Fblog%2F2010%2F06%2F08%2Fsplintering-the-community&amp;title=Splintering+the+Community" title="Buzz up this post : Splintering the Community "><span class="head">Buzz it up</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="reddit" href="http://www.reddit.com/submit?url=http%3A%2F%2Fdougal.gunters.org%2Fblog%2F2010%2F06%2F08%2Fsplintering-the-community&amp;title=Splintering+the+Community" title="Share this post : Splintering the Community on Reddit"><span class="head">share via Reddit</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="stumble" href="http://www.stumbleupon.com/submit?url=http%3A%2F%2Fdougal.gunters.org%2Fblog%2F2010%2F06%2F08%2Fsplintering-the-community&amp;title=Splintering+the+Community" title="Share this post : Splintering the Community with Stumblers"><span class="head">Share with Stumblers</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="twitter" href="http://twitter.com/home/?status=http%3A%2F%2Fbit.ly%2FanEFWg" title="Tweet this post : Splintering the Community on Twitter"><span class="head">Tweet about it</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="rss" href="http://dougal.gunters.org/blog/2010/06/08/splintering-the-community/feed" title="Follow this post : Splintering the Community comments"><span class="head">Subscribe to the comments on this post</span></a></li>\n<li class="iconOnly"><a rel="_blank" class="email" href="mailto:?subject=Dougal Campbell&#039;s geek ramblings : Splintering the Community&#038;body=I thought you might be interested in this post from Dougal Campbell.   http://dougal.gunters.org/blog/2010/06/08/splintering-the-community" title="Tell a friend about this post : Splintering the Community "><span class="head">Tell a friend</span></a></li>\n</ul>\n<div class="clean"></div>\n\n\n<p>No related posts.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 08 Jun 2010 16:30:24 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Dougal";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:24;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:53:"WordPress.tv: Karl Fogel: Bodysurfing the Blogosphere";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://wordpress.tv/?p=3901";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:73:"http://wordpress.tv/2010/05/01/karl-fogel-audience-distributed-film-sf10/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1390:"<div id="x-video-5" class="video-player">\n\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/3901/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/3901/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wptv.wordpress.com/3901/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wptv.wordpress.com/3901/" /></a> <a rel="nofollow" href="http://