v.wordpress.com/3882/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wptv.wordpress.com/3882/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wptv.wordpress.com/3882/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wptv.wordpress.com/3882/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wptv.wordpress.com/3882/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wptv.wordpress.com/3882/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=3882&subd=wptv&ref=&feed=1" /><div><a href="http://wordpress.tv/2010/04/24/jane-wells-keynote-oc10/"><img alt="Jane Wells - WordCamp Orange County Keynote" src="http://cdn.videos.wordpress.com/ZN4lvlb3/jane-wells-wcoc-keynote_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 04 Jun 2010 05:15:08 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:11:"Ryan Markel";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:33;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:52:"Weblog Tools Collection: WordPress And Giving Credit";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://weblogtoolscollection.com/?p=8145";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:81:"http://weblogtoolscollection.com/archives/2010/06/03/wordpress-and-giving-credit/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2497:"<p>WordPress 3.0 is almost out the door and one of the most exciting developments regarding the new version is the menu management system. This system started as a major contribution from WooThemes with their WooNav code but since it&#8217;s integration, the WooNav code has been reworked practically line for line to the point where there is almost nothing left of the original. At the time, WooThemes was heralded as an awesome company for contributing such a great piece of functionality to the core of WordPress. I still believe it&#8217;s great they contributed WooNav to the menu system but now things get dicey when it comes to how much credit should be given to WooThemes.</p>\n<p>There have been a <a href="http://www.wptavern.com/woothemes-has-and-will-continue-to-get-credit" target="_blank">few posts discussing</a> the credit factor and WooThemes concerning the new menu system. Some people think WooThemes deserves more credit while others think that credit has been given where credit was due. Not only did WooThemes get a lot of press when they made the announcement of giving WooNav to the WordPress core team, but I imagine they will be among the list of all of the other contributors receiving props once WordPress 3.0 goes live. </p>\n<p>One thing I have not noticed since my foray into the WordPress community is individuals claiming &#8220;<i>I did this</i>&#8221; and &#8220;<i>I did that</i>&#8221; as if it put them on a higher place than everyone else. Most contributors have been just fine with props given in the major release posts. Again, I don&#8217;t think credit is the main motivator for contributors, it&#8217;s just the icing on the cake. I could be wrong though which I hope you&#8217;ll tell me in the comments.</p>\n<p>I have a few questions I want to ask to the wider community. For starters, is everyone that contributes to WordPress on a level playing field in terms of making the software better, or are certain people better than everyone else? Secondly, what do you consider to be adequate credit given to contributors. Third, if you have previous experience, why do you contribute to the WordPress project? Is it for personal gain or just to make the software better? </p>\n<p>The last question I have, do you think the WordPress project would get along just fine if the entire notion of giving props or any credit disappeared. That way, it&#8217;s all about the software, not about the people and their egos. Looking forward to reading your feedback.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 03 Jun 2010 21:18:25 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:13:"Jeff Chandler";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:34;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:23:"Matt: Gravatar Profiles";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34568";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:39:"http://ma.tt/2010/06/gravatar-profiles/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:413:"<p><a href="http://blog.gravatar.com/2010/06/02/public-profiles-for-everyone/">Gravatar profiles are now live</a>. The fun thing about these are that they look handy, every linked service is verified, they&#8217;re as easy to link as Gravatars (hash of email), and they&#8217;re as open as Gravatar, meaning that with the email hash you can get all information someone has made public, in any format you like.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 03 Jun 2010 06:25:22 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:35;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:48:"WordPress.tv: Lucy Beer: WordPress for Marketing";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://wordpress.tv/?p=3876";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:66:"http://wordpress.tv/2010/04/24/lucy-beer-wordpress-marketing-oc10/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1400:"<div id="x-video-11" class="video-player">\n\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/3876/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/3876/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wptv.wordpress.com/3876/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wptv.wordpress.com/3876/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wptv.wordpress.com/3876/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wptv.wordpress.com/3876/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wptv.wordpress.com/3876/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wptv.wordpress.com/3876/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wptv.wordpress.com/3876/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wptv.wordpress.com/3876/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=3876&subd=wptv&ref=&feed=1" /><div><a href="http://wordpress.tv/2010/04/24/lucy-beer-wordpress-marketing-oc10/"><img alt="Lucy Beer: WordPress for Marketing" src="http://cdn.videos.wordpress.com/ukovW1ov/regulartrack005_h264_896k_2997p_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 03 Jun 2010 04:45:46 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:11:"Ryan Markel";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:36;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:82:"Weblog Tools Collection: WordPress 3.0 Walkthrough: Getting Started with Multisite";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://weblogtoolscollection.com/?p=8138";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:75:"http://weblogtoolscollection.com/archives/2010/06/02/wordpress-3-multisite/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3847:"<p>WordPress 3.0 Walkthrough: Multsite</p>\n<p>Multisite is the most talked about new feature in WordPress 3.0 &#8211; the WordPress team has folded the functionality of WordPress Multiuser into the main WordPress project. So how do you use it?</p>\n<p>This tutorial assumes your are comfortable using FTP clients such as <a href="http://filezilla-project.org/">Filezilla</a> and doing basic edits of WordPress files.</p>\n<p>1. Download WordPress 3.0 release candidate. You can find it <a href="http://wordpress.org/development/2010/05/wordpress-3-0-release-candidate/">here</a>.</p>\n<p>2. Edit wp-config in your favorite text editor and add the following line:</p>\n<p>define(&#8216;WP_ALLOW_MULTISITE&#8217;, true);</p>\n<p>(I&#8217;d suggest adding it just above the line &#8220;// ** MySQL settings &#8211; You can get this info from your web host ** //&#8221;)</p>\n<p>3. Install WordPress normally</p>\n<p>NOTE: If you&#8217;ve already installed WordPress 3.0, just edit wp-config and add that line of code, there&#8217;s no need to re-install.</p>\n<p>4. Under Tools on the sidebar, you&#8217;ll now have an &#8220;Network&#8221; option. Click it.</p>\n<p><img src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/screenshot-0.jpg" alt="WordPress 3.0 Multisite Screenshot" title="WordPress 3.0 Multisite Screenshot" width="144" height="118" class="alignnone size-full wp-image-8139" /></p>\n<p>5. Here you&#8217;ll setup your &#8220;Network&#8221; &#8211; a Network is all the blogs or sites you&#8217;ll have under your WordPress install (if you&#8217;re migrating back to WordPress from WordPress Multiuser this might be confusing. In WordPress Multiuser the term for network was &#8220;site&#8221; and the term for site was &#8220;blog.&#8221; Explanation <a href="http://www.andrewnacin.com/2010/03/25/terminology-nightmare-blogs-sites-networks/">here</a>).</p>\n<p><img src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/screenshot-1.jpg" alt="WordPress 3.0 Multisite Screenshot" title="WordPress 3.0 Multisite Screenshot" width="611" height="226" class="alignnone size-full wp-image-8140" /></p>\n<p>If your host supports it, you&#8217;ll have the option here to choose between subdomains and subdirectories.</p>\n<p>Example of a subdomain: site1.yourdomain.com<br />\nExample of a subdirectory: yourdomain.com/site1</p>\n<p>Fill out your Network Title and Admin E-mail Address and press install.</p>\n<p>6. You&#8217;ll be greeted with your next list of steps: creating a blogs.dir directory, editing wp-config.php, and .htaccess. WP recommends, as do I, backing up wp-config.php and .htaccess files before proceeding.</p>\n<p>After completing the steps, you&#8217;ll need to log back into WordPress.</p>\n<p>7. On your next login, you&#8217;ll notice a new menu: &#8220;Super Admin.&#8221;</p>\n<p><img src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/screenshot-2.jpg" alt="WordPress 3.0 Multisite Screenshot" title="WordPress 3.0 Multisite Screenshot" width="149" height="168" class="alignnone size-full wp-image-8141" /></p>\n<p>8. Click &#8220;Sites&#8221; under this option to create a new site. Fill out the forms accordingly.</p>\n<p><img src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/screenshot-3.jpg" alt="WordPress 3.0 Multisite Screenshot" title="WordPress 3.0 Multisite Screenshot" width="414" height="300" class="alignnone size-full wp-image-8142" /></p>\n<p>9. After creating a new site, click Users. You&#8217;ll see a new user was created for the new site.</p>\n<p>10. You can control all sites on your network through the Super Admin menu, but for right now you might find it easier to administer individual sites through their own admin menus. You can access them as you would a normal wordpress site. In the example above, it would be: http://mydomain.net/malta/wp-admin</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 03 Jun 2010 04:30:20 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"Klint Finley";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:37;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:57:"WordPress.tv: Steve Zehngut: Real-Time Plugin Development";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://wordpress.tv/?p=3874";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:67:"http://wordpress.tv/2010/04/24/steve-zehngut-realtime-plugins-oc10/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1409:"<div id="x-video-10" class="video-player">\n\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/3874/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/3874/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wptv.wordpress.com/3874/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wptv.wordpress.com/3874/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wptv.wordpress.com/3874/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wptv.wordpress.com/3874/"