;b:0;s:8:"xml_lang";s:0:"";}}}}}i:42;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:41:"WordPress Podcast: WordPress does Windows";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:30:"http://wp-community.org/?p=550";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:63:"http://feedproxy.google.com/~r/wordpresspodcast/~3/A-g5swqmQpo/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2343:"<p>Josh Holmes is a UX Architect Evangelist at Microsoft.com,  where he works hard to bridge the gaps that exist in technology adoption and Microsoft  and open source projects. In the past, Josh used <a href="http://code.msdn.microsoft.com/DasBlogML">DasBlogML</a> and he migrated  it to WordPress quite easily. On the show, Josh shared with us many of the  projects and <a href="http://www.microsoft.com/web/wordpress/">contributions</a> Microsoft is making to the WordPress community.  Among those plugins created by the Microsoft  team is <a href="http://wordpress.org/extend/plugins/windows-azure-storage/">Windows  Azure Storage for WordPress</a> with is similar to Amazon Web Services or  Rackspace Cloudfiles. Among the more interesting was learning how WordPress can  be run using <a href="http://www.microsoft.com/web/wordpress/#tabs-2">Microsoft  SQL Serve</a>r for the database store as shown on sites like <a href="http://oddlyspecific.com/">oddlyspecific.com</a> for example with <a href="http://ruslany.net/2010/03/make-wordpress-faster-on-iis-with-wincache-1-1/">performance</a> <a href="http://blogs.iis.net/ksingla/archive/2010/05/27/wordpress-widget-to-show-wincache-statistics.aspx">enhancements</a>.  Josh also highlighted some of the steps Microsoft is taking to make deployment  of their technologies easier using the <a href="http://www.microsoft.com/web/downloads/platform.aspx">Microsoft Web  Platform</a>, which is quite a solid offering.</p>\n<p>For those of you that are diligent developers or up for a challenge  you may want to try the <a href="http://www.toughestdeveloperpuzzleever.com/begin/">Toughest Developer  Puzzle Ever</a>.</p>\n<p>In news:</p>\n<ul>\n<li>WordPress 3.0 <a href="http://wordpress.org/development/2010/05/wordpress-3-0-release-candidate/">release  candidate</a> is now available and looking good.</li>\n<li>Encourage <a href="http://alexking.org/blog/2010/05/31/youre-welcome">constructive feedback</a> for the developers that make the WordPress community so rich and free.</li>\n</ul>\n<p>Plugin picks of the week:</p>\n<ul>\n<li><a href="http://wordpress.org/extend/plugins/changelogger/">Changelogger Plugin</a></li>\n<li><a href="http://code.msdn.microsoft.com/DasBlogML">DasBlogML</a></li>\n</ul>\n<img src="http://feeds.feedburner.com/~r/wordpresspodcast/~4/A-g5swqmQpo" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 01 Jun 2010 22:40:33 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:54:"joost@pressthis.com (Joost de Valk & Frederick Townes)";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:43;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:25:"Matt: Ortaköy and beyond";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang