(138, '_transient_feed_867bd5c64f85878d03a060509cd2f92c', 'a:4:{s:5:"child";a:1:{s:0:"";a:1:{s:3:"rss";a:1:{i:0;a:6:{s:4:"data";s:3:"\n\n\n";s:7:"attribs";a:1:{s:0:"";a:1:{s:7:"version";s:3:"2.0";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:1:{s:0:"";a:1:{s:7:"channel";a:1:{i:0;a:6:{s:4:"data";s:61:"\n	\n	\n	\n	\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:1:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:16:"WordPress Planet";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:28:"http://planet.wordpress.org/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"language";a:1:{i:0;a:5:{s:4:"data";s:2:"en";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:47:"WordPress Planet - http://planet.wordpress.org/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"item";a:50:{i:0;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:31:"Donncha: WP Super Cache 0.9.9.2";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:29:"http://ocaoimh.ie/?p=89495918";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:39:"http://ocaoimh.ie/wp-super-cache-09912/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2616:"<p><a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL3dvcmRwcmVzcy5vcmcvZXh0ZW5kL3BsdWdpbnMvd3Atc3VwZXItY2FjaGUv">WP Super Cache</a> 0.9.9.2 has just been released! This version works with WordPress 3.0 and adds a number of new features and bug fixes:</p>\n<ul>\n<li><a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL29jYW9pbWguaWUvcHJlbG9hZC1jYWNoZS13cC1zdXBlci1jYWNoZS8=">Cache Preloading</a> will cache every post on your site.</li>\n<li> A cache tester that will check if your homepage is cached.</li>\n<li> Much better <a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL3dvcmRwcmVzcy5vcmcvc3VwcG9ydC90b3BpYy8zMzkwNzU/cmVwbGllcz0yNSNwb3N0LTE0OTM3Nzg=">support</a> for mobile plugins.</li>\n<li> Mod rewrite rules can now be updated from within the admin page.</li>\n<li> Lots and lots of bugs fixed. See the changelog for more details.</li>\n</ul>\n<p>Preloading creates lots of files on your server so if you have many thousands of posts please be aware of this. Filesystem limitations may cause problems if you use a flat permalink structure. For example, ext2 or <a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL2VuLndpa2lwZWRpYS5vcmcvd2lraS9FeHQz">ext3</a> only allows 32,000 directories in a directory. If you have more than that number of posts you may run into <a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL3dvcmRwcmVzcy5vcmcvc3VwcG9ydC90b3BpYy80MDAzNDg/cmVwbGllcz02">problems</a>.</p>\n<p>The plugin does not preload category or tag pages but because your single posts will be cached you&#8217;ll find the load on your server will be reduced. Uncached pages will be served more quickly and your visitors will have a quicker and better experience on your site.<br />\nYou may also see an increase in site traffic if your server was previously underpowered!</p>\n<p><strong>Related Posts</strong><ul><li><a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL29jYW9pbWguaWUvd3Atc3VwZXItY2FjaGUtMDg0LXRoZS1nYXJiYWdlLWNvbGxlY3Rvci8=" rel="">WP Super Cache 0.8.4, the garbage collector</a></li><li><a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL29jYW9pbWguaWUvd3Atc3VwZXItY2FjaGUtMDg3Lw==" rel="">WP Super Cache 0.8.7</a></li><li><a href="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?url=aHR0cDovL29jYW9pbWguaWUvd3Atc3VwZXItY2FjaGUtMDk5Lw==" rel="">WP Super Cache 0.9.9</a></li></ul></p> <img src="http://ocaoimh.ie/wp-content/plugins/feed-statistics.php?view=1&post_id=89495918" width="1" height="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 15 Jun 2010 13:38:28 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:7:"Donncha";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:1;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:63:"Dougal Campbell: The Business of WordPress Conference (Atlanta)";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:33:"http://dougal.gunters.org/?p=2294";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:141:"http://dougal.gunters.org/blog/2010/06/15/the-business-of-wordpress-conference-atlanta?utm_source=rss&amp;utm_medium=rss&amp;utm_campaign=rss";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:6453:"<div><img width="150" height="38" src="http://media.dougal.us.s3.amazonaws.com/wordpress/wp-content/uploads/2010/06/business-of-wp-150x38.gif" class="attachment-post-thumbnail wp-post-image" alt="The Business of WordPress" title="The Business of WordPress" /></div><p>This may be kind of short notice, but those of you near Atlanta might be interested in the <a href="http://www.thebusinessof.net/wordpress/">Business of WordPress Conference</a>, taking place next week (June 22-23, 2010). The venue is the <a href="http://www.gtri.gatech.edu/conference-center">Georgia Tech Research Institute&#8217;s Conference Center</a>, on 14th Street (Midtown). This conference is aimed at non-technical users who are interested in learning more about the benefits of using WordPress to drive a business web site.</p>\n<blockquote cite="http://www.thebusinessof.net/wordpress/about/"><p>Over the past few decades the web has become an essential tool for business yet until recently it’s been very costly to continuously embrace the benefits the web has to offer business. Most small-to-medium sized businesses, departments in larger companies, non-profits and local and regional government agencies have just “<em>made do</em>” and not gained most of the benefits the web has to offer. <em>Fortunately, WordPress changes all that.</em> WordPress has emerged as <em>the defacto-web presence platform for business</em> and not learning what WordPress has to offer presents a huge opportunity lost cost.</p></blockquote>\n<p>This conference bills itself as having a &#8220;curated&#8221; agenda, meaning that the topics were chosen first, and presenters chosen based on the topics, rather than the other way around. Some of the talks will cover subjects like: eCommerce, choosing a consultant/agency, social media, membership sites, and incorporating photos and video.</p>\n<p>Keep in mind that this is a paid, professional conference, not a WordCamp or other low-cost un-conference type of event. However, as professional conferences go, admission cost is pretty reasonable ($299 for the main conference day, $399 if you also want access to the &#8220;Boardroom Pass&#8221; roundtables on both days).</p>\n<p>Disclaimer: there is a paid ad on this site for the conference, but I had planned to write something about it before I ever knew that the ad was going to be placed. Also, I would have liked to attend the event, myself, but will be unable to do so, due to timing issues.</p>\n<ul class="socialwrap size48 row">\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="delicious" href="http://delicious.com/post?url=http%3A%2F%2Fdougal.gunters.org%2Fblog%2F2010%2F06%2F15%2Fthe-business-of-wordpress-conference-atlanta&amp;title=The+Business+of+WordPress+Conference+%28Atlanta%29" title="Bookmark this post : The Business of WordPress Conference (Atlanta) on Delicious"><span class="head">Bookmark on Delicious</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="digg" href="http://digg.com/submit?url=http%3A%2F%2Fdougal.gunters.org%2Fblog%2F2010%2F06%2F15%2Fthe-business-of-wordpress-conference-atlanta&#038;title=The+Business+of+WordPress+Conference+%28Atlanta%29&#038;bodytext=This+may+be+kind+of+short+notice%2C+but+those+of+you+near+Atlanta+might+be+interested+in+the+Business+of+WordPress+Conference%2C+taking+place+next+week+%28June+22-23%2C+2010%29.+The+venue+is+the+Georgia+Tech+Research+Institute%27s+Conference+Center%2C+on+14th+Street+%28Midtown%29.+This+conference+is+aimed+at+non-technical+users+who+are+" title="Digg this post : The Business of WordPress Conference (Atlanta)"><span class="head">Digg this post</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="facebook" href="http://www.facebook.com/sharer.php?u=http%3A%2F%2Fdougal.gunters.org%2Fblog%2F2010%2F06%2F15%2Fthe-business-of-wordpress-conference-atlanta&amp;t=The+Business+of+WordPress+Conference+%28Atlanta%29" title="Recommend this post : The Business of WordPress Conference (Atlanta) on Facebook"><span class="head"> Recommend on Facebook</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="google_buzz" href="http://www.google.com/reader/link?url=http%3A%2F%2Fdougal.gunters.org%2Fblog%2F2010%2F06%2F15%2Fthe-business-of-wordpress-conference-atlanta&amp;title=The+Business+of+WordPress+Conference+%28Atlanta%29" title="Buzz up this post : The Business of WordPress Conference (Atlanta) "><span class="head">Buzz it up</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="reddit" href="http://www.reddit.com/submit?url=http%3A%2F%2Fdougal.gunters.org%2Fblog%2F2010%2F06%2F15%2Fthe-business-of-wordpress-conference-atlanta&amp;title=The+Business+of+WordPress+Conference+%28Atlanta%29" title="Share this post : The Business of WordPress Conference (Atlanta) on Reddit"><span class="head">share via Reddit</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="stumble" href="http://www.stumbleupon.com/submit?url=http%3A%2F%2Fdougal.gunters.org%2Fblog%2F2010%2F06%2F15%2Fthe-business-of-wordpress-conference-atlanta&amp;title=The+Business+of+WordPress+Conference+%28Atlanta%29" title="Share this post : The Business of WordPress Conference (Atlanta) with Stumblers"><span class="head">Share with Stumblers</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="twitter" href="http://twitter.com/home/?status=http%3A%2F%2Fbit.ly%2F9lp5O4" title="Tweet this post : The Business of WordPress Conference (Atlanta) on Twitter"><span class="head">Tweet about it</span></a></li>\n<li class="iconOnly"><a rel="nofollow" target="_blank" class="rss" href="http://dougal.gunters.org/blog/2010/06/15/the-business-of-wordpress-conference-atlanta/feed" title="Follow this post : The Business of WordPress Conference (Atlanta) comments"><span class="head">Subscribe to the comments on this post</span></a></li>\n<li class="iconOnly"><a rel="_blank" class="email" href="mailto:?subject=Dougal Campbell&#039;s geek ramblings : The Business of WordPress Conference (Atlanta)&#038;body=I thought you might be interested in this post from Dougal Campbell.   http://dougal.gunters.org/blog/2010/06/15/the-business-of-wordpress-conference-atlanta" title="Tell a friend about this post : The Business of WordPress Conference (Atlanta) "><span class="head">Tell a friend</span></a></li>\n</ul>\n<div class="clean"></div>\n\n\n<p>No related posts.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 15 Jun 2010 12:49:31 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Dougal";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:2;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:63:"Publisher Blog: Levi’s Selects WordPress for Pioneer Sessions";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:42:"http://publisherblog.automattic.com/?p=966";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:80:"http://publisherblog.automattic.com/2010/06/15/levis-wordpress-pioneer-sessions/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2102:"<p>Exciting news that <a href="http://levi.com">Levi&#8217;s</a> has just launched a new site, <a href="http://www.levispioneersessions.com/">Pioneer Sessions</a>,  using <a href="http://wordpress.org">WordPress</a> to showcase &#8220;pioneering musicians from rock, pop, soul, and rap to re-craft the classic songs that inspired their sound&#8221;:<br />\n<a href="http://www.levispioneersessions.com"><img src="http://s2.wp.com/mshots/v1/http%3A%2F%2Fwww.levispioneersessions.com%2F?w=600&amp;r=1" alt="http://www.levispioneersessions.com/" width="600" /></a></p>\n<p>Conceived by <a href="http://cornerstonepromotion.com">Cornerstone</a> and designed by <a href="http://www.wk.com/">Wieden+Kennedy</a>, this site is definitely worth checking-out.</p>\n<p>[ Visit <a href="http://www.levispioneersessions.com">levispioneersessions.com</a> ]</p>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wordpresspublishers.wordpress.com/966/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wordpresspublishers.wordpress.com/966/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wordpresspublishers.wordpress.com/966/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wordpresspublishers.wordpress.com/966/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wordpresspublishers.wordpress.com/966/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wordpresspublishers.wordpress.com/966/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wordpresspublishers.wordpress.com/966/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wordpresspublishers.wordpress.com/966/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wordpresspublishers.wordpress.com/966/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wordpresspublishers.wordpress.com/966/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=publisherblog.automattic.com&blog=1470857&post=966&subd=wordpresspublishers&ref=&feed=1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 15 Jun 2010 07:07:06 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:16:"Raanan Bar-Cohen";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:3;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:69:"WordPress.tv: Daniel Cook: Why We Turned Microsoft Office into a Game";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://wordpress.tv/?p=3948";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:70:"http://wordpress.tv/2010/05/01/daniel-cook-microsoft-office-game-sf10/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1405:"<div id="x-video-6" class="video-player">\n\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/3948/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/3948/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wptv.wordpress.com/3948/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wptv.wordpress.com/3948/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wptv.wordpress.com/3948/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wptv.wordpress.com/3948/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wptv.wordpress.com/3948/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wptv.wordpress.com/3948/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wptv.wordpress.com/3948/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wptv.wordpress.com/3948/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=3948&subd=wptv&ref=&feed=1" /><div><a href="http://wordpress.tv/2010/05/01/daniel-cook-microsoft-office-game-sf10/"><img alt="Daniel Cook - Why We Turned Microsoft Office into a Game" src="http://cdn.videos.wordpress.com/Ck9iKdF7/daniel-cook_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 15 Jun 2010 06:45:06 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:11:"Ryan Markel";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:4;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:27:"Alex King: WordCamp Boulder";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://alexking.org/?p=4417";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:52:"http://alexking.org/blog/2010/06/14/wordcamp-boulder";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:4115:"<p>The tickets for <a href="http://2010.boulder.wordcamp.org" rel="external">WordCamp Boulder 2010</a> went on sale today. The discounted early bird tickets have been flying off the shelves &#8211; it&#8217;s great to see such an enthusiastic response from our local tech community.</p>\n<p>I wanted to publish a quick Q &#038; A to answer a few things I&#8217;ve seen circling around:</p>\n<dl>\n<dt>What is included in the ticket price?</dt>\n<dd>Your ticket gives you access to all event sessions, the Genius Bar (staffed in part by <a href="http://wphelpcenter.com">WordPress HelpCenter</a>) the after-party as well as lunch and a snazzy t-shirt.</dd>\n<dt>Will the event sell out?</dt>\n<dd>It&#8217;s hard to say for sure, but last year&#8217;s WordCamp (the first in the Denver/Boulder area) sold out and we sadly had to turn folks away at the doors if they didn&#8217;t have a ticket. We&#8217;ve already seen that this year&#8217;s event has a lot more inertia than last year&#8217;s did. I do expect we will sell out and recommend buying a ticket ASAP.</dd>\n<dt>Where can I buy a ticket?</dt>\n<dd><a href="http://wordcampcolorado.eventbrite.com/" rel="external">Right here</a>.</dd>\n<dt>How can I get the latest news about WordCamp Boulder on Twitter?</dt>\n<dd>Follow <a href="http://twitter.com/wordcampboulder" rel="external">@WordCampBoulder</a></dd>\n<dt>What happened to WordCamp Denver?</dt>\n<dd>We&#8217;ve moved it to Boulder this year. There are great tech communities in both Denver and Boulder, it just made sense to have it in Boulder this year since we had it in Denver last year.</dd>\n<dt>Does this mean it will be in Denver next year?</dt>\n<dd>That&#8217;s the current thinking, though we are always happy to hear feedback from the community about location, venue, content, etc. for the event. After all, it is an event for the community &#8211; we want your help in shaping it.</dd>\n<dt>How can I provide useful feedback to help shape this year&#8217;s WordCamp?</dt>\n<dd>We have a <a href="http://polldaddy.com/s/0FF04C4ACF55FF0B" rel="external">survey</a> you can fill out. Also, feel free to <a href="http://2010.boulder.wordcamp.org/contact/" rel="external">get in touch</a> with any thoughts, idea and/or concerns you want to make sure we take into consideration.</dd>\n<dt>I want to help, what can I do?</dt>\n<dd>We can aways use more great volunteers, <a href="http://2010.boulder.wordcamp.org/speakers/" rel="external">speakers</a> and <a href="http://2010.boulder.wordcamp.org/sponsors/" rel="external">sponsors</a>. Please <a href="http://2010.boulder.wordcamp.org/contact/" rel="external">get in touch</a> and we&#8217;ll be glad to work with you.</dd>\n<dt>What can you tell me a little about the venue?</dt>\n<dd>We&#8217;re going to try <a href="http://2010.boulder.wordcamp.org/locations/" rel="external">something a little different</a> this year. Our main stage will be at the <a href="http://bouldertheather.com" rel="external">Boulder Theater</a>. This will be the location for morning check in and for the larger presentations. We will also be having smaller discussion and technical sessions at the <a href="http://techstars.org" rel="external">TechStars Bunker</a> and <a href="http://atlaspurveyors.com" rel="external">Atlas Purveyors</a>. We are hoping that the addition of these smaller venues will allow for those some sessions to be more interactive and hands-on.</dd>\n<dt>Is the WiFi going to work this year?</dt>\n<dd>We sure hope so. We can&#8217;t promise anything, but we have already taken steps to try and ensure we have great connectivity this year. Also, we should have better cell signal available in these venues.</dd>\n<dt>Will there be a live stream of the event?</dt>\n<dd>Probably not. We do plan to have videos posted on WordPress.tv after the event.</dd>\n</dl>\n<p>I&#8217;m quite looking forward to the event. We learned a great deal last year and received a bunch of valuable feedback &#8211; hopefully that will manifest itself in a stellar WordCamp Boulder 2010.</p>\n<img src="http://alexking.org/wp/?ak_action=api_record_view&id=4417&type=feed" alt="" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 14 Jun 2010 23:18:20 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Alex";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:5;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:26:"Matt: Packing for Montreal";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34730";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:42:"http://ma.tt/2010/06/packing-for-montreal/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:517:"<p><a href="http://ma.tt/2010/06/to-montreal/">As I mentioned the other day</a>, I&#8217;m going to Montreal for about a month and a half, maybe two months. I <a href="http://matt.wordpress.com/2010/06/14/packing/">posted to my moblog about packing</a> and Hanni asked what the final manifest would look like. <a href="http://matt.wordpress.com/2010/06/14/more-packing-with-breakdown/">Hear is a breakdown of everything I&#8217;m taking for the 1.5-2 month trip</a>, which is about 4x what I normally travel with.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 14 Jun 2010 18:43:06 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:6;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:21:"Matt: Twitter in Iran";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34728";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:37:"http://ma.tt/2010/06/twitter-in-iran/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:469:"<p><a href="http://www.foreignpolicy.com/articles/2010/06/07/the_twitter_revolution_that_wasnt?sms_ss=reddit">The Twitter Devolution</a> questions some of the assumptions we all had about Twitter&#8217;s role in the <a href="http://helpiranelection.com/">&#8220;green revolution&#8221; of Iran</a>. For the record, I didn&#8217;t shade <a href="http://twitter.com/photomatt">my Twitter picture</a> green because it&#8217;s pink and they would combine to make brown.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 14 Jun 2010 14:59:44 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:7;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:44:"Alex King: Twitter Tools and OAuth Continued";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://alexking.org/?p=4415";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:69:"http://alexking.org/blog/2010/06/13/twitter-tools-and-oauth-continued";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:4423:"<p>I didn&#8217;t post many details in my <a href="http://alexking.org/blog/2010/06/10/twitter-tools-oauth-update">previous update</a>, and I&#8217;d like to visit some of them now. At the time that post was written, it looked like the user experience for Twitter Tools was going to look something like this:</p>\n<ol>\n<li>Download, install and activate Twitter Tools.</li>\n<li>Click a link to twitter.com where you would have to <a href="http://dev.twitter.com/apps/new" rel="external">register your WordPress site as an application</a>.</li>\n<li>Take the two keys provided to you and go back to the Twitter Tools settings page. Copy-paste those keys into fields in the Twitter Tools admin page.</li>\n<li>Click another link to again visit twitter.com, this time to do the OAuth handshake and get your authentication tokens.</li>\n<li>Return to your WordPress admin and continue tweaking your settings, etc.</li>\n</ol>\n<p>If you were able to succeed in these steps, everything would be set up.</p>\n<p>The fact that I as a developer look at those steps and groan was an immediate red flag to me. I know all too well from years of email support questions that not all WordPress users are highly technical and a 4 step process with 2 steps that make you change sites and one that includes a copy-paste dance isn&#8217;t something that is going to make people happy.</p>\n<p>Some people have suggested that <a href="http://alexking.org/blog/2010/06/10/twitter-tools-oauth-update#comment-136426">this is just how it is and I have to deal with it</a>. I disagree. When I see something that&#8217;s too hard I want to fix it, not perpetuate it. I sent an email outlining my concerns to the Twitter API team. They are smart folks, clearly they had been working on solutions for this situation as well. They have posted a proposed <a href="http://groups.google.com/group/twitter-development-talk/browse_thread/thread/c18ade9d86c8b239" rel="external">outline of a different workflow</a> that looks to be an improvement over the previous situation. It&#8217;s an improvement, but it&#8217;s not enough.</p>\n<p>I added the following to the thread:</p>\n<blockquote><p>This is excellent news and sounds like a much better user experience  than the previously discussed options. I would like to suggest it be taken one step further. Could the encoded string with the keys be returned programatically to the Open Source application instead of asking the user to copy/paste? This way the user experience would be very similar to a standard OAuth transaction.</p></blockquote>\n<p>I really hope they make this change and provide the string with the tokens via a callback method/URL and allow us to completely skip the copy-paste step.</p>\n<p>I don&#8217;t pretend to have thought through every situation that the Twitter API team is having to consider here. I&#8217;m focused squarely on my own little use case. My goal is simple: make the process of installing and configuring Twitter Tools as easy as possible for my WordPress users.</p>\n<p>With what they have outlined and my suggestion above, I am hopeful that I will be able to support a user experience that looks something like this:</p>\n<ol>\n<li>Download, install and activate Twitter Tools.</li>\n<li>Click a button in the WordPress admin that registers your site with twitter.com and returns the necessary tokens to Twitter Tools.</li>\n<li>Click another link to again visit twitter.com, this time to do the OAuth handshake and get your authentication tokens.</li>\n<li>Return to your WordPress admin and continue tweaking your settings, etc.</li>\n</ol>\n<p>The OAuth step is going to be required &#8211; there isn&#8217;t a way around that (and shouldn&#8217;t be). However I want the rest of the connection stuff should be as painless as possible for my users.</p>\n<p>If you care about this, you might want to drop the Twitter API team a line (api@twitter.com or @twitterAPI) and encourage them to go one step further in their proposed implementation so that Twitter Tools can give you the easiest possible configuration experience.</p>\n<p>My guess is that the <a href="http://countdowntooauth.com/" rel="external">OAuth deadline</a> will be extended while this new API is being implemented and tested. I am currently holding off on my Twitter Tools integration until I see where things end up.</p>\n<img src="http://alexking.org/wp/?ak_action=api_record_view&id=4415&type=feed" alt="" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sun, 13 Jun 2010 21:43:33 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Alex";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:8;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:59:"Weblog Tools Collection: WordPress Theme Releases for 06/13";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://weblogtoolscollection.com/?p=8174";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:87:"http://weblogtoolscollection.com/archives/2010/06/13/wordpress-theme-releases-for-0613/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:4258:"<p>Good morning everyone. Hope you are having a great weekend. For your Sunday morning reading pleasure we bring you the latest installment of WordPress Theme Releases. Enjoy!</p>\n<h4><a title="Tumblelog Reloaded: www.polaraul.com" href="http://www.polaraul.com/2010/06/tumblelog-reloaded-theme-for-wordpress/">Tumblelog Reloaded</a></h4>\n<p><img src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/tumblelogReloaded.png" alt="" title="tumblelogReloaded" class="alignnone size-full wp-image-8175" height="150" width="200" /></p>\n<p>Tumblelog Reloaded is the 4th theme from UK-based Polaraul Themes that we&#8217;ve featured here at WLTC. This theme is a rework of the Tumblelog theme by Safirul Alredha. Some of its features include:</p>\n<ul>\n<li>custom page to post photo, quote, link, chat and video</li>\n<li>automatically format each post based on post type</li>\n<li>automatically resize large images/photos</li>\n<li>microformats hAtom and xFolk friendly</li>\n</ul>\n<p>It also comes with a theme uninstaller.</p>\n<h4><a href="http://www.themesheep.com/display/themes/free-themes/the-daily-edition/" title="The Daily Edition: www.themesheep.com">The Daily Edition</a></h4>\n<p><img src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/TheDailyEdition.png" alt="" title="TheDailyEdition" class="alignnone size-full wp-image-8176" height="150" width="200" /></p>\n<p>The Daily Edition from Theme Sheep is a magazine-style theme that comes shipped with a whopping 7 different colour schemes to choose from.  It has built-in pagination and breadcrumb navigation as well as &#8220;related posts&#8221; and features some cool animated social bookmarking icons. From the theme&#8217;s options page you can do all sorts of things such as:</p>\n<ul>\n<li>Include links to your RSS feed, Feedburner feed, Facebook page and Twitter page</li>\n<li>Include some custom CSS</li>\n<li>Include some custom footer content</li>\n<li>Select your colour scheme</li>\n<li>Select how many large posts to display on your front page. You can also decide how to display those posts &#8211; either full content or excerpts. If you choose excerpts you can even decide what length of excerpt you want.</li>\n<li>Select how many small posts to display on your front page. As is the case with the large posts, you can decide if you want to show full content or excerpts including the desired length of excerpts.</li>\n</ul>\n<p>These are just a few features. There are many more.</p>\n<h4><a href="http://intention.paycheckworld.com/" title="Intention: paycheckworld.com">Intention</a></h4>\n<p><img src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/intention.png" alt="" title="intention" class="alignnone size-full wp-image-8177" height="150" width="200" /></p>\n<p>Intention is a sharp-looking 2 column theme with a widgetized right sidebar and sports a horizontal navigation drop down menu for displaying pages.</p>\n<h4><a href="http://www.wpexplorer.com/minimal-xpert-wordpress-theme.html" title="Minimal Xpert: www.wpexplorer.com">Minimal Xpert</a></h4>\n<p><img src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/minimal-xpert.png" alt="" title="minimal-xpert" class="alignnone size-full wp-image-8178" height="160" width="200" /></p>\n<p>Don&#8217;t let the name or appearance of this theme fool you. It may have a minimalistic look but contains oodles of goodies under the hood. From the theme&#8217;s slick options page, some of the things you can do are:</p>\n<ul>\n<li>Include a custom favicon</li>\n<li>Enable/disable thumbnails on both the home page and individual post pages</li>\n<li>Enable/disable the home page slider</li>\n<li>Exclude pages/categories from the horizontal nav menus</li>\n<li>Enable/disable the &#8220;related posts&#8221; feature</li>\n<li>Activate/deactivate the sidebar advertisement block</li>\n</ul>\n<p>You can even elect to activate/deactivate the &#8220;extended footer&#8221; feature. When activated, your site will display a 4 column footer containing an &#8220;about me&#8221; section, a list of recent posts, a blogroll and your Twitter stream.</p>\n<p>We hope you have enjoyed this edition of WordPress Theme Releases. As always, you&#8217;re welcome to share your thoughts with us. We value your feedback.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sun, 13 Jun 2010 08:18:29 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:11:"Len Kutchma";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:9;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:60:"Weblog Tools Collection: WordPress Plugin Releases for 06/13";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://weblogtoolscollection.com/?p=8171";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:90:"http://weblogtoolscollection.com/archives/2010/06/13/wordpress-plugin-releases-for-0613-2/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1981:"<p>Good morning everyone. Here are the latest and greatest (as well as updated) WordPress plugins.</p>\n<h3>New Plugins</h3>\n<p><a href="http://wordpress.org/extend/plugins/cms-tree-page-view/">CMS Tree Page View</a><br />\nInserts a menu heading under Pages in the backend where you can see a tree-like view of your pages ala Windows Explorer.</p>\n<p><a href="http://wordpress.org/extend/plugins/simple-fields/">Simple Fields</a><br />\nReplace the WordPress default custom fields with your own such as textareas, check boxes, radio buttons, files etc. Requires WordPress 3.0 to function. (has been tested on WordPress 3.0 RC 1)</p>\n<p><a href="http://wordpress.org/extend/plugins/content-audit/">Content Audit</a><br />\nCreate a content inventory where you can mark content as redundant, outdated, trivial, or in need of a review for SEO or style. Requires WordPress 3.0 to function.</p>\n<p><a href="http://wordpress.org/extend/plugins/contemplate/">Contemplate</a><br />\nInsert custom content in posts, pages, widgets, and comments via a shortcode. Handy for managing commonly used blocks of content.</p>\n<p><a href="http://www.dynamicwp.net/plugins/free-plugin-dynamicwp-image-cube/">DynamicWP Image Cube</a><br />\nShow off your images as an animated cube.</p>\n<h3>Updated Plugins</h3>\n<p><a href="http://wordpress.org/extend/plugins/author-exposed/">Author Exposed</a><br />\nDisplays author info in a cool pop-up.</p>\n<p><a href="http://wordpress.org/extend/plugins/seo-ultimate/">SEO Ultimate</a><br />\nAll-in-one SEO plugin that lets you set title tags, meta, no index/nofollow, canonicalization, 404s, slugs, autolinks, and more.</p>\n<p><a href="http://wordpress.org/extend/plugins/table-of-contents-creator/">Table of Contents Creator</a><br />\nNot just another sitemap plugin. Sort results by Menu Order, Alphabetically, Post Date or Author. Show only titles or include a short excerpt. Comes with a choice of 5 different icon sets or choose to not display icons at all.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sun, 13 Jun 2010 07:52:56 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:11:"Len Kutchma";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:10;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:24:"Matt: WP-guided Missiles";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34724";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:39:"http://ma.tt/2010/06/wp-guided-missles/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:229:"<p><a href="http://www.viper007bond.com/2010/06/12/so-apparently-wordpress-can-guide-missles/">So Apparently WordPress Can Guide Missiles</a>, some WordPress Javascript makes a guest appearance on-screen in a British TV show.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 12 Jun 2010 16:29:52 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:11;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:26:"Matt: No Paradox of Choice";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34721";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:42:"http://ma.tt/2010/06/no-paradox-of-choice/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:642:"<p><a href="http://www.ft.com/cms/s/2/9cebd444-cd9c-11de-8162-00144feabdc0.html">Financial Times: Given the choice, how much choice would you like?</a> A refutation of the &#8220;so-called paradox of choice [that] is one of the most overrated and incorrectly cited results in the social sciences&#8221; <a href="http://www.marginalrevolution.com/marginalrevolution/2009/11/the-paradox-of-choice-is-not-robust.html">according to Tyler Cowen</a>. <cite>Hat tip: <a href="http://ryanholiday.net/">Ryan Holiday</a> in <a href="http://www.fourhourworkweek.com/blog/2010/06/09/choice-effect-why-are-you-single/">Tim&#8217;s comments</a>.</cite></p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 11 Jun 2010 23:13:29 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:12;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:17:"Matt: To Montreal";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=34719";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:33:"http://ma.tt/2010/06/to-montreal/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:458:"<p>On Monday I&#8217;m going to be leaving San Francisco to spend some time in Montreal, about a month and a half. I really enjoyed my time there last year for the <a href="http://www.montrealjazzfest.com/default-en.aspx">Jazz Festival</a> hence the extended stay this year. I&#8217;m looking forward to seeing all the bloggers, WordPress users, friends, and entrepreneurs there. I&#8217;m also hoping a WordCamp can happen while I&#8217;m in town again.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 11 Jun 2010 21:28:38 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:13;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:17:"Dev Blog: 3.0 RC3";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://wordpress.org/development/?p=1376";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:49:"http://wordpress.org/development/2010/06/3-0-rc3/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:437:"<p>A weekend present, in haiku:</p>\n<blockquote><p>Last call; final bugs<br />\nItch, scratch, contort; calmly wait<br />\nFor now: <a href="http://wordpress.org/wordpress-3.0-RC3.zip">RC3 </a></p></blockquote>\n<p>That&#8217;s right. What will hopefully be the final release candidate, <a href="http://wordpress.org/wordpress-3.0-RC3.zip">RC3, is now available for download</a> and testing.</p>\n<p>Plugin developers: test your plugins!</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 11 Jun 2010 20:49:38 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:10:"Jane Wells";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:14;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:54:"Weblog Tools Collection: IDrive for WordPress Released";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:40:"http://weblogtoolscollection.com/?p=8169";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:83:"http://weblogtoolscollection.com/archives/2010/06/10/idrive-for-wordpress-released/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:5177:"<p><a href="http://weblogtoolscollection.com/wp-content/uploads/2010/06/idrivelogo.png" rel="thumbnail"><img title="idrivelogo" border="0" alt="idrivelogo" src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/idrivelogo_thumb.png" width="168" height="86" /></a> </p>\n<p>There are 119 plug-ins in the WordPress Extend site that have the words <em>backup</em> and <em>database</em> in the descriptions.&#160; That in turn makes for a lot of options when it comes to backing up your critical data for your WordPress based website.</p>\n<p>A recent addition to the mix not only offers you a backup solution but they offer you a backup solution in the cloud.</p>\n<p>The <a href="http://www.idrive.com/wordpress.htm">IDrive WordPress plug-in</a> allows you access to your IDrive backup account and it works with either the free basic account or a paid account.&#160; The free account offers up to 2GB of storage which should accommodate most sites.&#160; If you need more space you can get their entry level paid account for less than $5 per month that allows you to store up to 150GB.</p>\n<p>Here is a description of the plug-in and its features from the developers:</p>\n<blockquote><p><strong>IDrive Plug-in for Wordpress</strong> is an easy to use backup utility, designed specifically to backup Wordpress blog data into your IDrive online backup account. It provides scheduled as well as immediate backup of Wordpress blog data including files and MySQL database dump. </p>\n<p>Features</p>\n<ul>\n<li>Immediate backup of Wordpress blog data, both files as well as MySQL data dump, into your IDrive online backup account </li>\n<li>Scheduled backups occur after 12 midnight every day </li>\n<li>Immediate restore of backed up data from your IDrive online backup account </li>\n<li><strong>Smart backup</strong> &#8211; Only the first backup transfers entire Wordpress content, subsequent backups are incremental where only the modified data is backed up </li>\n<li>Automatic notification via email on backup / restore status </li>\n<li>Secure transfer of data to IDrive server using SSL. Non SSL transfer option is also available for non SSL servers </li>\n<li>Detailed logging of backup / restore operations </li>\n</ul>\n<p><img border="0" src="http://www.idrive.com/images/ide_spacer.gif" width="1" height="20" />System Requirements</p>\n<ul>\n<li>Wordpress 2.8.5 or higher hosted on a Linux / Unix system. Wordpress blog hosted on a Windows system is not supported </li>\n<li>Javascript enabled web browser &#8211; IE, Safari, Firefox, Chrome </li>\n<li>Admin access to Wordpress dashboard to activate the Plug-in </li>\n<li>PHP 5.1 or higher </li>\n</ul>\n</blockquote>\n<p>Installation is just like any other plug-in.&#160; Once installed and activated look under the <em>Settings</em> menu in your WordPress Admin site and click on <em>IDrive</em>.</p>\n<p><a href="http://weblogtoolscollection.com/wp-content/uploads/2010/06/idrive1.png" rel="thumbnail"><img title="idrive1" border="0" alt="idrive1" src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/idrive1_thumb.png" width="244" height="123" /></a> </p>\n<p>The main IDrive screen. If you have already signed up for your account just enter your username and password. If you need an account click the <em>Create New IDrive Account</em> link.</p>\n<p><a href="http://weblogtoolscollection.com/wp-content/uploads/2010/06/idrive2.png" rel="thumbnail"><img title="idrive2" border="0" alt="idrive2" src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/idrive2_thumb.png" width="244" height="118" /></a></p>\n<p>Fill this form out to create your new account and once it is submitted you will be signed in and able to setup your backups.</p>\n<p><a href="http://weblogtoolscollection.com/wp-content/uploads/2010/06/idrive3.png" rel="thumbnail"><img title="idrive3" border="0" alt="idrive3" src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/idrive3_thumb.png" width="244" height="208" /></a> </p>\n<p>This is a very self-explanatory form to setup your backup periodicity as well as just a couple of options. The backup triggers after midnight on the days it is scheduled.</p>\n<p><a href="http://weblogtoolscollection.com/wp-content/uploads/2010/06/idrive4.png" rel="thumbnail"><img title="idrive4" border="0" alt="idrive4" src="http://weblogtoolscollection.com/wp-content/uploads/2010/06/idrive4_thumb.png" width="244" height="143" /></a> </p>\n<p>The second tab on the main screen allows you to see the logs related to any activity with your backups and account.</p>\n<p>I started up an initial backup of <a href="http://www.windowsobserver.com/">WindowsObserver.com</a> and 7,460 files were identified for backup. After 10 minutes only 80 of those files had been backed up.&#160; At that pace 480 files will be backed up an hour and that means it could take over 15 hours to do this backup process.&#160; I will post a note in the comments to verify how long this back up actually took once it is done!</p>\n<p>At least subsequent backups will be incremental and only effect data and files that have changed.&#160; I did not notice any impact browsing on my site while the backup was in progress.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 11 Jun 2010 01:45:34 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:11:"Richard Hay";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:15;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:43:"Peter Westwood: Introducing menu_page_url()";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:33:"http://westi.wordpress.com/?p=171";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:64:"http://westi.wordpress.com/2010/06/10/introducing-menu_page_url/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1778:"<p>We&#8217;ve just added a new api into WordPress 3.0 to make plugin writing that bit easier &#8211; <a href="http://core.trac.wordpress.org/ticket/13829">#13829</a></p>\n<p>It is now really easy to get the url for a plugin page that you have registered to make it easy to link between different plugin pages.  You use the new function like this:</p>\n<pre class="brush: php;">\nadd_options_page(''Best Evar Menu'', ''Best Evar Menu'', ''manage_options'', ''best_evar_menu'', ''best_evar_options_page'');\n\nmenu_page_url( ''best_evar_menu'' );\n</pre>\n<p>The function will by default echo the url out but if you want you can get it returned for processing by setting the second argument to false.</p>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/westi.wordpress.com/171/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/westi.wordpress.com/171/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/westi.wordpress.com/171/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/westi.wordpress.com/171/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/westi.wordpress.com/171/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/westi.wordpress.com/171/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/westi.wordpress.com/171/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/westi.wordpress.com/171/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/westi.wordpress.com/171/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/westi.wordpress.com/171/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=westi.wordpress.com&blog=15396&post=171&subd=westi&ref=&feed=1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 10 Jun 2010 21:50:29 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:14:"Peter Westwood";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:16;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:37:"Alex King: Twitter Tools OAuth Update";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://alexking.org/?p=4407";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:62:"http://alexking.org/blog/2010/06/10/twitter-tools-oauth-update";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:974:"<p>I&#8217;ve finished researching the changes needed to integrate OAuth into <a href="http://crowdfavorite.com/wordpress/plugins/twitter-tools/">Twitter Tools</a>. The code changes are pretty straightforward and there is plenty of prior art and examples out there to reference. The technical implementation isn&#8217;t a problem.</p>\n<p>My concern is with the user experience of the initial install and set-up of the plugin. This would take a pretty big hit if I implement OAuth according to my best understanding of the required guidelines. I&#8217;m exploring some other options to see if I can find a good way to reduce the required steps and keep a nice simple user experience.</p>\n<p>Regardless, I still plan to have something ready for public release before the <a href="http://countdowntooauth.com" rel="external">deadline</a> &#8211; though time is getting a little tight.</p>\n<img src="http://alexking.org/wp/?ak_action=api_record_view&id=4407&type=feed" alt="" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 10 Jun 2010 16:21:13 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Alex";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:17;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:54:"WordPress.tv: Niall Kennedy: Writing Plugins for N00bs";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://wordpress.tv/?p=3924";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:71:"http://wordpress.tv/2010/05/01/niall-kennedy-writing-plugins-for-n00bs/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1394:"<div id="x-video-8" class="video-player">\n\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/3924/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/3924/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wptv.wordpress.com/3924/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wptv.wordpress.com/3924/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wptv.wordpress.com/3924/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumb