ng";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:68:"http://wordpress.tv/2010/04/24/pete-mall-wordpress-3-multisite-oc10/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1401:"<div id="x-video-15" class="video-player">\n\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/3853/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/3853/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/wptv.wordpress.com/3853/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/wptv.wordpress.com/3853/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/wptv.wordpress.com/3853/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/wptv.wordpress.com/3853/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/wptv.wordpress.com/3853/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/wptv.wordpress.com/3853/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/wptv.wordpress.com/3853/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/wptv.wordpress.com/3853/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=3853&subd=wptv&ref=&feed=1" /><div><a href="http://wordpress.tv/2010/04/24/pete-mall-wordpress-3-multisite-oc10/"><img alt="Pete Mall: WordPress 3.0 Multisite" src="http://cdn.videos.wordpress.com/BzYDTnD9/ocwordcamp003_h264_1096k_2997p_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 01 Jun 2010 04:15:07 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:11:"Ryan Markel";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:48;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:27:"Alex King: You’re Welcome";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:27:"http://alexking.org/?p=4380";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:49:"http://alexking.org/blog/2010/05/31/youre-welcome";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3059:"<p>This sort of thing frustrates me to no end:</p>\n<p class="center"><img src="http://alexking.org/wp/wp-content/uploads/2010/05/Picture-2.png" alt="Annoying" title="Annoying" width="357" height="378" /></p>\n<p>Ms. Bates, your carefully chosen words say volumes.</p>\n<p>Not to confuse people with the facts, but not only does Twitter Tools give you fine grain control over your decision to send (or not send) <em>each post</em> to Twitter, it even has a feature that prevents posts from being tweeted if they were published before you installed Twitter Tools. Could there be a bug? Sure (though it&#8217;s unlikely that I wouldn&#8217;t have heard about it before now), but that&#8217;s not really the point is it?</p>\n<p>The &#8220;don&#8217;t tweet old posts&#8221; feature was <a href="http://alexking.org/blog/2008/04/13/twitter-tools-12b1">added in version 1.2b1 back in 2008</a>. It was added solely because people requested it; it certainly wasn&#8217;t something I needed &#8211; just trying to make things better for the WordPress community.</p>\n<p>Of course for every group of people you satisfy by adding a feature, you&#8217;ll have an equal number of people requesting the opposite:</p>\n<p class="center"><a href="http://wordpress.org/support/topic/395610"><img src="http://alexking.org/wp/wp-content/uploads/2010/05/Picture-5-300x95.png" alt="Can&#039;t make everyone happy" title="Can&#039;t make everyone happy" width="300" height="95" class="alignnone size-medium wp-image-4382" /></a></p>\n<p>The joys of building software and giving it away for free.</p>\n<hr />\n<p>The irony of course is that I was getting set to start coding on a rewrite of Twitter Tools this evening (since there is a <a href="http://countdowntooauth.com/" rel="external">deadline looming</a>), but comments like the ones above really take the wind out of my sails.</p>\n<p>The combination of an evolving set of best-practices in WordPress core and extremely high expectations from the WordPress user community has plugin developers in a tough spot these days.</p>\n<p>I hired someone this summer for the sole purpose of updating all of our publicly released plugins/themes from the best practices of the time to the best practices in WP 3.0 (along with a few added features, bug fixes and enhancements). That&#8217;s the entire job. I expect it to take about 4-6 months to update the ~30 plugins/themes in question.</p>\n<p>That&#8217;s an expense I decided we should take on for the good of the community. The cost of the developer&#8217;s salary alone is <em>way</em> more than the total donations received on all of the plugins (over a 5-6 year period) &#8211; not to mention the time spent creating them in the first place, updating them, etc.</p>\n<p>There are many things in the WordPress community that are great. There are also many things that need to continue to evolve and improve.</p>\n<p>Enough ranting, I&#8217;ll go back to working on something more productive&#8230;</p>\n<img src="http://alexking.org/wp/?ak_action=api_record_view&id=4380&type=feed" alt="" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 01 Jun 2010 02:59:09 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Alex";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:49;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:31:"Gravatar: How Global Can We Go?";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:37:"https://gravatar.wordpress.com/?p=199";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:58:"http://blog.gravatar.com/2010/05/31/gravatar-localization/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3230:"<p>Gravatar has always been about GLOBALLY Recognized Avatars. The Global part of that came from Gravatar being really simple to implement in almost any environment. Let&#8217;s see what we can do to make things global by being available in every language!</p>\n<p>Previously, a few very helpful volunteers made sure that the Gravatar website was available in 14 different languages. There are now more strings to translate than ever (469 per language actually!), and so we&#8217;ve spent some time trying to make things easier to work with. Our buddies over at <a href="http://wordpress.com/">WordPress.com</a> are hosting a <a href="http://glotpress.org/">GlotPress</a> installation for us that will allow you all to contribute to the translation process online, with nothing but a web browser. All you need to do to get started is head over to <strong><a href="http://translate.wordpress.com/projects/gravatar">the Gravatar project</a></strong>, log in using your WordPress.com/Gravatar account and start translating strings!</p>\n<p><a href="http://translate.wordpress.com/projects/gravatar"><img class="aligncenter size-medium wp-image-200" title="Gravatar &lt; GlotPress" src="http://gravatar.files.wordpress.com/2010/05/gravatar-glotpress.png?w=274&#038;h=300" alt="" width="274" height="300" /></a></p>\n<p>We&#8217;ve imported all previous translations to get things started, and you&#8217;ll find some nifty tools in GlotPress, including the ability to use Google Translate for a bit of a head start. Strings are also prioritized according to where they appear within the website (so that we get the most important ones translated first). If you&#8217;d like to work on a language that isn&#8217;t currently listed, please let us know via an email to support [at] gravatar.com and we&#8217;ll get things set up for you.</p>\n<p>Once each translation gets near completion, we&#8217;ll get it online so that everyone can benefit from seeing the Gravatar.com website in their native language.</p>\n<p>We&#8217;re really looking forward to making Gravatar even more global than ever with your help!</p>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/gravatar.wordpress.com/199/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/gravatar.wordpress.com/199/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godelicious/gravatar.wordpress.com/199/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/delicious/gravatar.wordpress.com/199/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gostumble/gravatar.wordpress.com/199/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/stumble/gravatar.wordpress.com/199/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/godigg/gravatar.wordpress.com/199/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/digg/gravatar.wordpress.com/199/" /></a> <a rel="nofollow" href="http://feeds.wordpress.com/1.0/goreddit/gravatar.wordpress.com/199/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/reddit/gravatar.wordpress.com/199/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=blog.gravatar.com&blog=1886259&post=199&subd=gravatar&ref=&feed=1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 31 May 2010 21:49:44 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:11:"Beau Lebens";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}}}}}}}}}}}}s:4:"type";i:128;s:7:"headers";a:8:{s:4:"date";s:29:"Tue, 15 Jun 2010 14:31:54 GMT";s:6:"server";s:9:"LiteSpeed";s:13:"accept-ranges";s:5:"bytes";s:10:"connection";s:5:"close";s:4:"etag";s:23:""29e02-4c178ead-5042b6"";s:13:"last-modified";s:29:"Tue, 15 Jun 2010 14:31:09 GMT";s:12:"content-type";s:15:"application/xml";s:14:"content-length";s:6:"171522";}s:5:"build";s:14:"20090627192103";}', 'no');
