INSERT INTO `wp_bb_forums` (`forum_id`, `forum_name`, `forum_slug`, `forum_desc`, `forum_parent`, `forum_order`, `topics`, `posts`) VALUES
(1, 'Default Forum', 'default-forum', '', 0, 1, 0, 0),
(2, 'Fathers', 'fathers', 'Fathers - let''s talk.', 1, 2, 0, 0),
(3, 'Mothers', 'mothers', 'This is a space for just us mothers to talk about the things that bind us, freak us out, that give us comfort or the things we fear. Here you can sit with a cup of tea and discuss what you can really only discuss with the girls… the girls who for better or worse understand your grief, your loss, your new place in the world. It’s a strange and essential comfort to find out you are not the only one who can’t be around newborns, or see your dearest friends, or get through a day dry-eyed. This is a place where you can ask the questions and offer your thoughts about the child you lost and the feelings that you have (even if it''s about another pregnancy)… mother to mothers. ', 1, 3, 5, 6),
(4, 'Everyone', 'everyone', 'This is why we''re here - this is the place we can all come together and share with every member of the site. ', 1, 4, 2, 3),
(5, 'Public Everyone', 'public-everyone', 'Forums here are intended for sharing helpful information with everyone. - All visitors to the site anonymous or otherwise - can see these discussions. Here''s hoping they find them helpful!', 1, 5, 2, 4),
(6, 'Think Tank', 'think-tank', 'Here we will discuss all things related to Hope in Loss - as an organization - as a website -- as a force for positive grieving. Anything and everything that has to do with HIL -- let''s talk about it.', 1, 6, 0, 0);
