INSERT INTO `wp_bp_activity` (`id`, `user_id`, `component`, `type`, `action`, `content`, `primary_link`, `item_id`, `secondary_item_id`, `date_recorded`, `hide_sitewide`, `mptt_left`, `mptt_right`, `is_spam`) VALUES
(1, 3, 'groups', 'created_group', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> created the group <a href="http://hopeinloss.org/groups/mothers/">Mothers</a>', '', 'http://hopeinloss.org/members/susanbrennan/', 1, 0, '2010-04-07 13:30:33', 1, 0, 0, 0),
(6, 3, 'groups', 'activity_update', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> posted an update in the group <a href="http://hopeinloss.org/groups/mothers/">Mothers</a>:', 'So even though its just me- I\\''m getting ready for you other mothers to join me. So I started a forum topic (its in Forums in taps right above here and as a link in the post below this one- How Old he Would Be Today). Forums are where discussion will happen so check it out and respond if you are moved to. I won\\''t limit my posts to MOTHERS as I like to hear what your significant others have to say as well.... but like the night the mothers and fathers broke up into groups there is something unique to the woman conversation. Welcome. ', 'http://hopeinloss.org/members/susanbrennan/', 1, 0, '2010-04-07 18:29:48', 1, 0, 0, 0),
(7, 2, 'groups', 'created_group', '<a href="http://hopeinloss.org/members/tombrennan/" title="tombrennan">tombrennan</a> created the group <a href="http://hopeinloss.org/groups/everyone/">Everyone</a>', '', 'http://hopeinloss.org/members/tombrennan/', 3, 0, '2010-04-10 01:41:43', 1, 0, 0, 0),
(8, 3, 'activity', 'activity_update', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> posted an update:', 'People are coming to chat soon. Welcome. ', 'http://hopeinloss.org/members/susanbrennan/', 0, 0, '2010-04-10 20:54:23', 0, 0, 0, 0),
(3, 2, 'groups', 'created_group', '<a href="http://hopeinloss.org/members/tombrennan/" title="tombrennan">tombrennan</a> created the group <a href="http://hopeinloss.org/groups/fathers-1537696536/">Fathers</a>', '', 'http://hopeinloss.org/members/tombrennan/', 2, 0, '2010-04-07 17:53:09', 1, 0, 0, 0),
(4, 1, 'blogs', 'new_blog_post', '<a href="http://hopeinloss.org/members/admin/" title="admin">admin</a> wrote a new blog post: <a href="http://hopeinloss.org/2010/04/05/hello-world/">Home</a>', '<div>Welcome...</div> Thank you for stopping by hopeinloss.org, we hope you find your visit helpful and healing. We are here to create and provide a safe, secure, ad free, cost free, string free, online environment for parents dealing with the loss of a child late in pregnancy, or immediately after birth, so they may engage each other [...]', 'http://hopeinloss.org/2010/04/05/hello-world/', 1, 1, '2010-04-05 15:51:54', 0, 0, 0, 0),
(104, 3, 'blogs', 'new_blog_post', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> wrote a new blog post: <a href="http://susantomwillandtiger.hopeinloss.org/2010/12/02/135/">interchangeable </a>', '<img src="http://susantomwillandtiger.hopeinloss.org/files/2010/12/waves_on_rocky_shore-300x237.jpg" width="126.58227848101" height="100" alt="Thumbnail" class="align-left thumbnail" />The memories would slam against me like the waves of an incoming tide, sweeping my body along to some strange new place - a place where I lived with the dead. There Naoko lived, and I could speak with her and hold her in my arms. Death in that place was not a decisive element that [...]', 'http://susantomwillandtiger.hopeinloss.org/2010/12/02/135/', 2, 135, '2010-12-02 17:50:00', 0, 0, 0, 0),
(5, 3, 'groups', 'new_forum_topic', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> started the forum topic <a href="http://hopeinloss.org/groups/mothers/forum/topic/how-old-he-would-be-today/">How old he would be today </a> in the group <a href="http://hopeinloss.org/groups/mothers/">Mothers</a>:', 'It occurred to be me today that, had Tiger been born on his scheduled due date and then lived, he would be six months old. I think about age with Will too- usually when I see the child of a friend who was pregnant at the same time as me- and see what he would [...]', 'http://hopeinloss.org/groups/mothers/forum/topic/how-old-he-would-be-today/', 1, 1, '2010-04-07 18:23:30', 1, 0, 0, 0),
(39, 3, 'blogs', 'new_blog_post', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> wrote a new blog post: <a href="http://susantomwillandtiger.hopeinloss.org/2010/05/26/the-tiredness-of-sympathy/">the tiredness of sympathy</a>', 'In <span> An Exact Replica of a Figment of my Imagination </span> Elizabeth McCracken, in talking about the long healing process of grief says, "Grief lasts longer than sympathy, which is one of the tragedies of the grieving." I wouldn''t want the same sympathy that we got right after Tiger died. The difficulty of what Elizabeth says [...]', 'http://susantomwillandtiger.hopeinloss.org/2010/05/26/the-tiredness-of-sympathy/', 2, 55, '2010-05-26 16:49:17', 0, 0, 0, 0),
(10, 0, 'groups', 'joined_group', ' joined the group <a href="http://hopeinloss.org/groups//"></a>', '', 'http://hopeinloss.org/members/tombrennan/', 0, 0, '2010-04-15 17:40:07', 1, 0, 0, 0),
(14, 2, 'blogs', 'new_blog_comment', '<a href="http://hopeinloss.org/members/tombrennan/" title="tombrennan">tombrennan</a> commented on the blog post <a href="http://susantomwillandtiger.hopeinloss.org/2010/04/22/breaking-through-the-shock/#comment-2#comment-2">Breaking through the shock </a>', 'I remember the moment - before the monitor - when the technician asked if we had noticed kicking today.. and you said, "actually, no, not really." You said that -- and we looked at each other -- there was no more technician -- there was no more Universe. Eventually, as she pointed to the monitor [...]', 'http://susantomwillandtiger.hopeinloss.org/2010/04/22/breaking-through-the-shock/#comment-2', 2, 2, '2010-04-22 20:05:18', 0, 0, 0, 0),
(13, 3, 'blogs', 'new_blog_post', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> wrote a new blog post: <a href="http://susantomwillandtiger.hopeinloss.org/2010/04/22/breaking-through-the-shock/">Breaking through the shock </a>', 'I''m in the moment of the ultrasound without a heartbeat. I knew the second they put the wand on my stomach- I knew he was gone. All else- the cheery technician telling me to look at my son''s profile, the call to the doctor to look for herself, the silence in my hospital room, the [...]', 'http://susantomwillandtiger.hopeinloss.org/2010/04/22/breaking-through-the-shock/', 2, 19, '2010-04-22 15:00:31', 0, 0, 0, 0),
(12, 3, 'blogs', 'new_blog_post', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> wrote a new blog post: <a href="http://susantomwillandtiger.hopeinloss.org/2010/04/15/not-a-walk-in-the-park/">not a walk in the park</a>', 'I love the name Tiger now. A beautiful spring morning in Brooklyn, walking Fletcher in the park.... and the tulips at Will''s tree are in bloom.... and I wanted you with me. I guess I longed for these morning walks with you, like I had with Lucy and Fletch minus Will''s tree years ago now. [...]', 'http://susantomwillandtiger.hopeinloss.org/2010/04/15/not-a-walk-in-the-park/', 2, 5, '2010-04-15 17:53:07', 0, 0, 0, 0),
(15, 3, 'blogs', 'new_blog_post', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> wrote a new blog post: <a href="http://susantomwillandtiger.hopeinloss.org/2010/04/29/unexpected-grief/">Unexpected Grief </a>', '<img src="http://susantomwillandtiger.hopeinloss.org/files/2010/04/IMG_0667-300x225.jpg" width="133.33333333333" height="100" alt="Thumbnail" class="align-left thumbnail" /><em><a href="http://susantomwillandtiger.hopeinloss.org/files/2010/04/IMG_0667.jpg"></a>It''s so curious: one can resist tears and </em>behave<em> very well in the hardest hours of grief. But then someone makes you a friendly sign behind a window, or one notices that a flower that was in bud only yesterday has suddenly blossomed, or a letter slips from a drawer.. and everything collapses </em>. ~Colette Grief renders me [...]', 'http://susantomwillandtiger.hopeinloss.org/2010/04/29/unexpected-grief/', 2, 29, '2010-04-29 13:28:37', 0, 0, 0, 0),
(16, 2, 'blogs', 'new_blog_post', '<a href="http://hopeinloss.org/members/tombrennan/" title="tombrennan">tombrennan</a> wrote a new blog post: <a href="http://susantomwillandtiger.hopeinloss.org/2010/05/05/congratulations/">Congratulations</a>', 'When I came into work yesterday Marlon was back. He had missed a few days as he and his wife had their beautiful baby boy. (I forget his name) Everyone was gathered around the pictures -- I did my best. " <em>He''s so cute </em>." Actually, I think I did alright -- Even did my usual bit about, " <em>who''s [...]</em>', 'http://susantomwillandtiger.hopeinloss.org/2010/05/05/congratulations/', 2, 36, '2010-05-05 14:21:49', 0, 0, 0, 0),
(17, 3, 'blogs', 'new_blog_comment', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> commented on the blog post <a href="http://susantomwillandtiger.hopeinloss.org/2010/05/05/congratulations/#comment-3#comment-3">Congratulations</a>', 'I think I''m the one who laughed darlin''. I do every time. You were good to make the joke. The truth is that it didn''t hide anything. With you standing there, you were not the only one thinking about Will and Tiger- it crossed a few other''s minds that YOU were looking at a picture [...]', 'http://susantomwillandtiger.hopeinloss.org/2010/05/05/congratulations/#comment-3', 2, 3, '2010-05-05 15:04:43', 0, 0, 0, 0),
(48, 2, 'groups', 'created_group', '<a href="http://hopeinloss.org/members/tombrennan/" title="tombrennan">tombrennan</a> created the group <a href="http://hopeinloss.org/groups/think-tank/">Think Tank</a>', '', 'http://hopeinloss.org/members/tombrennan/', 5, 0, '2010-06-15 14:46:24', 1, 0, 0, 0),
(49, 2, 'friends', 'friendship_created', '<a href="http://hopeinloss.org/members/tombrennan/" title="tombrennan">tombrennan</a> and <a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> are now friends', '', 'http://hopeinloss.org/members/susanbrennan/', 6, 0, '2010-06-16 11:56:56', 0, 0, 0, 0),
(19, 5, 'activity', 'activity_update', '<a href="http://hopeinloss.org/members/liisa/" title="liisa">liisa</a> posted an update:', 'I\\''m glad to have finally taken a few moments to get connected to this cause!  Thank you Tom and Susan for your efforts to keep us in communication.', 'http://hopeinloss.org/members/liisa/', 0, 0, '2010-05-06 16:36:45', 0, 1, 4, 0),
(20, 0, 'groups', 'joined_group', ' joined the group <a href="http://hopeinloss.org/groups//"></a>', '', 'http://hopeinloss.org/members/tombrennan/', 0, 0, '2010-05-07 09:47:11', 1, 0, 0, 0),
(21, 2, 'activity', 'activity_comment', '<a href="http://hopeinloss.org/members/tombrennan/" title="tombrennan">tombrennan</a> posted a new activity comment:', 'no - thank you! \n\nFeel free to browse around to figure out how it all works. I need to develop some tutorials to explain the basics (what\\''s private, what\\''s not, how to create a blog post on your blog, how to start a new forum topic, etc) You Joshua, Susan and I are the first, so we may have to figure some things out as we go - sorry about that.\n\nHopefully we can get a process going that will end up being very helpful - to a lot of people - for a long time. ', 'http://hopeinloss.org/members/tombrennan/', 19, 19, '2010-05-07 09:54:36', 0, 2, 3, 0),
(23, 2, 'activity', 'activity_update', '<a href="http://hopeinloss.org/members/tombrennan/" title="tombrennan">tombrennan</a> posted an update:', 'Susan and I had our first comment from a random visitor on our blog – a woman came to it and found some small comfort in Susan’s post. Sarah H. whoever you are – so glad you stopped by. If this site was a deli – your comment would be the dollar bill we’d display proudly behind the register for all time.', 'http://hopeinloss.org/members/tombrennan/', 0, 0, '2010-05-07 10:01:41', 0, 0, 0, 0),
(24, 0, 'groups', 'joined_group', ' joined the group <a href="http://hopeinloss.org/groups//"></a>', '', 'http://hopeinloss.org/members/susanbrennan/', 0, 0, '2010-05-07 12:22:14', 1, 0, 0, 0),
(25, 5, 'groups', 'activity_update', '<a href="http://hopeinloss.org/members/liisa/" title="liisa">liisa</a> posted an update in the group <a href="http://hopeinloss.org/groups/mothers/">Mothers</a>:', 'Mother\\''s Day is looming...this dreaded event has become the most awkward of holidays. Ok, so I\\''m technically and biologically a mom, but not in the day-to-day practical sense. Last year I was wished a \\''happy mother\\''s day\\'' out of dreadful pity; this year I hope it doesn\\''t get brought up. I find it difficult to even muster up the energy to send out cards to the other mothers in my life (with the exception of my mom)...', 'http://hopeinloss.org/members/liisa/', 1, 0, '2010-05-07 18:31:30', 1, 1, 6, 0),
(26, 3, 'activity', 'activity_comment', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> posted a new activity comment:', 'Bitter sweet is about the best that I can muster. I remember what you said the last night of the group about being a \\''mother\\''. It\\''s a whole different world- not being the one expected. I think you get a free pass from wishing anyone but your mom a happy mother\\''s day Liisa- Here, I\\''ll make it for you:\n\n                                          FREE PASS (for as long as needed)\nThis entitled Liisa to forget all unnecessary merriment on this day, to excuse herself from \nsmiling, sweet emails, and cards to woman that she knows. You have a life time pass from such \nresponsibilities. Other than her own mother of course. ', 'http://hopeinloss.org/members/susanbrennan/', 25, 25, '2010-05-09 21:28:12', 1, 2, 5, 0),
(27, 5, 'activity', 'activity_comment', '<a href="http://hopeinloss.org/members/liisa/" title="liisa">liisa</a> posted a new activity comment:', 'Susan--I love my new free pass!  Thank you! Yesterday was less dreadful than expected. I was able to enjoy a leisurely brunch with a wise woman in my life. (You know the kind of mature friend who just knows what to say at the right time? They are a rare gem, and I am grateful.) We feasted on melt-in-your-mouth smocked salmon ladened baguette and discussed our dreams. Good times. Of course there were many mother\\''s day wishes echoed throughout the cafe that morning, but whatever, we were enjoying each others company...', 'http://hopeinloss.org/members/liisa/', 25, 26, '2010-05-10 23:08:33', 1, 3, 4, 0),
(28, 3, 'groups', 'activity_update', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> posted an update in the group <a href="http://hopeinloss.org/groups/everyone/">Everyone</a>:', 'Welcome everyone. Babyloss parents. \n\nThere are other \\''terms\\''- none of which I like. After all, they are not titles we wish we had. \nI felt for a long time a strange almost rubberneck like quality to being apart of a group whose link was lost babies. But after our support group, an online forum, and emails with other mothers who lost their children I\\''m finding this such a relief. I\\''m hoping many other parents will too. I think, since what\\''s done is done, I love the idea that our children can connect us and give us comfort. \n\nSo I really mean WELCOME. I want to hear how you move through this new world, how you \\''part the air\\'' now with loss as a new dimension to being alive. I find all of it so raw and comforting. \n\nIs the world out there different for you with others? ', 'http://hopeinloss.org/members/susanbrennan/', 3, 0, '2010-05-14 14:53:04', 1, 0, 0, 0),
(29, 3, 'groups', 'activity_update', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> posted an update in the group <a href="http://hopeinloss.org/groups/mothers/">Mothers</a>:', 'WoW. \nI\\''m getting better with the newborn and pregnant woman thing. Better- not anywhere near normal- but not bursting out into tears either. I\\''ve actually held a baby and given solicited pregnancy advice. \nBut the last couple of days- man! They are everywhere! Is it Spring? or Park Slope? or me? You know the scene in Being John Malkovitch where all of a sudden every person in the room is John Malkovitch? I feel like there are days where every person on the street is either pregnant or holding a newborn. \nAnd I feel different about it- but what is unusual for me is- I can\\''t explain it. I\\''m just.... in a confused fog... like it\\''s a dream or something. \nI don\\''t watch for long enough to feel anger or longing. \nI think I\\''m just reminded that this time last year I was pregnant and in another month Tiger will have died a year ago and i find that really shocking. \nYou know what I mean? ', 'http://hopeinloss.org/members/susanbrennan/', 1, 0, '2010-05-14 15:05:32', 1, 1, 4, 0),
(30, 3, 'groups', 'new_forum_topic', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> started the forum topic <a href="http://hopeinloss.org/groups/everyone/forum/topic/some-thoughts-on-hil-members-similarities-and-differences/">Some thoughts on HIL member&#39;s similarities and differences. </a> in the group <a href="http://hopeinloss.org/groups/everyone/">Everyone</a>:', 'We spend a lot of time talking about how much sensitivity to the differences in our losses should be highlighted on Hope In Loss. In the end I think we look to The Pregnancy Loss Support Group''s belief that: we all share the loss of a dream- we all share the loss of a baby, [...]', 'http://hopeinloss.org/groups/everyone/forum/topic/some-thoughts-on-hil-members-similarities-and-differences/', 3, 2, '2010-05-17 16:45:54', 1, 0, 0, 0),
(31, 2, 'groups', 'new_forum_post', '<a href="http://hopeinloss.org/members/tombrennan/" title="tombrennan">tombrennan</a> posted on the forum topic <a href="http://hopeinloss.org/groups/everyone/forum/topic/some-thoughts-on-hil-members-similarities-and-differences/">Some thoughts on HIL member&#39;s similarities and differences. </a> in the group <a href="http://hopeinloss.org/groups/everyone/">Everyone</a>:', 'My love -- I love how you have started this discussion -- we definitely have to continue it. What I think you capture so beautifully is, "all parents that have suffered the loss of a baby have suffered the loss of a dream." The rest is details. When I read what you wrote - I''m [...]', 'http://hopeinloss.org/groups/everyone/forum/topic/some-thoughts-on-hil-members-similarities-and-differences/#post-3', 3, 3, '2010-05-17 20:03:33', 1, 0, 0, 0),
(32, 5, 'activity', 'activity_comment', '<a href="http://hopeinloss.org/members/liisa/" title="liisa">liisa</a> posted a new activity comment:', 'No, it\\''s not just you--they are everywhere...multiplying like rabbits. Ubiquitous as air. Everywhere. I go to the mall near us, and it seems that every woman between the ages of 16 and 48 is either pregnant or pushing some form of high-end stroller. It was hard to know where to look at the park today; so I fed squirrels near the plastic recycling bin in hopes of ignoring the \\''celebration of fertility\\'' around me. It\\''s not easy--actually, it\\''s quite horrible. \nI fear the best solution is to join them. But the thought of that makes me feel even worse.\nThe month leading to the anniversary is anxious and shaky. I\\''m so sorry you are facing that time. It must be especially difficult these days.', 'http://hopeinloss.org/members/liisa/', 29, 29, '2010-05-17 20:16:16', 1, 2, 3, 0),
(35, 0, 'groups', 'joined_group', ' joined the group <a href="http://hopeinloss.org/groups//"></a>', '', 'http://hopeinloss.org/members/susanbrennan/', 0, 0, '2010-05-18 13:39:11', 1, 0, 0, 0),
(36, 3, 'groups', 'activity_update', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> posted an update in the group <a href="http://hopeinloss.org/groups/mothers/">Mothers</a>:', 'So things are little confusing on where to post in each group: \n*To discuss a topic and get comments on that topic/question go to the Forum tab just above this (you are on the Home tab). There you can post a topic and we can discuss. \n*Here on Home are just notes and comments about whatever- to let each other know about something or an event. \n*We will change the titles of Home and Forum soon to make it clearer. \n*Don\\''t forget about the Everyone group. I do think that there are things just for woman to discuss (here on Mothers) and also things for us all to share. Eventually I\\''d love some feedback on what you find the most useful, what is redundant, what is confusing, what is missing. \nThanks for being a part of this while we iron out the logistics. So glad that you are here. ', 'http://hopeinloss.org/members/susanbrennan/', 1, 0, '2010-05-18 13:46:01', 1, 0, 0, 0),
(100, 3, 'blogs', 'new_blog_post', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> wrote a new blog post: <a href="http://susantomwillandtiger.hopeinloss.org/2010/09/11/grief-expanded-and-compressed-and-expanded/">grief expanded and compressed..... and expanded</a>', 'I live in New York City. I lived in Manhattan on September 11, 2001. The feeling of shock and otherworldliness filled the streets. We all walked around silent, looking one another in the eyes for answers. None of course. The unthinkable, the impossible had happened. We passed MISSING signs, we check on friends who worked [...]', 'http://susantomwillandtiger.hopeinloss.org/2010/09/11/grief-expanded-and-compressed-and-expanded/', 2, 123, '2010-09-11 22:05:44', 0, 0, 0, 0),
(105, 3, 'blogs', 'new_blog_post', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> wrote a new blog post: <a href="http://susantomwillandtiger.hopeinloss.org/2010/12/21/but-through-the-body/">..... but through the body</a>', '<img src="http://susantomwillandtiger.hopeinloss.org/files/2010/12/60497321-300x300.jpg" width="100" height="100" alt="Thumbnail" class="align-left thumbnail" /><em><a href="http://susantomwillandtiger.hopeinloss.org/files/2010/12/60497321.jpg"></a></em> <em><a href="http://susantomwillandtiger.hopeinloss.org/files/2010/12/60497321.jpg"></a>Absolutely there is body memory </em>. My body conducts my tears, screens vivid visual memories in the theater of my brain, builds rituals on the anniversaries of the boys'' deaths, births, due dates, memorial dates (endless dates). I am reminded of the pain leading up to Tiger''s death around my period. When the same adhesion pain is [...]', 'http://susantomwillandtiger.hopeinloss.org/2010/12/21/but-through-the-body/', 2, 144, '2010-12-21 19:56:03', 0, 0, 0, 0),
(38, 3, 'groups', 'new_forum_topic', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> started the forum topic <a href="http://hopeinloss.org/groups/mothers/forum/topic/what-you-can-handle/">what you can handle </a> in the group <a href="http://hopeinloss.org/groups/mothers/">Mothers</a>:', 'I''m kind of amazed and confused by what I can and can''t handle these days. I hold a baby, I dash away from a woman on the subway carrying a newborn in a sling. I have a family with a 4 month old girl move into our house, I cry at little boy''s baseball games [...]', 'http://hopeinloss.org/groups/mothers/forum/topic/what-you-can-handle/', 1, 3, '2010-05-19 15:24:12', 1, 0, 0, 0),
(40, 2, 'blogs', 'new_blog_post', '<a href="http://hopeinloss.org/members/tombrennan/" title="tombrennan">tombrennan</a> wrote a new blog post: <a href="http://susantomwillandtiger.hopeinloss.org/2010/05/26/one-for-a-solitary-man/">"One for A SOLITARY MAN"</a>', 'It''s true - I went to the movies last night and saw, A SOLITARY MAN,...  by myself. Bada bum. I go every week, it''s something Susan does for me. Yeah, she''s pretty great. Speaking of Susan, she just posted on our blog with a beautiful discussion/essay on sympathy and time. It was a fascinating read for me. [...]', 'http://susantomwillandtiger.hopeinloss.org/2010/05/26/one-for-a-solitary-man/', 2, 65, '2010-05-26 17:48:18', 0, 0, 0, 0),
(41, 2, 'blogs', 'new_blog_comment', '<a href="http://hopeinloss.org/members/tombrennan/" title="tombrennan">tombrennan</a> commented on the blog post <a href="http://susantomwillandtiger.hopeinloss.org/2010/05/26/the-tiredness-of-sympathy/#comment-9#comment-9">the tiredness of sympathy</a>', 'My love - thank you thank you thank you - beautiful wonderful post.', 'http://susantomwillandtiger.hopeinloss.org/2010/05/26/the-tiredness-of-sympathy/#comment-9', 2, 9, '2010-05-26 17:57:38', 0, 0, 0, 0),
(42, 3, 'blogs', 'new_blog_comment', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> commented on the blog post <a href="http://susantomwillandtiger.hopeinloss.org/2010/05/26/one-for-a-solitary-man/#comment-10#comment-10">"One for A SOLITARY MAN"</a>', 'hmmm. a site to give others the space to really be with people sounds in order. oh you are doing that already. \r\n\r\nI love that you say their names whenever you can. \r\n\r\nYou are such an amazing father.', 'http://susantomwillandtiger.hopeinloss.org/2010/05/26/one-for-a-solitary-man/#comment-10', 2, 10, '2010-05-26 19:02:17', 0, 0, 0, 0),
(43, 5, 'groups', 'activity_update', '<a href="http://hopeinloss.org/members/liisa/" title="liisa">liisa</a> posted an update in the group <a href="http://hopeinloss.org/groups/mothers/">Mothers</a>:', 'So, what do you do when it seems that all of your friends are pregnant?! Seriously, it\\''s impossible to just hang with friends who aren\\''t somehow enjoying their capabilities of fertility? Geez. At first I thought I would be some kind of \\''bad luck\\'' charm--but I must be the opposite in regards to everyone elses\\'' uteruses. (\\''Hey, you lookin\\'' to have a baby? Hang out with me and it\\''s sure to work out for ya!\\'') It makes for very awkward encounters: two weeks ago I was having lunch with a friend who made \\''the blessed announcement\\'' and then proceeded to hand me a book on miscarriage. It was just weird on so many levels. (I don\\''t at all mean to minimize the pain of a miscarriage--but, that is not what I had!) Every time I hear these announcements I just want to vomit and mumble vulgerities...not very mature, I know. But come on! It\\''s becoming a weekly occurance.', 'http://hopeinloss.org/members/liisa/', 1, 0, '2010-06-07 02:54:04', 1, 0, 0, 0),
(44, 1, 'groups', 'new_calendar_event', '<a href="http://hopeinloss.org/members/admin/" title="admin">admin</a> created an event for the group <a href="http://hopeinloss.org/groups/fathers-1537696536/">Fathers</a>:', '<a href="http://hopeinloss.org/groups/fathers-1537696536/calendar/event/1/" title="View Event">Father''s Day: June 20, 2010 7:00 am</a>', 'http://hopeinloss.org/groups/fathers-1537696536/calendar/event/1/', 2, 1, '2010-06-09 19:40:47', 1, 0, 0, 0),
(45, 1, 'groups', 'new_forum_topic', '<a href="http://hopeinloss.org/members/admin/" title="admin">admin</a> started the forum topic <a href="http://hopeinloss.org/groups/public-everyone/forum/topic/youve-recently-suffered-a-loss-and/">You&#39;ve recently suffered a loss and... </a> in the group <a href="http://hopeinloss.org/groups/public-everyone/">Public Everyone</a>:', 'Quick info for anyone that'' suffered the neo-natal loss of a child.', 'http://hopeinloss.org/groups/public-everyone/forum/topic/youve-recently-suffered-a-loss-and/', 4, 4, '2010-06-09 19:45:41', 0, 0, 0, 0),
(46, 3, 'blogs', 'new_blog_post', '<a href="http://hopeinloss.org/members/susanbrennan/" title="susanbrennan">susanbrennan</a> wrote a new blog post: <a href="http://susantomwillandtiger.hopeinloss.org/2010/06/13/365-days-in-the-spirit-of-tiger/">365 days in the spirit of Tiger</a>', '<img src="http://susantomwillandtiger.hopeinloss.org/files/2010/06/IMG_10032-225x300.jpg" width="75" height="100" alt="Thumbnail" class="align-left thumbnail" />*This is the year of the tiger in the Chinese Zodiac *Tigers are really good swimmers. *Tiger cubs start to hunt with their mothers at 6 months. They can''t feed themselves though so they remain with their moms until 16 months. * The number of tigers in the wild has dwindled to 3,200 - less than [...]', 'http://susantomwillandtiger.hopeinloss.org/2010/06/13/365-days-in-the-spirit-of-tiger/', 2, 72, '2010-06-13 22:31:15', 0, 0, 0, 0),
(47, 2, 'blogs', 'new_blog_comment', '<a href="http://hopeinloss.org/members/tombrennan/" title="tombrennan">tombrennan</a> commented on the blog post <a href="http://susantomwillandtiger.hopeinloss.org/2010/06/13/365-days-in-the-spirit-of-tiger/comment-page-1/#comment-13">365 days in the spirit of Tiger</a>', 'My love -- you are  a wonder on earth -- I celebrate, adore, worship, and stand in awe, of the breath of life in you.', 'http://susantomwillandtiger.hopeinloss.org/2010/06/13/365-days-in-the-spirit-of-tiger/comment-page-1/#comment-13', 2, 13, '2010-06-14 14:15:09', 0, 0, 0, 0),
