INSERT INTO `wp_bp_groups` (`id`, `creator_id`, `name`, `slug`, `description`, `status`, `enable_forum`, `date_created`) VALUES
(1, 3, 'Mothers  (Members)', 'mothers', 'This is a space for just us mothers to talk about the things that bind us, freak us out, that give us comfort or the things we fear. Here you can sit with a cup of tea and discuss what you can really only discuss with the girls… the girls who for better or worse understand your grief, your loss, your new place in the world. It’s a strange and essential comfort to find out you are not the only one who can’t be around newborns, or see your dearest friends, or get through a day dry-eyed. This is a place where you can ask the questions and offer your thoughts about the child you lost and the feelings that you have (even if it\\''s about another pregnancy)… mother to mothers. \r\nWelcome. ', 'private', 1, '2010-04-07 13:30:05'),
(2, 2, 'Fathers  (Members)', 'fathers-1537696536', 'Fathers - let\\''s talk.', 'private', 1, '2010-04-07 17:51:43'),
(3, 2, 'Everyone  (Members)', 'everyone', 'This is why we\\''re here - this is the place we can all come together and share with every member of the site. ', 'private', 1, '2010-04-10 01:32:45'),
(4, 1, 'Public Everyone', 'public-everyone', 'Forums here are intended for sharing helpful information with everyone. - All visitors to the site anonymous or otherwise - can see these discussions. Here\\''s hoping they find them helpful!', 'public', 1, '2010-06-09 19:43:25'),
(5, 2, 'Think Tank', 'think-tank', 'Here we will discuss all things related to Hope in Loss - as an organization - as a website -- as a force for positive grieving. Anything and everything that has to do with HIL -- let\\''s talk about it.', 'hidden', 1, '2010-06-15 14:44:31');
