INSERT INTO `wp_bp_messages_messages` (`id`, `thread_id`, `sender_id`, `subject`, `message`, `date_sent`) VALUES
(1, 1, 3, 'checkin in', 'Hey Josh,\r\n\r\nI just wanted to say sorry we have been moving at a snail pace. We really appreciated you moving around the site. So now that we seem to be getting it together and Liisa is on too- will you join the everyone group? I\\''d love to talk to you guys. \r\n\r\nAlso, the park it looking beautiful. Tiger\\''s anniversary is in a month so think we will have a \\''something\\'' before too long. I hope you two will join us. \r\n\r\nlight,\r\nsusan ', '2010-05-14 09:57:31'),
(2, 2, 10, 'hello', 'Hi Susan,\r\n\r\n I found that whole \\"edit\\" part on  thoughts for friends and family a bit daunting, but wanted to make a small suggestion.  There is a part where you say that men and women grieve differently.  I would suggest that you say something like - Ask men how THEY are doing, not just how their wives are doing.  My husband got that a lot and he really apprietiated it when people thought to check in with HIM.  All the best, Giorgiana ', '2010-06-30 21:04:27');
